/* AUTO-GENERATED — Arkansas Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["AR"] = {"code":"AR","name":"Arkansas","agency":"Arkansas DFA","agencyShort":"DFA","handbook":"https://dps.arkansas.gov/wp-content/uploads/CDL-Manual_August-21-2025.pdf","links":{},"en":[{"q":"On Arkansas highways, what is the maximum total outside width of a vehicle (with or without a load) before a special permit is required?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"Arkansas Code Ann. 27-35-206 sets the maximum legal width of a vehicle at 102 inches (8 feet 6 inches), unladen or with load; anything wider requires an oversize permit from ARDOT/Arkansas Highway Police.","handbook":"","hbref":""},{"q":"Under current Arkansas law, what is the maximum height of a vehicle (including its load) allowed on state highways without a special permit?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"answer":2,"explanation":"Arkansas Code Ann. 27-35-207, as amended by Act 871 of 2021 (effective July 28, 2021), raised the legal height limit from 13'6\" to 14 feet. A vehicle exceeding 14 feet requires a special (over-height) permit.","handbook":"","hbref":""},{"q":"What is the maximum gross weight of a vehicle or combination allowed on Arkansas highways without an overweight permit?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"answer":1,"explanation":"Consistent with the federal standard and Arkansas Code Ann. 27-35-203, the maximum legal gross weight is 80,000 pounds. Exceeding it requires an overweight permit from the ARDOT/Arkansas Highway Police Permit Section.","handbook":"","hbref":""},{"q":"In Arkansas, what is the maximum load that may be carried on a single axle without a permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"Arkansas Code Ann. 27-35-203 limits a single axle to 20,000 pounds. This matches the federal single-axle limit applied on Arkansas highways.","handbook":"","hbref":""},{"q":"What is the maximum legal load on a tandem axle group in Arkansas without a permit?","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"answer":1,"explanation":"Arkansas Code Ann. 27-35-203 limits a tandem axle to 34,000 pounds. (With a permit, a tandem may reach 46,000 pounds, but 34,000 is the unpermitted maximum.)","handbook":"","hbref":""},{"q":"Under Arkansas Code 27-35-203, two consecutive axles are treated as a 'tandem axle' when the spacing between their centers is:","options":["More than 40 inches but not more than 96 inches","More than 96 inches but not more than 120 inches","Exactly 48 inches","Less than 40 inches"],"answer":0,"explanation":"Arkansas Code Ann. 27-35-203 defines a tandem axle as two or more consecutive axles whose centers are spaced more than 40 inches and not more than 96 inches apart, with a combined limit of 34,000 pounds.","handbook":"","hbref":""},{"q":"What is the maximum length of a single (straight) truck operated on Arkansas highways without a permit?","options":["35 feet","40 feet","45 feet","53 feet"],"answer":1,"explanation":"Arkansas Code Ann. 27-35-208 limits a single (straight) vehicle to an overall length of 40 feet, unladen or with load.","handbook":"","hbref":""},{"q":"On Arkansas highways, what is the maximum length of a semitrailer operating in combination with a truck tractor that the state cannot restrict below?","options":["48 feet","50 feet","53 feet 6 inches","57 feet"],"answer":2,"explanation":"Arkansas Code Ann. 27-35-208 provides that the state shall not impose a semitrailer/trailer length limit of less than 53 feet 6 inches on a unit operated in combination with a truck tractor.","handbook":"","hbref":""},{"q":"In a truck-tractor-semitrailer-trailer (twin/double) combination on Arkansas highways, what is the maximum length of each trailing unit?","options":["24 feet","28 feet","33 feet","40 feet"],"answer":1,"explanation":"Arkansas Code Ann. 27-35-208 limits each semitrailer or trailer in a truck-tractor-semitrailer-trailer (double) combination to an overall length of 28 feet, exclusive of coupling devices.","handbook":"","hbref":""},{"q":"Which formula does Arkansas use to determine the maximum allowable weight on a group of axles relative to the distance between them?","options":["The Federal Bridge Formula (Formula B)","The Arkansas Tare Weight Formula","The Gross Combination Ratio Rule","The Tandem Spacing Multiplier"],"answer":0,"explanation":"Arkansas applies the Federal Bridge Formula (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], to set the maximum weight a given axle group may carry based on the number of axles (N) and the distance (L) between them.","handbook":"","hbref":""},{"q":"In the Federal Bridge Formula as applied in Arkansas, W = 500[LN/(N-1) + 12N + 36], what does 'N' represent?","options":["The number of axles in the group being considered","The net (tare) weight of the vehicle","The number of tires on the drive axle","The nominal speed limit of the highway"],"answer":0,"explanation":"In the Federal Bridge Formula used by Arkansas, N is the number of axles in the group under consideration, L is the spacing in feet between the outer axles of the group, and W is the maximum allowable weight.","handbook":"","hbref":""},{"q":"A trucker's load is 9 feet 2 inches wide. On Arkansas highways this load:","options":["Is legal because it is under 10 feet","Requires an oversize permit because it exceeds 102 inches","Is legal only on the Interstate system","Requires only a flag, not a permit"],"answer":1,"explanation":"The Arkansas legal width is 102 inches (8'6\") per Code 27-35-206. A 9'2\" load (110 inches) exceeds the legal width and requires an oversize permit from ARDOT/Arkansas Highway Police.","handbook":"","hbref":""},{"q":"Which agency issues oversize and overweight movement permits for the Arkansas State Highway System?","options":["The Arkansas Department of Finance and Administration","The Arkansas Department of Transportation through the Arkansas Highway Police Permit Section","The county sheriff in each county of travel","The Federal Motor Carrier Safety Administration"],"answer":1,"explanation":"Under the ARDOT 2023 Permit Rules, oversize/overweight permits for the State Highway System are issued by the Arkansas Department of Transportation through the Arkansas Highway Police Permit Section.","handbook":"","hbref":""},{"q":"When does a motor carrier need an overweight permit in Arkansas?","options":["Only when the load can be reduced by splitting it","When the vehicle exceeds the legal gross, single-axle, or tandem-axle weight limits","Any time the trip crosses a county line","Only when traveling at night"],"answer":1,"explanation":"Per the ARDOT Permit Rules and Code 27-35-203/210, an overweight permit is required whenever a vehicle exceeds the legal limits (80,000 lbs gross, 20,000 lbs single axle, or 34,000 lbs tandem, or a bridge-formula limit). Such permits are generally issued only for nondivisible loads.","handbook":"","hbref":""},{"q":"Overweight permits in Arkansas are generally issued only for loads that are:","options":["Divisible into smaller legal loads","Nondivisible (cannot reasonably be reduced to legal weight)","Carried at less than 45 mph","Owned by a government agency"],"answer":1,"explanation":"Under the ARDOT Permit Rules, an overweight permit is issued for nondivisible loads, those that cannot reasonably be broken down to meet legal weight limits. Divisible loads must be reduced to legal weight rather than permitted.","handbook":"","hbref":""},{"q":"Arkansas allows an annual permit for a truck-tractor/semitrailer combination of at least five axles hauling agronomic or horticultural crops in their natural state up to what gross weight?","options":["84,000 pounds","90,000 pounds","100,000 pounds","112,000 pounds"],"answer":2,"explanation":"Arkansas Code Ann. 27-35-210 authorizes an annual permit for a minimum five-axle truck-tractor/semitrailer combination hauling natural-state agronomic or horticultural crops up to a total gross weight of 100,000 pounds.","handbook":"","hbref":""},{"q":"On a permitted move in Arkansas, a tandem axle group may be loaded up to a maximum of:","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"answer":2,"explanation":"Under the ARDOT Permit Rules, a permitted tandem axle group may carry up to 46,000 pounds (with no single axle exceeding 23,000 pounds), compared with the 34,000-pound unpermitted legal limit in Code 27-35-203.","handbook":"","hbref":""},{"q":"A five-axle tractor-semitrailer in Arkansas is loaded to 80,000 lbs gross, 20,000 lbs on the steer axle, 34,000 lbs on the drive tandem, and 26,000 lbs on the trailer tandem. Which condition is over the legal limit?","options":["The gross weight","The steer (single) axle weight","The drive tandem weight","None of these exceed their legal limit"],"answer":3,"explanation":"Per Code 27-35-203, the legal limits are 80,000 lbs gross, 20,000 lbs single axle, and 34,000 lbs tandem. Each value here is at or below its limit, so no axle or gross weight is over the legal limit (bridge-formula spacing still applies).","handbook":"","hbref":""},{"q":"Which statement about overall combination length on Arkansas highways is correct for a truck-tractor and single semitrailer?","options":["Arkansas caps the overall tractor-semitrailer combination at exactly 65 feet","Arkansas does not impose a fixed overall length limit on a tractor-and-single-semitrailer combination; the semitrailer itself may be up to 53'6\"","Arkansas caps the overall combination at 60 feet on all roads","Arkansas allows no semitrailer longer than 48 feet"],"answer":1,"explanation":"Arkansas Code Ann. 27-35-208 limits the semitrailer length (not less than 53'6\" may be restricted) but does not set a fixed overall length limit on a truck-tractor plus single semitrailer combination, consistent with federal STAA rules.","handbook":"","hbref":""},{"q":"A flatbed in Arkansas measures 14 feet 4 inches tall to the top of its load. Without a permit, this vehicle is:","options":["Legal, because the limit is 15 feet","Over height and requires a special (over-height) permit","Legal only off the Interstate system","Legal because height is not regulated in Arkansas"],"answer":1,"explanation":"The current Arkansas legal height is 14 feet under Code 27-35-207 (as amended by Act 871 of 2021). A load measuring 14'4\" exceeds 14 feet and requires an over-height permit from ARDOT/Arkansas Highway Police.","handbook":"","hbref":""},{"q":"In Arkansas, which CDL class is required to operate a combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the towed unit has a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Arkansas defines a Class A CDL as any combination of vehicles with a GCWR of 26,001 pounds or more, inclusive of a towed unit with a GVWR of more than 10,000 pounds. Source: Arkansas CDL Manual, Section 1 (Classifications); Arkansas DFA Office of Driver Services CDL page.","handbook":"","hbref":""},{"q":"Under Arkansas rules, a single vehicle with a GVWR of 26,001 pounds or more (or such a vehicle towing a unit that does not exceed 10,000 pounds GVWR) requires which CDL class?","options":["Class B","Class A","Class C","Class M"],"answer":0,"explanation":"Arkansas defines a Class B CDL as any single vehicle with a GVWR of 26,001 pounds or more, or any such vehicle towing a unit not exceeding 10,000 pounds GVWR. Source: Arkansas CDL Manual, Section 1 (Classifications); Arkansas DFA CDL page.","handbook":"","hbref":""},{"q":"In Arkansas, a vehicle that does not meet the Class A or Class B definition but is designed to transport 16 or more passengers (including the driver) or is used to transport placarded hazardous materials falls under which CDL class?","options":["Class A","Class C","Class B","Class P"],"answer":1,"explanation":"Arkansas defines a Class C CDL as a vehicle that does not meet Class A or B but is designed to carry 16 or more passengers including the driver, or transports placarded hazardous materials or a select agent/toxin under 42 CFR Part 73. Source: Arkansas CDL Manual, Section 1; Arkansas DFA CDL page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Arkansas CDL limited to driving a commercial motor vehicle only within the state (intrastate commerce)?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"Arkansas requires a driver to be at least 18 years old to operate a commercial motor vehicle in intrastate commerce (within Arkansas only). Source: Arkansas DFA Office of Driver Services CDL requirements.","handbook":"","hbref":""},{"q":"What is the minimum age required to obtain an Arkansas CDL valid for driving across state lines (interstate commerce)?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"Arkansas (following federal standards) requires a driver to be at least 21 years old to operate a commercial motor vehicle in interstate commerce. A driver 18-20 is limited to intrastate operation. Source: Arkansas DFA Office of Driver Services CDL requirements.","handbook":"","hbref":""},{"q":"Which endorsement is required in Arkansas to operate a tank vehicle designed to transport liquid or gas in a tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":0,"explanation":"Arkansas requires the N (Tank Vehicle) endorsement for vehicles designed to transport liquid or gaseous materials in a tank or tanks having an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more. Source: Arkansas CDL Manual, Section 1 (Endorsements) and Section 8.","handbook":"","hbref":""},{"q":"In Arkansas, which endorsement is required to drive a vehicle hauling material that is designated as hazardous and required to be placarded under 49 CFR Part 172?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"answer":2,"explanation":"Arkansas requires the H (Hazardous Materials) endorsement, regardless of vehicle class, for any driver hauling material designated hazardous under 49 U.S.C. 5103 and required to be placarded under 49 CFR Part 172. Source: Arkansas CDL Manual, Section 1 (Endorsements).","handbook":"","hbref":""},{"q":"Beyond passing a written knowledge test, what additional step does Arkansas require before issuing a Hazardous Materials (H) endorsement?","options":["A vision exam by an ophthalmologist","A TSA security threat assessment with fingerprints and a background check","A second road skills test in a tank vehicle","A notarized employer sponsorship letter"],"answer":1,"explanation":"To obtain, renew, or transfer a HazMat endorsement, Arkansas requires a TSA security threat assessment that includes fingerprinting and a federal background check (criminal, immigration, and FBI records). Drivers should allow at least 90 days. Source: Arkansas DFA Hazardous Materials Endorsement page; Arkansas CDL Manual, Section 1.","handbook":"","hbref":""},{"q":"Which endorsement does Arkansas require for a driver who wants to pull double or triple trailers?","options":["T endorsement","N endorsement","S endorsement","X endorsement"],"answer":0,"explanation":"Arkansas requires the T (Doubles/Triples) endorsement to pull double or triple trailers; the applicant must pass a knowledge examination on the problems associated with pulling multiple trailers. Source: Arkansas CDL Manual, Section 1 (Endorsements) and Section 7.","handbook":"","hbref":""},{"q":"In Arkansas, a driver who wishes to operate a vehicle designed to carry 16 or more people, including the driver, must obtain which endorsement?","options":["S endorsement","T endorsement","P endorsement","N endorsement"],"answer":2,"explanation":"Arkansas requires the P (Passenger) endorsement for drivers of a vehicle designed to carry 16 or more people including the driver. The applicant must pass a knowledge test and a skills test in a passenger vehicle. Source: Arkansas CDL Manual, Section 1 (Endorsements) and Section 4.","handbook":"","hbref":""},{"q":"Which endorsement must an Arkansas driver hold to drive a school bus, in addition to the Passenger (P) endorsement?","options":["H endorsement","T endorsement","S endorsement","X endorsement"],"answer":2,"explanation":"Arkansas requires the S (School Bus) endorsement to drive a school bus; the driver must pass a school-bus knowledge test and a skills test in a school bus, and the endorsement applies in any class (A, B, or C). Source: Arkansas CDL Manual, Section 1 (Endorsements) and Section 10.","handbook":"","hbref":""},{"q":"In Arkansas, a driver of a tank vehicle who must also haul placarded hazardous materials should obtain which single combination endorsement?","options":["T endorsement","X endorsement","P endorsement","S endorsement"],"answer":1,"explanation":"Arkansas issues the X endorsement as a combination of HazMat and Tank Vehicle; the driver must pass the knowledge examinations for both tank vehicles and hazardous materials. Source: Arkansas CDL Manual, Section 1 (Endorsements).","handbook":"","hbref":""},{"q":"According to the Arkansas CDL Manual, which set of endorsements are the ONLY ones that may be added to a Commercial Learner's Permit (CLP)?","options":["H, N, and T","P, H, and X","P, S, and N","T, S, and H"],"answer":2,"explanation":"The Arkansas CDL Manual states the only endorsements that may be added to a CLP are Passenger (P), School Bus (S), and Tank Vehicle (N). A HazMat (H) endorsement cannot be issued on a CLP. Source: Arkansas CDL Manual, Section 1 (Endorsements/CLP).","handbook":"","hbref":""},{"q":"In Arkansas, when a CLP is issued with a Tank Vehicle (N) endorsement, what restriction must it carry?","options":["No interstate operation (K)","No air brake equipped CMV (L)","No manual transmission (E)","No cargo in a CMV tank vehicle (X)"],"answer":3,"explanation":"Arkansas requires that a CLP issued with an N endorsement also carry the X restriction (No cargo in a CMV tank vehicle); the holder may only operate an empty tank that has been purged of any residue. Source: Arkansas CDL Manual, Section 1 (Restrictions).","handbook":"","hbref":""},{"q":"Under Arkansas and federal CLP rules, how long must a CLP holder wait after initial issuance before being eligible to take the CDL skills test?","options":["7 days","10 days","14 days","30 days"],"answer":2,"explanation":"Arkansas applies the federal rule that a CLP holder is not eligible to take the CDL skills test during the first 14 days after initial issuance of the CLP. Source: Arkansas DFA Commercial Learner's Permit (CLP) page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"For how long is an Arkansas Commercial Learner's Permit (CLP) valid before the holder must retake the general and endorsement knowledge tests?","options":["Up to 60 days","Up to 180 days","Up to 1 year","Up to 2 years"],"answer":2,"explanation":"An Arkansas CLP is valid for up to 1 year; after expiration the holder must retake the general and endorsement knowledge tests. Source: Arkansas DFA Commercial Learner's Permit (CLP) page.","handbook":"","hbref":""},{"q":"Which state agency issues the Commercial Driver License (CDL) in Arkansas?","options":["Arkansas State Police","Arkansas Department of Finance and Administration, Office of Driver Services","Arkansas Department of Transportation (ARDOT)","Federal Motor Carrier Safety Administration"],"answer":1,"explanation":"In Arkansas the CDL is issued by the Department of Finance and Administration (DFA), Office of Driver Services. ARDOT handles roads/permits and FMCSA is the federal regulator, but the licensing agency is DFA Driver Services. Source: Arkansas DFA Driver Services CDL page.","handbook":"","hbref":""},{"q":"When applying for an Arkansas CDL or CLP, which combination of proofs does the Office of Driver Services require an applicant to present?","options":["Only a Social Security card and a utility bill","Only a U.S. passport","Proof of identity/date of birth, Social Security number, Arkansas residency, and lawful presence","A high school diploma and proof of employment"],"answer":2,"explanation":"Arkansas DFA requires applicants to provide proof of identity and date of birth, proof of Social Security number, proof of Arkansas residency (current address), and proof of lawful presence/legal U.S. presence. Source: Arkansas DFA Driver Services documentation requirements ('Do You Have What You Need?').","handbook":"","hbref":""},{"q":"Under federal Entry-Level Driver Training (ELDT) rules applied in Arkansas (effective Feb. 7, 2022), where must a first-time applicant complete the required training before testing?","options":["Any community college in Arkansas","An Arkansas DFA revenue office","A provider listed on the FMCSA Training Provider Registry (TPR)","An employer's in-house orientation only"],"answer":2,"explanation":"ELDT requires first-time Class A/B applicants and applicants for the P, S, or H endorsement to complete training from a provider listed on the FMCSA Training Provider Registry before the state-administered test; for H the training is theory-only before the knowledge test, while Class A/B, P, and S require theory plus behind-the-wheel before the skills test. Source: FMCSA ELDT rule (49 CFR Part 380), effective Feb. 7, 2022; FMCSA Training Provider Registry.","handbook":"","hbref":""},{"q":"When applying for an Arkansas CDL, a driver must self-certify into one of the four medical certification categories. Which of the following is one of those four categories?","options":["Recreational interstate","Hazmat-exempt interstate","Provisional intrastate","Non-excepted interstate"],"answer":3,"explanation":"Arkansas drivers must self-certify into one of four categories: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, or Excepted Intrastate. Non-excepted interstate drivers must maintain a federal medical examiner's certificate. Source: Arkansas CDL Manual, Section 1.2 (Self-Certification); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"In Arkansas, a person is considered to be driving a commercial motor vehicle (CMV) under the influence and subject to disqualification if their blood alcohol concentration (BAC) is at or above what level?","options":["0.04%","0.08%","0.02%","0.10%"],"answer":0,"explanation":"Arkansas adopts the federal CMV standard: operating a CMV with a BAC of 0.04% or more is driving under the influence and a disqualifying major offense, half the 0.08% limit for non-commercial drivers. Source: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Arkansas law, what is the minimum disqualification period for a CDL holder's FIRST major offense (such as DUI in a CMV) when NOT transporting placarded hazardous materials?","options":["1 year","60 days","3 years","6 months"],"answer":0,"explanation":"A first major offense (DUI, 0.04+ BAC, test refusal, leaving the scene, etc.) results in a 1-year CDL disqualification in Arkansas. Source: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Arkansas, if a driver commits a first major offense while operating a CMV that is transporting placarded hazardous materials, the disqualification period increases to:","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"Arkansas increases the first-major-offense disqualification from 1 year to 3 years when the offense occurs while transporting placarded hazardous materials. Source: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period in Arkansas for a SECOND major offense committed in a separate incident by a CDL holder?","options":["Lifetime","10 years","3 years","5 years"],"answer":0,"explanation":"A second major offense results in lifetime (permanent) disqualification of the CDL in Arkansas. Source: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Refusing to submit to a required alcohol/BAC test while operating a CMV in Arkansas results in what disqualification for a first occurrence?","options":["1 year","90 days","30 days","No disqualification, only a fine"],"answer":0,"explanation":"Test refusal is treated as a major offense, carrying the same 1-year disqualification as a DUI (3 years if transporting placarded hazmat). Refusal is covered by Arkansas's implied-consent rule for CMV operators. Source: Ark. Code 27-23-112; Arkansas DFA CDL/CMV Offenses; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Arkansas's implied-consent provision for commercial drivers, a person who operates a CMV in the state is deemed to have given consent to:","options":["Testing of blood, breath, or urine for alcohol or controlled substances","Random vehicle searches without cause","Waiving the right to a hearing on any disqualification","Annual mandatory drug rehabilitation"],"answer":0,"explanation":"Arkansas's implied-consent rule provides that anyone who drives a CMV is deemed to have consented to alcohol/controlled-substance testing required to enforce the impaired-driving and 0.04% rules. Source: Ark. Code 27-23-112/27-23-113; Arkansas DFA CDL/CMV Offenses.","handbook":"","hbref":""},{"q":"A CDL holder in Arkansas who is found to have ANY measured or detected presence of alcohol (below 0.04%) while operating a CMV must be:","options":["Placed out of service for 24 hours","Disqualified for 1 year","Fined $2,500 and disqualified for 60 days","Arrested for DUI immediately"],"answer":0,"explanation":"Arkansas Code 27-23-113 prohibits operating a CMV with any measured or detected alcohol; a driver found in violation is placed out of service for 24 hours. A full DUI disqualification applies only at 0.04% or above. Source: Ark. Code 27-23-113.","handbook":"","hbref":""},{"q":"In Arkansas, a SECOND serious traffic violation committed in a separate incident within a 3-year period results in disqualification for how long?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Two serious traffic violations in separate incidents within 3 years result in a 60-day disqualification in Arkansas. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A THIRD (or subsequent) serious traffic violation in separate incidents within a 3-year period results in what Arkansas disqualification?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Three or more serious traffic violations in separate incidents within 3 years result in a 120-day disqualification in Arkansas. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for an Arkansas CDL holder (not a major offense)?","options":["Excessive speeding, 15 mph or more over the limit","Driving a CMV with a 0.04% BAC","Leaving the scene of an accident in a CMV","Using a CMV to commit a felony"],"answer":0,"explanation":"Excessive speeding (15+ mph over the limit), reckless driving, improper/erratic lane changes, following too closely, and texting/handheld phone use are serious traffic violations. The other choices listed are major offenses. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period are required before ANY disqualification period is triggered in Arkansas?","options":["2","1","3","4"],"answer":0,"explanation":"A single serious violation does not disqualify; the first disqualification (60 days) is triggered by the second serious violation within 3 years, and a third triggers 120 days. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for an Arkansas CDL holder's FIRST conviction of a railroad-highway grade crossing violation while operating a CMV?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation carries a minimum 60-day disqualification in Arkansas. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A SECOND railroad-highway grade crossing violation within a 3-year period results in what minimum Arkansas disqualification?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"A second grade-crossing violation within 3 years carries a minimum 120-day disqualification in Arkansas. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A THIRD railroad-highway grade crossing violation within a 3-year period results in what minimum Arkansas disqualification?","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third grade-crossing violation within 3 years carries a minimum 1-year disqualification in Arkansas. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which action is a railroad-highway grade crossing violation that can disqualify an Arkansas CDL holder?","options":["Failing to have enough space to drive completely through the crossing without stopping","Driving 5 mph over the limit near tracks","Sounding the horn before crossing","Stopping more than 15 feet from the nearest rail"],"answer":0,"explanation":"Grade-crossing violations include failing to slow and check for trains, failing to stop when required, not having space to clear the crossing, disobeying crossing traffic-control devices, and insufficient undercarriage clearance. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the minimum disqualification period for an Arkansas CDL holder's FIRST conviction of violating a driver or vehicle out-of-service (OOS) order?","options":["180 days","60 days","1 year","90 days"],"answer":0,"explanation":"A first conviction for violating an out-of-service order carries a minimum 180-day disqualification (up to 1 year) in Arkansas. Source: Ark. Code 27-23-112/27-23-114; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A SECOND conviction within 10 years for violating an out-of-service order results in what minimum Arkansas disqualification?","options":["2 years","180 days","1 year","5 years"],"answer":0,"explanation":"A second OOS-order violation within 10 years carries a minimum 2-year disqualification (up to 5 years) in Arkansas. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Besides disqualification, a driver convicted of violating an out-of-service order in Arkansas is subject to a civil penalty of at least what amount for a first conviction?","options":["$2,500","$1,000","$5,000","$500"],"answer":0,"explanation":"Arkansas imposes a civil penalty of not less than $2,500 on a driver for a first out-of-service-order violation (and not less than $5,000 for a second), in addition to disqualification. Source: Ark. Code 27-23-114.","handbook":"","hbref":""},{"q":"Under Arkansas and federal rules, how is a CDL driver's use of a hand-held mobile phone or texting while driving a CMV treated for disqualification purposes?","options":["As a serious traffic violation that, on repeat offenses, can lead to disqualification","As a major offense with a 1-year disqualification","As a lifetime-disqualifying offense","It carries no disqualification consequence, only a citation"],"answer":0,"explanation":"Texting or using a hand-held phone while driving a CMV is a serious traffic violation; multiple convictions count toward the 2-violations (60 days) / 3-violations (120 days) disqualification, with fines up to $2,750 for drivers. Source: Arkansas CDL manual; Ark. Code 27-51-1504; FMCSA 49 CFR 383.51/392.80-82.","handbook":"","hbref":""},{"q":"An Arkansas CDL holder who uses a CMV in the commission of a felony involving manufacturing, distributing, or dispensing a controlled substance faces what disqualification?","options":["Lifetime, with no possibility of reinstatement","1 year","3 years","10 years"],"answer":0,"explanation":"Using a CMV to manufacture, distribute, or dispense controlled substances is a major offense carrying a mandatory lifetime disqualification with no reinstatement, distinct from other lifetime bans that may allow reinstatement after 10 years. Source: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Arkansas, when a bus or placarded hazardous-materials vehicle must stop at a railroad-highway crossing, how far from the nearest rail must it stop?","options":["No closer than 15 feet and no farther than 50 feet","No closer than 10 feet and no farther than 40 feet","No closer than 25 feet and no farther than 75 feet","No closer than 5 feet and no farther than 15 feet"],"answer":0,"explanation":"Arkansas requires buses and placarded HazMat vehicles to stop no closer than 15 feet and no farther than 50 feet from the nearest rail, where the driver has the best view of the tracks. Source: Arkansas Commercial Driver License Manual, Sections 2.15, 4.3.5, and 9.","handbook":"","hbref":""},{"q":"Under Arkansas's Move Over law, what must a driver on a multi-lane highway do when approaching an authorized vehicle stopped with flashing lights?","options":["Come to a complete stop until the authorized vehicle moves","Move to the farthest possible lane from the stopped vehicle until safely past it","Maintain the posted speed and sound the horn while passing","Move into the lane closest to the stopped vehicle to keep traffic flowing"],"answer":1,"explanation":"Arkansas Code 27-51-310 requires drivers on a multi-lane road to move to the farthest possible lane or position from the stopped authorized vehicle and remain there until safely past. Source: Ark. Code Ann. 27-51-310 (Move Over law).","handbook":"","hbref":""},{"q":"On an Arkansas non-controlled-access highway, what is the maximum lawful speed for a truck of one-and-one-half-ton capacity or more?","options":["55 mph","60 mph","50 mph","65 mph"],"answer":2,"explanation":"Arkansas sets a maximum of 50 mph for trucks of one-and-one-half-ton capacity or more on highways that are not controlled-access, compared with 60 mph for other vehicles in those same locations. Source: Ark. Code Ann. 27-51-201.","handbook":"","hbref":""},{"q":"In Arkansas, when a school bus stops on a two-lane road and displays its alternating red warning lights to load or unload, which drivers must stop?","options":["Only drivers traveling behind the bus in the same direction","Only drivers in the lane immediately next to the bus","Only drivers within 100 feet of the bus","Drivers meeting or overtaking the bus from any direction"],"answer":3,"explanation":"On a two-lane road, Arkansas Code 27-51-1004 requires every operator meeting or overtaking the bus from any direction to come to a complete stop while the red lights flash. Source: Ark. Code Ann. 27-51-1004.","handbook":"","hbref":""},{"q":"What 2021 Arkansas law restricts use of the left-most lane on a multilane highway to passing only?","options":["Act 1054 of 2007","Act 1090 of 2021","Act 27 of 2021","Act 310 of 2019"],"answer":1,"explanation":"Act 1090 of 2021 reserves the left-most lane for passing on multilane highways; except where lanes are blocked, drivers must use the right lanes for travel. Source: Act 1090 of 2021; ARDOT public notice on the Left Lane Driving Law.","handbook":"","hbref":""},{"q":"If a commercial vehicle must stop on the shoulder of an Arkansas highway, within what time must the driver place the emergency warning devices (reflective triangles)?","options":["Within 5 minutes","Within 15 minutes","Within 10 minutes","Within 30 minutes"],"answer":2,"explanation":"A driver who must stop on a road or shoulder must place emergency warning devices within 10 minutes. Source: Arkansas Commercial Driver License Manual, Section 2.5 (Communicating).","handbook":"","hbref":""},{"q":"On a one-way or divided Arkansas highway, where must a stopped commercial vehicle place its three warning triangles?","options":["10 feet, 100 feet, and 100 feet on each side","25 feet, 100 feet, and 300 feet toward approaching traffic","50 feet, 150 feet, and 250 feet toward approaching traffic","10 feet, 100 feet, and 200 feet toward the approaching traffic"],"answer":3,"explanation":"On a one-way or divided highway the triangles go 10 feet, 100 feet, and 200 feet from the vehicle toward the approaching traffic. Source: Arkansas Commercial Driver License Manual, Section 2.5.","handbook":"","hbref":""},{"q":"Which group of vehicles is NOT among the 'authorized vehicles' covered by Arkansas's Move Over law (Ark. Code 27-51-310)?","options":["Any private passenger car with its 4-way flashers on","Tow trucks engaged in a towing operation","Arkansas Department of Transportation vehicles","Utility company vehicles displaying flashing lights"],"answer":0,"explanation":"Arkansas's Move Over law covers emergency response, law enforcement, ARDOT, ARDOT contractor, utility, and towing vehicles displaying flashing/revolving lights; an ordinary private car using only its hazard flashers is not an 'authorized vehicle.' Source: Ark. Code Ann. 27-51-310.","handbook":"","hbref":""},{"q":"On a non-controlled-access Arkansas highway, how much higher is the general speed limit for passenger cars than for trucks of one-and-one-half-ton capacity or more?","options":["5 mph higher (55 mph vs. 50 mph)","15 mph higher (65 mph vs. 50 mph)","10 mph higher (60 mph vs. 50 mph)","There is no difference; both are 55 mph"],"answer":2,"explanation":"Arkansas allows 60 mph for other vehicles but only 50 mph for heavy trucks on non-controlled-access highways, a 10 mph difference. Source: Ark. Code Ann. 27-51-201.","handbook":"","hbref":""},{"q":"Under Arkansas's school bus law, on which roadway type are oncoming drivers NOT required to stop for a school bus loading or unloading children?","options":["A two-lane road","A two-lane road with a center turning lane","A four-lane road without a median","A divided highway of four or more lanes with a median separation"],"answer":3,"explanation":"Arkansas requires all traffic in both directions to stop except on a divided highway of four or more lanes with a median separation, where only traffic following the bus must stop. A center turn lane is not a median. Source: Ark. Code Ann. 27-51-1004; official Arkansas school bus safety law guidance.","handbook":"","hbref":""},{"q":"By how much does Arkansas law require the maximum speed of heavy trucks (1.5 tons or more) to be set below the auto maximum on controlled-access highways?","options":["10 mph below the maximum for automobiles","5 mph below the maximum for automobiles","15 mph below the maximum for automobiles","The same as the maximum for automobiles"],"answer":0,"explanation":"Ark. Code 27-51-201 directs that the maximum permissible speed of trucks of one-and-one-half-ton capacity or more on controlled-access highways be fixed 10 mph below the auto maximum (e.g., 70 mph for trucks where cars may run 75). Source: Ark. Code Ann. 27-51-201.","handbook":"","hbref":""},{"q":"Which Arkansas-distinctive lane restriction is posted on certain six-lane Interstates as 'Trucks Use Right 2 Lanes'?","options":["All trucks must travel only in the center lane at all times","Vehicles with more than two axles may not use the far-left lane on designated six-lane Interstates","Trucks are banned from Interstates entirely between 7 a.m. and 9 a.m.","Trucks must use the left lane to keep the right lanes open for merging"],"answer":1,"explanation":"Act 1054 of 2007 amended Ark. Code 27-65-107(a) to keep vehicles with more than two axles out of the farthest-left lane on designated six-lane Interstates, signed 'Trucks Use Right 2 Lanes.' Source: Act 1054 of 2007; Ark. Code Ann. 27-65-107(a).","handbook":"","hbref":""},{"q":"If changing lanes is unsafe or impossible while approaching a stopped authorized vehicle in Arkansas, what does the Move Over law require?","options":["Stop completely on the roadway until the authorized vehicle leaves","Continue at the posted speed since lane changing is not possible","Pull onto the shoulder behind the authorized vehicle and wait","Reduce speed, proceed with caution, and maintain a reduced speed through the area"],"answer":3,"explanation":"When a safe lane change is not possible, Ark. Code 27-51-310 requires the driver to reduce speed, proceed with caution, and maintain a reduced speed appropriate to road conditions through the area where the authorized vehicle is stopped. Source: Ark. Code Ann. 27-51-310.","handbook":"","hbref":""},{"q":"What is the legal maximum width of a vehicle or load in Arkansas before an oversize permit is required?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Arkansas's legal maximum width on the State Highway System is 8 feet 6 inches; anything wider requires an oversize permit. Source: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles.","handbook":"","hbref":""},{"q":"On a two-lane Arkansas road carrying traffic both directions, where must a stopped CMV place its warning triangles?","options":["10 feet, 100 feet, and 200 feet only toward the rear","Within 10 feet of the vehicle and 100 feet behind and ahead of it","25 feet behind and 25 feet ahead of the vehicle only","100 feet behind only, with none placed ahead"],"answer":1,"explanation":"On a two-lane, two-way (undivided) road, place one triangle within 10 feet of the vehicle and one 100 feet behind and one 100 feet ahead. Source: Arkansas Commercial Driver License Manual, Section 2.5.","handbook":"","hbref":""},{"q":"What is the legal maximum height of a vehicle on Arkansas's State Highway System before a permit is required?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"answer":2,"explanation":"Arkansas's legal maximum height is 13 feet 6 inches; loads exceeding it require an oversize permit. Source: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles.","handbook":"","hbref":""},{"q":"What size red flags does Arkansas require on the rear corners of an overwidth or overlength permitted load?","options":["12-inch red flags","24-inch red flags","6-inch red flags","18-inch red flags"],"answer":3,"explanation":"Arkansas requires 18-inch red flags on the lower rear corners of overwidth and overlength loads, along with OVERSIZE LOAD signs front and rear. Source: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles.","handbook":"","hbref":""},{"q":"In Arkansas, what is the maximum speed at which a vehicle towing a manufactured or mobile home may be driven?","options":["45 mph","55 mph","60 mph","65 mph"],"answer":1,"explanation":"Arkansas permit rules prohibit driving a vehicle towing a manufactured or mobile home faster than 55 mph. Source: Code of Arkansas Rules 111-109 / ARDOT Permit Rules (oversize/overweight movement).","handbook":"","hbref":""},{"q":"Arkansas penalties for illegally passing a stopped school bus that is loading or unloading children include a fine in what range?","options":["A flat $100 fine with no jail","Not less than $500 nor more than $5,000","Not less than $250 nor more than $1,000","Not less than $50 nor more than $250"],"answer":2,"explanation":"Ark. Code 27-51-1001 sets the fine for passing a stopped school bus at not less than $250 nor more than $1,000, with possible jail, license suspension, and community service. Source: Ark. Code Ann. 27-51-1001.","handbook":"","hbref":""},{"q":"When stopping for a railroad-highway crossing in Arkansas, a commercial driver should also do which of the following before crossing?","options":["Turn on the four-way emergency flashers and use a pullout lane if available","Sound the horn continuously until the vehicle is across the tracks","Shift into a higher gear to clear the tracks faster","Stop directly on the nearest rail to maximize the view of the tracks"],"answer":0,"explanation":"When a stop is required at a grade crossing, the Arkansas manual instructs drivers to check traffic behind while stopping gradually, use a pullout lane if available, and turn on the four-way flashers; do not shift gears while crossing. Source: Arkansas Commercial Driver License Manual, Section 2.15.4.","handbook":"","hbref":""},{"q":"Which state agency is responsible for issuing Commercial Driver Licenses (CDLs) in Arkansas?","options":["The Arkansas State Police Highway Safety Division","The Arkansas Department of Transportation (ARDOT)","The Federal Motor Carrier Safety Administration (FMCSA)","The Arkansas Department of Finance and Administration (DFA), Office of Driver Services"],"answer":3,"explanation":"CDLs in Arkansas are issued by the Department of Finance and Administration (DFA), Office of Driver Services, which administers and enforces driver licensing law. Source: Arkansas DFA Office of Driver Services / CDL pages (dfa.arkansas.gov).","handbook":"","hbref":""},{"q":"In Arkansas, who typically administers the CDL skills (road) test?","options":["Any local revenue office clerk during the application appointment","The Arkansas State Police at designated testing locations, or an approved third-party tester","The Arkansas Department of Transportation weigh-station staff","Only private CDL schools that issue the license directly"],"answer":1,"explanation":"While DFA issues the license, CDL skills tests are administered at designated Arkansas State Police testing locations or by approved third-party testers. Source: Arkansas DFA Driver Services / Arkansas State Police CDL testing information.","handbook":"","hbref":""},{"q":"Before an applicant can take the CDL skills test in Arkansas, they must first obtain which credential?","options":["A Class D operator's license endorsement","A federal interstate operating authority number","A Commercial Learner's Permit (CLP)","A temporary 30-day commercial road permit"],"answer":2,"explanation":"An applicant must first hold a Commercial Learner's Permit (CLP) before taking the CDL skills test in Arkansas. Source: Arkansas DFA CLP page (dfa.arkansas.gov).","handbook":"","hbref":""},{"q":"Under Arkansas rules, how long must an applicant hold a Commercial Learner's Permit (CLP) before being allowed to take the CDL skills test?","options":["At least 14 days after initial issuance of the CLP","At least 30 days after initial issuance of the CLP","At least 7 days after initial issuance of the CLP","At least 60 days after initial issuance of the CLP"],"answer":0,"explanation":"Arkansas, following the federal CDL standard, prohibits taking the skills test in the first 14 days after the CLP is initially issued. Source: Arkansas DFA CLP page (49 CFR 383.25 standard adopted by Arkansas).","handbook":"","hbref":""},{"q":"What is the maximum period a Commercial Learner's Permit (CLP) remains valid in Arkansas before the knowledge tests must be retaken?","options":["Up to two years from issuance","Up to one year from issuance","Up to 90 days from issuance","Up to four years from issuance"],"answer":1,"explanation":"The CLP is valid for up to one year; if it expires, the holder must retake the general and any endorsement knowledge tests before a new permit can be issued. Source: Arkansas DFA CLP page (consistent with 49 CFR 383.25).","handbook":"","hbref":""},{"q":"A new applicant seeking a Class A CDL for the first time in Arkansas must complete which federally required training before taking the knowledge test for the CLP-to-CDL process?","options":["A state-run defensive driving certificate course","Entry-Level Driver Training (ELDT) from an FMCSA-registered provider","A National Safety Council first-aid certification","An employer-sponsored apprenticeship lasting 12 months"],"answer":1,"explanation":"Since February 7, 2022, first-time CDL applicants must complete Entry-Level Driver Training (ELDT) through a provider listed on the FMCSA Training Provider Registry before testing. Arkansas verifies completion via the registry. Source: FMCSA ELDT rule / Arkansas DFA CDL information.","handbook":"","hbref":""},{"q":"ELDT theory training completion is reported to which system that Arkansas DFA checks before issuing a CDL?","options":["The Arkansas DFA MyDMV portal only","The National Driver Register (NDR)","The Commercial Driver License Information System (CDLIS) only","The FMCSA Training Provider Registry (TPR)"],"answer":3,"explanation":"Training providers submit ELDT completion to the FMCSA Training Provider Registry (TPR); the state licensing agency, including Arkansas DFA, checks the TPR before allowing the skills test or issuing the CDL. Source: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov).","handbook":"","hbref":""},{"q":"ELDT is required in Arkansas for a first-time applicant in all of the following situations EXCEPT:","options":["Obtaining a Class A or Class B CDL for the first time","Upgrading an existing Class B CDL to a Class A CDL","Renewing an existing Class A CDL with no new endorsements","Obtaining a hazardous materials (H) endorsement for the first time"],"answer":2,"explanation":"ELDT applies to first-time Class A/B CDLs, upgrades from B to A, and first-time S, P, or H endorsements. A simple renewal of an existing CDL with no new endorsement does not trigger ELDT. Source: FMCSA ELDT rule (49 CFR Part 380) as applied in Arkansas.","handbook":"","hbref":""},{"q":"The CDL skills test in Arkansas consists of which three parts, in the order they are generally performed?","options":["Written knowledge, vision screening, and on-road driving","Air-brake check, hazmat handling, and on-road driving","Pre-trip inspection, basic vehicle control, and on-road driving","Basic vehicle control, knowledge test, and pre-trip inspection"],"answer":2,"explanation":"The Arkansas CDL skills test has three parts: the pre-trip vehicle inspection, basic vehicle control skills, and the on-road driving test. Source: Arkansas DFA / Arkansas State Police CDL skills test information (49 CFR 383.113).","handbook":"","hbref":""},{"q":"During the basic vehicle control portion of the Arkansas CDL skills test, the examiner primarily evaluates the applicant's ability to:","options":["Maneuver and back the vehicle precisely in a confined area","Recite the federal hours-of-service limits from memory","Calculate the gross combination weight rating of the vehicle","Demonstrate emergency roadside flare placement"],"answer":0,"explanation":"Basic vehicle control tests the driver's ability to control and position the vehicle through maneuvers such as straight-line backing, offset backing, and parking in a confined area. Source: Arkansas DFA / FMCSA skills test standards (49 CFR 383.113).","handbook":"","hbref":""},{"q":"Federal medical certification rules adopted by Arkansas require every CLP and CDL holder to self-certify into how many possible operating categories?","options":["Two categories","Four categories","Three categories","Six categories"],"answer":1,"explanation":"Every CLP/CDL holder must self-certify into one of four categories based on interstate vs. intrastate operation and excepted vs. non-excepted status. Source: Arkansas DFA Medical Certification page (49 CFR 383.71).","handbook":"","hbref":""},{"q":"Which self-certification category requires the driver to meet federal DOT physical qualification standards and carry a medical examiner's certificate?","options":["Excepted Interstate","Excepted Intrastate","Non-Excepted Interstate","Hobby / Personal Use Only"],"answer":2,"explanation":"A driver who self-certifies as Non-Excepted Interstate must meet federal DOT physical qualification standards (49 CFR 391) and maintain a valid medical examiner's certificate. Source: Arkansas DFA Medical Certification page (49 CFR 383.71).","handbook":"","hbref":""},{"q":"A driver who operates only within Arkansas and is NOT subject to the federal physical qualification requirements would most accurately self-certify as:","options":["Non-Excepted Interstate","Excepted Intrastate","Excepted Interstate","Non-Excepted Federal"],"answer":1,"explanation":"A driver operating only within the state who is not required to meet federal physical qualification standards self-certifies as Excepted Intrastate. Source: Arkansas DFA Medical Certification page (49 CFR 383.71).","handbook":"","hbref":""},{"q":"When a CDL applicant in Arkansas self-certifies as Non-Excepted Interstate, the DOT medical examiner who performs the physical must be:","options":["Employed by the Arkansas State Police medical unit","Any licensed pharmacist in the applicant's home county","Approved individually by the local revenue office manager","Listed on the FMCSA National Registry of Certified Medical Examiners"],"answer":3,"explanation":"Non-excepted drivers must obtain their physical from a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners, and that certificate is submitted to the Office of Driver Services. Source: Arkansas DFA Medical Certification page (49 CFR 391.41 / National Registry).","handbook":"","hbref":""},{"q":"Which of the following is an accepted way to submit a DOT Medical Examiner's Certificate and Self-Certification Affidavit to the Arkansas Office of Driver Services?","options":["Posting it directly to the FMCSA National Registry website","Handing it to a roadside Arkansas State Police trooper at any traffic stop","Bringing it in person to any Arkansas revenue office, or emailing/faxing it to the Office of Driver Services","Uploading it only to the applicant's private trucking employer portal"],"answer":2,"explanation":"Arkansas accepts the medical certificate and self-certification in person at any state revenue office, by mail to the Office of Driver Services, or by the email/fax channels DFA publishes. Source: Arkansas DFA Medical Certification / Register Medical Certificate pages.","handbook":"","hbref":""},{"q":"What happens to a non-excepted Arkansas CDL holder's commercial privileges if their DOT medical examiner's certificate expires and a new one is not submitted?","options":["The CDL is changed to a 'Not Certified' status and commercial driving privileges are lost","Nothing changes until the full CDL term expires years later","The CDL is automatically downgraded to a CLP for one year","The driver is fined but keeps full commercial privileges"],"answer":0,"explanation":"Failure to provide a current medical card by its expiration places the CDL in a 'Not Certified' medical status, removing commercial driving privileges until a valid certificate is submitted. Source: Arkansas DFA Medical Certification page.","handbook":"","hbref":""},{"q":"When renewing a CDL in Arkansas, a non-excepted driver must typically provide all of the following EXCEPT:","options":["A new Entry-Level Driver Training (ELDT) certificate for the existing class","Their current driver license","A completed Self-Certification Affidavit","A current Medical Examiner's Certificate"],"answer":0,"explanation":"Renewing an existing CDL of the same class with no new endorsement does not require ELDT; the driver does need their current license, a self-certification affidavit, and (if non-excepted) a current medical certificate. Source: Arkansas DFA Driver Services renewal requirements / FMCSA ELDT rule.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Arkansas CDL limited to intrastate (within-state) commercial driving?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"Arkansas allows a CDL for intrastate operation at age 18; interstate operation requires the driver to be 21. Source: Arkansas DFA CDL requirements (49 CFR 383 / 391 age standards).","handbook":"","hbref":""},{"q":"Regarding CDL application fees in Arkansas, which statement reflects the correct process-oriented expectation?","options":["CDL application and testing are always free of charge in Arkansas","The fee is permanently fixed by federal law and never changes","Only the hazmat endorsement carries any fee; all other CDL services are free","Fees are set by the state and can change, so applicants should confirm the current amount with DFA before applying"],"answer":3,"explanation":"Arkansas CDL fees (license, endorsement, and testing) are set by the state and are subject to change, so applicants should verify the current amounts with DFA rather than rely on a fixed figure. Source: Arkansas DFA Driver Services fee schedule (subject to change).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая наружная ширина транспортного средства (с грузом или без него) на автодорогах Арканзаса, при превышении которой требуется специальное разрешение?","options":["96 дюймов (8 футов)","102 дюйма (8 футов 6 дюймов)","108 дюймов (9 футов)","120 дюймов (10 футов)"],"explanation":"Arkansas Code Ann. 27-35-206 устанавливает максимальную допустимую ширину транспортного средства в 102 дюйма (8 футов 6 дюймов), без груза или с грузом; всё, что шире, требует разрешения на негабарит от ARDOT/Arkansas Highway Police."},"1":{"q":"Согласно действующему законодательству Арканзаса, какова максимальная высота транспортного средства (включая его груз), допустимая на автодорогах штата без специального разрешения?","options":["13 футов","13 футов 6 дюймов","14 футов","15 футов"],"explanation":"Arkansas Code Ann. 27-35-207, с поправками, внесёнными Act 871 of 2021 (вступившими в силу 28 июля 2021 года), повысил допустимый предел высоты с 13'6\" до 14 футов. Транспортное средство выше 14 футов требует специального разрешения (на превышение высоты)."},"2":{"q":"Какова максимальная полная масса транспортного средства или автопоезда, допустимая на автодорогах Арканзаса без разрешения на перевес?","options":["73,280 фунтов","80,000 фунтов","84,000 фунтов","88,000 фунтов"],"explanation":"В соответствии с федеральным стандартом и Arkansas Code Ann. 27-35-203, максимальная допустимая полная масса составляет 80,000 фунтов. Её превышение требует разрешения на перевес от ARDOT/Arkansas Highway Police Permit Section."},"3":{"q":"Какую максимальную нагрузку в Арканзасе можно перевозить на одиночной оси без разрешения?","options":["18,000 фунтов","20,000 фунтов","22,400 фунтов","34,000 фунтов"],"explanation":"Arkansas Code Ann. 27-35-203 ограничивает нагрузку на одиночную ось до 20,000 фунтов. Это соответствует федеральному ограничению для одиночной оси, применяемому на автодорогах Арканзаса."},"4":{"q":"Какова максимальная допустимая нагрузка на сдвоенную группу осей в Арканзасе без разрешения?","options":["32,000 фунтов","34,000 фунтов","40,000 фунтов","46,000 фунтов"],"explanation":"Arkansas Code Ann. 27-35-203 ограничивает нагрузку на сдвоенную ось до 34,000 фунтов. (С разрешением сдвоенная ось может достигать 46,000 фунтов, но 34,000 — это максимум без разрешения.)"},"5":{"q":"Согласно Arkansas Code 27-35-203, две последовательные оси считаются «сдвоенной осью», когда расстояние между их центрами составляет:","options":["Более 40 дюймов, но не более 96 дюймов","Более 96 дюймов, но не более 120 дюймов","Ровно 48 дюймов","Менее 40 дюймов"],"explanation":"Arkansas Code Ann. 27-35-203 определяет сдвоенную ось как две или более последовательные оси, центры которых расположены на расстоянии более 40 дюймов и не более 96 дюймов друг от друга, с суммарным ограничением в 34,000 фунтов."},"6":{"q":"Какова максимальная длина одиночного (неартикулированного) грузовика, эксплуатируемого на автодорогах Арканзаса без разрешения?","options":["35 футов","40 футов","45 футов","53 фута"],"explanation":"Arkansas Code Ann. 27-35-208 ограничивает одиночное (неартикулированное) транспортное средство общей длиной в 40 футов, без груза или с грузом."},"7":{"q":"Какова максимальная длина полуприцепа, эксплуатируемого в составе автопоезда с седельным тягачом, ниже которой штат Арканзас не может устанавливать ограничение?","options":["48 футов","50 футов","53 фута 6 дюймов","57 футов"],"explanation":"Arkansas Code Ann. 27-35-208 предусматривает, что штат не может устанавливать ограничение длины полуприцепа/прицепа менее 53 футов 6 дюймов для единицы, эксплуатируемой в составе автопоезда с седельным тягачом."},"8":{"q":"В составе автопоезда «седельный тягач — полуприцеп — прицеп» (спарка/двойной прицеп) на автодорогах Арканзаса, какова максимальная длина каждого прицепного звена?","options":["24 фута","28 футов","33 фута","40 футов"],"explanation":"Arkansas Code Ann. 27-35-208 ограничивает каждый полуприцеп или прицеп в составе автопоезда «седельный тягач — полуприцеп — прицеп» (двойной прицеп) общей длиной в 28 футов, без учёта сцепных устройств."},"9":{"q":"Какую формулу использует Арканзас для определения максимально допустимой нагрузки на группу осей в зависимости от расстояния между ними?","options":["Федеральную мостовую формулу (Formula B)","Арканзасскую формулу собственной массы (Tare Weight Formula)","Правило соотношения полной массы автопоезда (Gross Combination Ratio Rule)","Множитель межосевого расстояния сдвоенных осей (Tandem Spacing Multiplier)"],"explanation":"Арканзас применяет Федеральную мостовую формулу (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], для определения максимальной нагрузки, которую может нести данная группа осей, исходя из количества осей (N) и расстояния (L) между ними."},"10":{"q":"В Федеральной мостовой формуле, применяемой в Арканзасе, W = 500[LN/(N-1) + 12N + 36], что обозначает «N»?","options":["Количество осей в рассматриваемой группе","Собственную (тарную) массу транспортного средства","Количество шин на ведущей оси","Номинальное ограничение скорости на автодороге"],"explanation":"В Федеральной мостовой формуле, используемой в Арканзасе, N — это количество осей в рассматриваемой группе, L — расстояние в футах между крайними осями группы, а W — максимально допустимая нагрузка."},"11":{"q":"Груз водителя имеет ширину 9 футов 2 дюйма. На автодорогах Арканзаса этот груз:","options":["Допустим, поскольку он менее 10 футов","Требует разрешения на негабарит, поскольку превышает 102 дюйма","Допустим только на системе межштатных автомагистралей","Требует только флажка, но не разрешения"],"explanation":"Допустимая ширина в Арканзасе составляет 102 дюйма (8'6\") согласно Code 27-35-206. Груз шириной 9'2\" (110 дюймов) превышает допустимую ширину и требует разрешения на негабарит от ARDOT/Arkansas Highway Police."},"12":{"q":"Какое ведомство выдаёт разрешения на перевозку негабаритных и тяжеловесных грузов для системы автодорог штата Арканзас?","options":["Arkansas Department of Finance and Administration","Arkansas Department of Transportation через Arkansas Highway Police Permit Section","Шериф округа в каждом округе следования","Federal Motor Carrier Safety Administration"],"explanation":"Согласно ARDOT 2023 Permit Rules, разрешения на негабарит/перевес для системы автодорог штата выдаёт Arkansas Department of Transportation через Arkansas Highway Police Permit Section."},"13":{"q":"Когда автоперевозчику в Арканзасе требуется разрешение на перевес?","options":["Только когда груз можно уменьшить, разделив его","Когда транспортное средство превышает допустимые пределы полной массы, нагрузки на одиночную ось или на сдвоенную ось","Каждый раз, когда поездка пересекает границу округа","Только при движении в ночное время"],"explanation":"Согласно ARDOT Permit Rules и Code 27-35-203/210, разрешение на перевес требуется всякий раз, когда транспортное средство превышает допустимые пределы (80,000 фунтов полной массы, 20,000 фунтов на одиночную ось или 34,000 фунтов на сдвоенную ось, либо предел по мостовой формуле). Такие разрешения обычно выдаются только для неделимых грузов."},"14":{"q":"Разрешения на перевес в Арканзасе обычно выдаются только для грузов, которые являются:","options":["Делимыми на более мелкие допустимые грузы","Неделимыми (не могут быть разумно уменьшены до допустимой массы)","Перевозимыми со скоростью менее 45 mph","Принадлежащими государственному ведомству"],"explanation":"Согласно ARDOT Permit Rules, разрешение на перевес выдаётся для неделимых грузов — тех, которые не могут быть разумно разделены для соблюдения допустимых пределов массы. Делимые грузы должны быть уменьшены до допустимой массы, а не оформлены по разрешению."},"15":{"q":"Арканзас допускает годовое разрешение для автопоезда «седельный тягач/полуприцеп» с не менее чем пятью осями, перевозящего агрономические или садоводческие культуры в их естественном состоянии, до какой полной массы?","options":["84,000 фунтов","90,000 фунтов","100,000 фунтов","112,000 фунтов"],"explanation":"Arkansas Code Ann. 27-35-210 разрешает годовое разрешение для автопоезда «седельный тягач/полуприцеп» с минимум пятью осями, перевозящего агрономические или садоводческие культуры в естественном состоянии, до общей полной массы в 100,000 фунтов."},"16":{"q":"При перевозке по разрешению в Арканзасе сдвоенная группа осей может быть загружена максимум до:","options":["34,000 фунтов","40,000 фунтов","46,000 фунтов","50,000 фунтов"],"explanation":"Согласно ARDOT Permit Rules, сдвоенная группа осей по разрешению может нести до 46,000 фунтов (при условии, что ни одна одиночная ось не превышает 23,000 фунтов), по сравнению с допустимым пределом без разрешения в 34,000 фунтов согласно Code 27-35-203."},"17":{"q":"Пятиосный седельный тягач с полуприцепом в Арканзасе загружен до 80,000 фунтов полной массы: 20,000 фунтов на управляемую ось, 34,000 фунтов на ведущую сдвоенную ось и 26,000 фунтов на сдвоенную ось прицепа. Какое значение превышает допустимый предел?","options":["Полная масса","Нагрузка на управляемую (одиночную) ось","Нагрузка на ведущую сдвоенную ось","Ни одно из них не превышает свой допустимый предел"],"explanation":"Согласно Code 27-35-203, допустимые пределы составляют 80,000 фунтов полной массы, 20,000 фунтов на одиночную ось и 34,000 фунтов на сдвоенную ось. Каждое значение здесь не превышает свой предел или равно ему, поэтому ни одна ось и полная масса не превышают допустимый предел (при этом по-прежнему действует требование по межосевому расстоянию из мостовой формулы)."},"18":{"q":"Какое утверждение об общей длине автопоезда на автодорогах Арканзаса верно для седельного тягача с одиночным полуприцепом?","options":["Арканзас ограничивает общую длину автопоезда «тягач — полуприцеп» ровно 65 футами","Арканзас не устанавливает фиксированного ограничения общей длины для автопоезда «тягач с одиночным полуприцепом»; сам полуприцеп может быть длиной до 53'6\"","Арканзас ограничивает общую длину автопоезда 60 футами на всех дорогах","Арканзас не допускает полуприцепов длиннее 48 футов"],"explanation":"Arkansas Code Ann. 27-35-208 ограничивает длину полуприцепа (ограничение не может быть установлено менее 53'6\"), но не устанавливает фиксированного ограничения общей длины для автопоезда «седельный тягач плюс одиночный полуприцеп», что согласуется с федеральными правилами STAA."},"19":{"q":"Бортовая платформа в Арканзасе имеет высоту 14 футов 4 дюйма до верха груза. Без разрешения это транспортное средство:","options":["Допустимо, поскольку предел составляет 15 футов","Превышает по высоте и требует специального разрешения (на превышение высоты)","Допустимо только вне системы межштатных автомагистралей","Допустимо, поскольку высота в Арканзасе не регулируется"],"explanation":"Действующая допустимая высота в Арканзасе составляет 14 футов согласно Code 27-35-207 (с поправками, внесёнными Act 871 of 2021). Груз высотой 14'4\" превышает 14 футов и требует разрешения на превышение высоты от ARDOT/Arkansas Highway Police."},"20":{"q":"Какой класс CDL требуется в Арканзасе для управления автопоездом с полной массой автопоезда (GCWR) 26,001 фунт или более, в котором буксируемое звено имеет GVWR более 10,000 фунтов?","options":["Class A","Class B","Class C","Class D"],"explanation":"Арканзас определяет CDL Class A как любой автопоезд с GCWR 26,001 фунт или более, включающий буксируемое звено с GVWR более 10,000 фунтов. Источник: Arkansas CDL Manual, Section 1 (Classifications); страница CDL Arkansas DFA Office of Driver Services."},"21":{"q":"Согласно правилам Арканзаса, одиночное транспортное средство с GVWR 26,001 фунт или более (или такое транспортное средство, буксирующее звено, не превышающее 10,000 фунтов GVWR) требует какого класса CDL?","options":["Class B","Class A","Class C","Class M"],"explanation":"Арканзас определяет CDL Class B как любое одиночное транспортное средство с GVWR 26,001 фунт или более, или любое такое транспортное средство, буксирующее звено, не превышающее 10,000 фунтов GVWR. Источник: Arkansas CDL Manual, Section 1 (Classifications); страница CDL Arkansas DFA."},"22":{"q":"В Арканзасе транспортное средство, которое не соответствует определению Class A или Class B, но предназначено для перевозки 16 или более пассажиров (включая водителя) либо используется для перевозки опасных грузов, требующих табличек-плакатов, относится к какому классу CDL?","options":["Class A","Class C","Class B","Class P"],"explanation":"Арканзас определяет CDL Class C как транспортное средство, которое не соответствует Class A или B, но предназначено для перевозки 16 или более пассажиров включая водителя, либо перевозит опасные грузы, требующие табличек-плакатов, или специальный агент/токсин согласно 42 CFR Part 73. Источник: Arkansas CDL Manual, Section 1; страница CDL Arkansas DFA."},"23":{"q":"Каков минимальный возраст для получения CDL в Арканзасе, ограниченного управлением коммерческим транспортным средством только в пределах штата (внутриштатные перевозки)?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Арканзас требует, чтобы водителю было не менее 18 лет для управления коммерческим транспортным средством во внутриштатных перевозках (только в пределах Арканзаса). Источник: требования к CDL Arkansas DFA Office of Driver Services."},"24":{"q":"Каков минимальный возраст, необходимый для получения CDL в Арканзасе, действительного для управления транспортным средством через границы штатов (межштатные перевозки)?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Арканзас (следуя федеральным стандартам) требует, чтобы водителю было не менее 21 года для управления коммерческим транспортным средством в межштатных перевозках. Водитель 18-20 лет ограничен внутриштатными перевозками. Источник: требования к CDL Arkansas DFA Office of Driver Services."},"25":{"q":"Какое подтверждение (endorsement) требуется в Арканзасе для управления цистерной, предназначенной для перевозки жидкости или газа в ёмкости с индивидуальной номинальной вместимостью более 119 галлонов и суммарной номинальной вместимостью 1,000 галлонов или более?","options":["Подтверждение N","Подтверждение H","Подтверждение T","Подтверждение X"],"explanation":"Арканзас требует подтверждение N (Tank Vehicle) для транспортных средств, предназначенных для перевозки жидких или газообразных материалов в одной или нескольких ёмкостях с индивидуальной номинальной вместимостью более 119 галлонов и суммарной номинальной вместимостью 1,000 галлонов или более. Источник: Arkansas CDL Manual, Section 1 (Endorsements) и Section 8."},"26":{"q":"Какое подтверждение требуется в Арканзасе для управления транспортным средством, перевозящим материал, который классифицируется как опасный и должен иметь таблички-плакаты согласно 49 CFR Part 172?","options":["Подтверждение N","Подтверждение T","Подтверждение H","Подтверждение P"],"explanation":"Арканзас требует подтверждение H (Hazardous Materials), независимо от класса транспортного средства, для любого водителя, перевозящего материал, классифицированный как опасный согласно 49 U.S.C. 5103 и требующий табличек-плакатов согласно 49 CFR Part 172. Источник: Arkansas CDL Manual, Section 1 (Endorsements)."},"27":{"q":"Помимо сдачи письменного теста на знания, какой дополнительный шаг требует Арканзас перед выдачей подтверждения Hazardous Materials (H)?","options":["Проверку зрения у офтальмолога","Оценку угрозы безопасности TSA с отпечатками пальцев и проверкой биографии","Повторный практический экзамен по вождению на цистерне","Нотариально заверенное письмо-спонсорство от работодателя"],"explanation":"Для получения, продления или передачи подтверждения HazMat Арканзас требует оценку угрозы безопасности TSA, включающую снятие отпечатков пальцев и федеральную проверку биографии (криминальные, иммиграционные данные и записи FBI). Водителям следует закладывать не менее 90 дней. Источник: страница Hazardous Materials Endorsement Arkansas DFA; Arkansas CDL Manual, Section 1."},"28":{"q":"Какое подтверждение требует Арканзас для водителя, который хочет буксировать двойные или тройные прицепы?","options":["Подтверждение T","Подтверждение N","Подтверждение S","Подтверждение X"],"explanation":"Арканзас требует подтверждение T (Doubles/Triples) для буксировки двойных или тройных прицепов; заявитель должен сдать экзамен на знания по проблемам, связанным с буксировкой нескольких прицепов. Источник: Arkansas CDL Manual, Section 1 (Endorsements) и Section 7."},"29":{"q":"В Арканзасе водитель, который хочет управлять транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя, должен получить какое подтверждение?","options":["Подтверждение S","Подтверждение T","Подтверждение P","Подтверждение N"],"explanation":"Арканзас требует подтверждение P (Passenger) для водителей транспортного средства, предназначенного для перевозки 16 или более человек, включая водителя. Заявитель должен сдать тест на знания и практический экзамен на пассажирском транспортном средстве. Источник: Arkansas CDL Manual, Section 1 (Endorsements) и Section 4."},"30":{"q":"Какое подтверждение должен иметь водитель в Арканзасе для управления школьным автобусом, в дополнение к подтверждению Passenger (P)?","options":["Подтверждение H","Подтверждение T","Подтверждение S","Подтверждение X"],"explanation":"Арканзас требует подтверждение S (School Bus) для управления школьным автобусом; водитель должен сдать тест на знания по школьным автобусам и практический экзамен на школьном автобусе, и это подтверждение применяется в любом классе (A, B или C). Источник: Arkansas CDL Manual, Section 1 (Endorsements) и Section 10."},"31":{"q":"В Арканзасе водитель цистерны, который также должен перевозить опасные грузы с табличками-плакатами, должен получить какое единое комбинированное подтверждение?","options":["Подтверждение T","Подтверждение X","Подтверждение P","Подтверждение S"],"explanation":"Арканзас выдаёт подтверждение X как комбинацию HazMat и Tank Vehicle; водитель должен сдать экзамены на знания как по цистернам, так и по опасным грузам. Источник: Arkansas CDL Manual, Section 1 (Endorsements)."},"32":{"q":"Согласно Arkansas CDL Manual, какой набор подтверждений является ЕДИНСТВЕННЫМ, который может быть добавлен к Commercial Learner's Permit (CLP)?","options":["H, N и T","P, H и X","P, S и N","T, S и H"],"explanation":"Arkansas CDL Manual гласит, что единственными подтверждениями, которые могут быть добавлены к CLP, являются Passenger (P), School Bus (S) и Tank Vehicle (N). Подтверждение HazMat (H) не может быть выдано на CLP. Источник: Arkansas CDL Manual, Section 1 (Endorsements/CLP)."},"33":{"q":"В Арканзасе, когда CLP выдаётся с подтверждением Tank Vehicle (N), какое ограничение он должен содержать?","options":["Запрет на межштатные перевозки (K)","Запрет на CMV, оборудованные пневматическими тормозами (L)","Запрет на механическую коробку передач (E)","Запрет на груз в цистерне CMV (X)"],"explanation":"Арканзас требует, чтобы CLP, выданный с подтверждением N, также содержал ограничение X (Запрет на груз в цистерне CMV); владелец может управлять только пустой цистерной, которая была очищена от любых остатков. Источник: Arkansas CDL Manual, Section 1 (Restrictions)."},"34":{"q":"Согласно правилам CLP Арканзаса и федеральным правилам, сколько должен ждать владелец CLP после первоначальной выдачи, прежде чем он сможет сдавать практический экзамен CDL?","options":["7 дней","10 дней","14 дней","30 дней"],"explanation":"Арканзас применяет федеральное правило, согласно которому владелец CLP не имеет права сдавать практический экзамен CDL в течение первых 14 дней после первоначальной выдачи CLP. Источник: страница Commercial Learner's Permit (CLP) Arkansas DFA; 49 CFR 383.25."},"35":{"q":"В течение какого срока действителен Commercial Learner's Permit (CLP) Арканзаса, прежде чем владелец должен повторно сдать общий тест на знания и тест на знания по подтверждениям?","options":["До 60 дней","До 180 дней","До 1 года","До 2 лет"],"explanation":"CLP Арканзаса действителен до 1 года; после истечения срока действия владелец должен повторно сдать общий тест на знания и тест на знания по подтверждениям. Источник: страница Commercial Learner's Permit (CLP) Arkansas DFA."},"36":{"q":"Какое ведомство штата выдаёт Commercial Driver License (CDL) в Арканзасе?","options":["Arkansas State Police","Arkansas Department of Finance and Administration, Office of Driver Services","Arkansas Department of Transportation (ARDOT)","Federal Motor Carrier Safety Administration"],"explanation":"В Арканзасе CDL выдаётся Department of Finance and Administration (DFA), Office of Driver Services. ARDOT занимается дорогами/разрешениями, а FMCSA является федеральным регулятором, но лицензирующим ведомством является DFA Driver Services. Источник: страница CDL Arkansas DFA Driver Services."},"37":{"q":"При подаче заявления на CDL или CLP в Арканзасе, какую комбинацию подтверждающих документов требует предъявить Office of Driver Services?","options":["Только карту Social Security и счёт за коммунальные услуги","Только паспорт США","Подтверждение личности/даты рождения, номера Social Security, проживания в Арканзасе и законного нахождения","Аттестат об окончании средней школы и подтверждение трудоустройства"],"explanation":"Arkansas DFA требует, чтобы заявители предоставили подтверждение личности и даты рождения, подтверждение номера Social Security, подтверждение проживания в Арканзасе (текущий адрес) и подтверждение законного нахождения/легального присутствия в США. Источник: требования к документам Arkansas DFA Driver Services («Do You Have What You Need?»)."},"38":{"q":"Согласно федеральным правилам Entry-Level Driver Training (ELDT), применяемым в Арканзасе (вступившим в силу 7 февраля 2022 года), где впервые подающий заявление должен пройти необходимое обучение перед тестированием?","options":["В любом муниципальном колледже Арканзаса","В офисе доходов Arkansas DFA","У провайдера, указанного в FMCSA Training Provider Registry (TPR)","Только на внутреннем инструктаже работодателя"],"explanation":"ELDT требует, чтобы впервые подающие заявление на Class A/B и заявители на подтверждение P, S или H прошли обучение у провайдера, указанного в FMCSA Training Provider Registry, перед тестом, проводимым штатом; для H обучение является только теоретическим перед тестом на знания, тогда как Class A/B, P и S требуют теории плюс практики за рулём перед практическим экзаменом. Источник: правило FMCSA ELDT (49 CFR Part 380), вступившее в силу 7 февраля 2022 года; FMCSA Training Provider Registry."},"39":{"q":"При подаче заявления на CDL в Арканзасе водитель должен самостоятельно отнести себя к одной из четырёх медицинских сертификационных категорий. Какая из следующих является одной из этих четырёх категорий?","options":["Recreational interstate","Hazmat-exempt interstate","Provisional intrastate","Non-excepted interstate"],"explanation":"Водители Арканзаса должны самостоятельно отнести себя к одной из четырёх категорий: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate или Excepted Intrastate. Водители категории non-excepted interstate должны иметь действующий федеральный сертификат медицинского эксперта. Источник: Arkansas CDL Manual, Section 1.2 (Self-Certification); 49 CFR 383.71."},"40":{"q":"В Арканзасе человек считается управляющим коммерческим транспортным средством (CMV) в состоянии опьянения и подлежит дисквалификации, если его концентрация алкоголя в крови (BAC) равна или превышает какой уровень?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"Арканзас принимает федеральный стандарт для CMV: управление CMV с BAC 0.04% или более является управлением в состоянии опьянения и дисквалифицирующим тяжким нарушением, что составляет половину предела 0.08% для некоммерческих водителей. Источник: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"41":{"q":"Согласно законодательству Арканзаса, каков минимальный срок дисквалификации для владельца CDL за ПЕРВОЕ тяжкое нарушение (например, DUI в CMV), когда он НЕ перевозит опасные грузы с табличками-плакатами?","options":["1 год","60 дней","3 года","6 месяцев"],"explanation":"Первое тяжкое нарушение (DUI, BAC 0.04+, отказ от теста, оставление места происшествия и т. д.) влечёт дисквалификацию CDL на 1 год в Арканзасе. Источник: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"42":{"q":"В Арканзасе, если водитель совершает первое тяжкое нарушение во время управления CMV, перевозящим опасные грузы с табличками-плакатами, срок дисквалификации увеличивается до:","options":["3 года","1 год","5 лет","Пожизненно"],"explanation":"Арканзас увеличивает дисквалификацию за первое тяжкое нарушение с 1 года до 3 лет, когда нарушение происходит во время перевозки опасных грузов с табличками-плакатами. Источник: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"43":{"q":"Каков срок дисквалификации в Арканзасе за ВТОРОЕ тяжкое нарушение, совершённое в отдельном инциденте владельцем CDL?","options":["Пожизненно","10 лет","3 года","5 лет"],"explanation":"Второе тяжкое нарушение влечёт пожизненную (постоянную) дисквалификацию CDL в Арканзасе. Источник: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"44":{"q":"Отказ пройти обязательный тест на алкоголь/BAC во время управления CMV в Арканзасе влечёт какую дисквалификацию за первый случай?","options":["1 год","90 дней","30 дней","Без дисквалификации, только штраф"],"explanation":"Отказ от теста рассматривается как тяжкое нарушение и влечёт ту же дисквалификацию на 1 год, что и DUI (3 года при перевозке опасных грузов с табличками-плакатами). Отказ подпадает под правило подразумеваемого согласия Арканзаса для операторов CMV. Источник: Ark. Code 27-23-112; Arkansas DFA CDL/CMV Offenses; 49 CFR 383.51."},"45":{"q":"Согласно положению Арканзаса о подразумеваемом согласии для коммерческих водителей, лицо, управляющее CMV в штате, считается давшим согласие на:","options":["Тестирование крови, дыхания или мочи на алкоголь или контролируемые вещества","Случайные обыски транспортного средства без основания","Отказ от права на слушание по любой дисквалификации","Ежегодную обязательную наркологическую реабилитацию"],"explanation":"Правило подразумеваемого согласия Арканзаса предусматривает, что любой, кто управляет CMV, считается давшим согласие на тестирование на алкоголь/контролируемые вещества, необходимое для обеспечения соблюдения правил о вождении в состоянии опьянения и правила 0.04%. Источник: Ark. Code 27-23-112/27-23-113; Arkansas DFA CDL/CMV Offenses."},"46":{"q":"Владелец CDL в Арканзасе, у которого обнаружено ЛЮБОЕ измеренное или выявленное присутствие алкоголя (ниже 0.04%) во время управления CMV, должен быть:","options":["Выведен из эксплуатации (out of service) на 24 часа","Дисквалифицирован на 1 год","Оштрафован на $2,500 и дисквалифицирован на 60 дней","Немедленно арестован за DUI"],"explanation":"Arkansas Code 27-23-113 запрещает управление CMV с любым измеренным или выявленным алкоголем; водитель, признанный нарушителем, выводится из эксплуатации на 24 часа. Полная дисквалификация за DUI применяется только при 0.04% или выше. Источник: Ark. Code 27-23-113."},"47":{"q":"В Арканзасе ВТОРОЕ серьёзное нарушение правил дорожного движения, совершённое в отдельном инциденте в течение 3-летнего периода, влечёт дисквалификацию на какой срок?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения правил дорожного движения в отдельных инцидентах в течение 3 лет влекут дисквалификацию на 60 дней в Арканзасе. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"48":{"q":"ТРЕТЬЕ (или последующее) серьёзное нарушение правил дорожного движения в отдельных инцидентах в течение 3-летнего периода влечёт какую дисквалификацию в Арканзасе?","options":["120 дней","60 дней","1 год","90 дней"],"explanation":"Три или более серьёзных нарушения правил дорожного движения в отдельных инцидентах в течение 3 лет влекут дисквалификацию на 120 дней в Арканзасе. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"49":{"q":"Что из следующего классифицируется как СЕРЬЁЗНОЕ нарушение правил дорожного движения для владельца CDL в Арканзасе (а не тяжкое нарушение)?","options":["Чрезмерное превышение скорости, на 15 mph или более выше предела","Управление CMV с BAC 0.04%","Оставление места происшествия на CMV","Использование CMV для совершения тяжкого преступления (felony)"],"explanation":"Чрезмерное превышение скорости (на 15+ mph выше предела), безрассудное вождение, неправильная/беспорядочная смена полос, слишком близкое следование и отправка сообщений/использование телефона в руке являются серьёзными нарушениями правил дорожного движения. Остальные перечисленные варианты являются тяжкими нарушениями. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"50":{"q":"Сколько серьёзных нарушений правил дорожного движения в течение 3-летнего периода требуется, прежде чем в Арканзасе будет применён ЛЮБОЙ срок дисквалификации?","options":["2","1","3","4"],"explanation":"Одно серьёзное нарушение не влечёт дисквалификации; первая дисквалификация (60 дней) применяется при втором серьёзном нарушении в течение 3 лет, а третье влечёт 120 дней. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"51":{"q":"Какова минимальная дисквалификация для владельца CDL в Арканзасе за ПЕРВОЕ осуждение за нарушение на железнодорожном переезде во время управления CMV?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде влечёт минимальную дисквалификацию на 60 дней в Арканзасе. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"52":{"q":"ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода влечёт какую минимальную дисквалификацию в Арканзасе?","options":["120 дней","60 дней","1 год","90 дней"],"explanation":"Второе нарушение на переезде в течение 3 лет влечёт минимальную дисквалификацию на 120 дней в Арканзасе. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"53":{"q":"ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода влечёт какую минимальную дисквалификацию в Арканзасе?","options":["1 год","120 дней","180 дней","60 дней"],"explanation":"Третье нарушение на переезде в течение 3 лет влечёт минимальную дисквалификацию на 1 год в Арканзасе. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"54":{"q":"Какое действие является нарушением на железнодорожном переезде, которое может дисквалифицировать владельца CDL в Арканзасе?","options":["Отсутствие достаточного пространства, чтобы проехать переезд полностью без остановки","Движение на 5 mph выше предела рядом с путями","Подача сигнала клаксоном перед переездом","Остановка более чем в 15 футах от ближайшего рельса"],"explanation":"Нарушения на переезде включают непринятие мер для снижения скорости и проверки наличия поездов, неостановку при необходимости, отсутствие пространства для проезда переезда, несоблюдение средств регулирования движения на переезде и недостаточный дорожный просвет. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"55":{"q":"Каков минимальный срок дисквалификации для владельца CDL в Арканзасе за ПЕРВОЕ осуждение за нарушение приказа о выводе водителя или транспортного средства из эксплуатации (out-of-service, OOS)?","options":["180 дней","60 дней","1 год","90 дней"],"explanation":"Первое осуждение за нарушение приказа о выводе из эксплуатации влечёт минимальную дисквалификацию на 180 дней (до 1 года) в Арканзасе. Источник: Ark. Code 27-23-112/27-23-114; Arkansas CDL manual; 49 CFR 383.51."},"56":{"q":"ВТОРОЕ осуждение в течение 10 лет за нарушение приказа о выводе из эксплуатации влечёт какую минимальную дисквалификацию в Арканзасе?","options":["2 года","180 дней","1 год","5 лет"],"explanation":"Второе нарушение приказа OOS в течение 10 лет влечёт минимальную дисквалификацию на 2 года (до 5 лет) в Арканзасе. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"57":{"q":"Помимо дисквалификации, водитель, осуждённый за нарушение приказа о выводе из эксплуатации в Арканзасе, подлежит гражданско-правовому штрафу в размере не менее какой суммы за первое осуждение?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"Арканзас налагает гражданско-правовой штраф в размере не менее $2,500 на водителя за первое нарушение приказа о выводе из эксплуатации (и не менее $5,000 за второе), в дополнение к дисквалификации. Источник: Ark. Code 27-23-114."},"58":{"q":"Согласно правилам Арканзаса и федеральным правилам, как рассматривается использование водителем CDL мобильного телефона в руке или отправка сообщений во время управления CMV для целей дисквалификации?","options":["Как серьёзное нарушение правил дорожного движения, которое при повторных нарушениях может привести к дисквалификации","Как тяжкое нарушение с дисквалификацией на 1 год","Как нарушение, влекущее пожизненную дисквалификацию","Оно не влечёт последствий в виде дисквалификации, только штраф"],"explanation":"Отправка сообщений или использование телефона в руке во время управления CMV является серьёзным нарушением правил дорожного движения; несколько осуждений засчитываются в счёт дисквалификации за 2 нарушения (60 дней) / 3 нарушения (120 дней), со штрафами до $2,750 для водителей. Источник: Arkansas CDL manual; Ark. Code 27-51-1504; FMCSA 49 CFR 383.51/392.80-82."},"59":{"q":"Владелец CDL в Арканзасе, который использует CMV при совершении тяжкого преступления (felony), связанного с изготовлением, распространением или сбытом контролируемого вещества, сталкивается с какой дисквалификацией?","options":["Пожизненной, без возможности восстановления","1 год","3 года","10 лет"],"explanation":"Использование CMV для изготовления, распространения или сбыта контролируемых веществ является тяжким нарушением, влекущим обязательную пожизненную дисквалификацию без возможности восстановления, в отличие от других пожизненных запретов, которые могут допускать восстановление через 10 лет. Источник: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"60":{"q":"В Арканзасе, когда автобус или транспортное средство с табличками об опасных грузах должны остановиться на железнодорожном переезде, на каком расстоянии от ближайшего рельса они обязаны остановиться?","options":["Не ближе 15 футов и не дальше 50 футов","Не ближе 10 футов и не дальше 40 футов","Не ближе 25 футов и не дальше 75 футов","Не ближе 5 футов и не дальше 15 футов"],"explanation":"Арканзас требует, чтобы автобусы и транспортные средства с табличками HazMat останавливались не ближе 15 футов и не дальше 50 футов от ближайшего рельса — там, где у водителя наилучший обзор путей. Источник: Arkansas Commercial Driver License Manual, разделы 2.15, 4.3.5 и 9."},"61":{"q":"Согласно закону Арканзаса «Move Over», что должен сделать водитель на многополосной автомагистрали, приближаясь к стоящему уполномоченному транспортному средству с включёнными проблесковыми маячками?","options":["Полностью остановиться, пока уполномоченное транспортное средство не тронется","Перестроиться в максимально удалённую полосу от стоящего транспортного средства и оставаться там, пока безопасно его не минует","Сохранять установленную скорость и подавать звуковой сигнал при проезде","Перестроиться в полосу, ближайшую к стоящему транспортному средству, чтобы не прерывать поток движения"],"explanation":"Arkansas Code 27-51-310 требует, чтобы водители на многополосной дороге перестраивались в максимально удалённую полосу или позицию от стоящего уполномоченного транспортного средства и оставались там, пока безопасно его не минуют. Источник: Ark. Code Ann. 27-51-310 (закон Move Over)."},"62":{"q":"На автомагистрали Арканзаса без ограниченного доступа какова максимальная разрешённая скорость для грузовика грузоподъёмностью полторы тонны и более?","options":["55 mph","60 mph","50 mph","65 mph"],"explanation":"Арканзас устанавливает максимум 50 mph для грузовиков грузоподъёмностью полторы тонны и более на автомагистралях без ограниченного доступа, по сравнению с 60 mph для прочих транспортных средств в тех же местах. Источник: Ark. Code Ann. 27-51-201."},"63":{"q":"В Арканзасе, когда школьный автобус останавливается на двухполосной дороге и включает попеременно мигающие красные предупредительные огни для посадки или высадки, какие водители обязаны остановиться?","options":["Только водители, едущие позади автобуса в том же направлении","Только водители на полосе, непосредственно прилегающей к автобусу","Только водители в пределах 100 футов от автобуса","Водители, встречающие или обгоняющие автобус с любого направления"],"explanation":"На двухполосной дороге Arkansas Code 27-51-1004 требует, чтобы каждый водитель, встречающий или обгоняющий автобус с любого направления, полностью остановился, пока мигают красные огни. Источник: Ark. Code Ann. 27-51-1004."},"64":{"q":"Какой закон Арканзаса 2021 года ограничивает использование крайней левой полосы на многополосной автомагистрали только для обгона?","options":["Act 1054 of 2007","Act 1090 of 2021","Act 27 of 2021","Act 310 of 2019"],"explanation":"Act 1090 of 2021 резервирует крайнюю левую полосу для обгона на многополосных автомагистралях; за исключением случаев, когда полосы заблокированы, водители должны использовать правые полосы для движения. Источник: Act 1090 of 2021; публичное уведомление ARDOT о законе о движении по левой полосе (Left Lane Driving Law)."},"65":{"q":"Если коммерческое транспортное средство вынуждено остановиться на обочине автомагистрали Арканзаса, в течение какого времени водитель должен выставить аварийные предупредительные устройства (светоотражающие треугольники)?","options":["В течение 5 минут","В течение 15 минут","В течение 10 минут","В течение 30 минут"],"explanation":"Водитель, вынужденный остановиться на дороге или обочине, должен выставить аварийные предупредительные устройства в течение 10 минут. Источник: Arkansas Commercial Driver License Manual, раздел 2.5 (Communicating)."},"66":{"q":"На дороге Арканзаса с односторонним движением или с разделительной полосой, где остановившееся коммерческое транспортное средство должно выставить три предупредительных треугольника?","options":["10 футов, 100 футов и 100 футов с каждой стороны","25 футов, 100 футов и 300 футов в сторону приближающегося движения","50 футов, 150 футов и 250 футов в сторону приближающегося движения","10 футов, 100 футов и 200 футов в сторону приближающегося движения"],"explanation":"На дороге с односторонним движением или с разделительной полосой треугольники ставятся на 10 футов, 100 футов и 200 футов от транспортного средства в сторону приближающегося движения. Источник: Arkansas Commercial Driver License Manual, раздел 2.5."},"67":{"q":"Какая группа транспортных средств НЕ входит в число «уполномоченных транспортных средств», на которые распространяется закон Арканзаса Move Over (Ark. Code 27-51-310)?","options":["Любой частный легковой автомобиль с включённой аварийной сигнализацией (4-way flashers)","Эвакуаторы, выполняющие буксировочную операцию","Транспортные средства Департамента транспорта Арканзаса (Arkansas Department of Transportation)","Транспортные средства коммунальных служб с включёнными проблесковыми маячками"],"explanation":"Закон Арканзаса Move Over распространяется на транспортные средства экстренного реагирования, правоохранительных органов, ARDOT, подрядчиков ARDOT, коммунальных служб и буксировки с включёнными мигающими/вращающимися маячками; обычный частный автомобиль, использующий только аварийную сигнализацию, не является «уполномоченным транспортным средством». Источник: Ark. Code Ann. 27-51-310."},"68":{"q":"На автомагистрали Арканзаса без ограниченного доступа насколько выше общее ограничение скорости для легковых автомобилей, чем для грузовиков грузоподъёмностью полторы тонны и более?","options":["На 5 mph выше (55 mph против 50 mph)","На 15 mph выше (65 mph против 50 mph)","На 10 mph выше (60 mph против 50 mph)","Разницы нет; для обоих 55 mph"],"explanation":"Арканзас разрешает 60 mph для прочих транспортных средств, но только 50 mph для тяжёлых грузовиков на автомагистралях без ограниченного доступа — разница в 10 mph. Источник: Ark. Code Ann. 27-51-201."},"69":{"q":"Согласно закону Арканзаса о школьных автобусах, на каком типе дороги встречные водители НЕ обязаны останавливаться перед школьным автобусом, выполняющим посадку или высадку детей?","options":["Двухполосная дорога","Двухполосная дорога с центральной полосой для поворота","Четырёхполосная дорога без разделительной полосы","Автомагистраль с разделительной полосой из четырёх или более полос с разделением посередине"],"explanation":"Арканзас требует, чтобы всё движение в обоих направлениях останавливалось, за исключением автомагистрали с разделительной полосой из четырёх или более полос с разделением посередине, где останавливаться обязано только движение, следующее за автобусом. Центральная полоса для поворота не является разделительной полосой. Источник: Ark. Code Ann. 27-51-1004; официальные разъяснения закона Арканзаса о безопасности школьных автобусов."},"70":{"q":"Насколько закон Арканзаса требует устанавливать максимальную скорость тяжёлых грузовиков (1,5 тонны и более) ниже максимума для легковых автомобилей на автомагистралях с ограниченным доступом?","options":["На 10 mph ниже максимума для автомобилей","На 5 mph ниже максимума для автомобилей","На 15 mph ниже максимума для автомобилей","Так же, как максимум для автомобилей"],"explanation":"Ark. Code 27-51-201 предписывает устанавливать максимально допустимую скорость грузовиков грузоподъёмностью полторы тонны и более на автомагистралях с ограниченным доступом на 10 mph ниже максимума для автомобилей (например, 70 mph для грузовиков там, где автомобили могут двигаться 75). Источник: Ark. Code Ann. 27-51-201."},"71":{"q":"Какое характерное для Арканзаса ограничение по полосам обозначено на некоторых шестиполосных межштатных автомагистралях как «Trucks Use Right 2 Lanes»?","options":["Все грузовики должны двигаться только по центральной полосе постоянно","Транспортным средствам более чем с двумя осями запрещено использовать крайнюю левую полосу на обозначенных шестиполосных межштатных автомагистралях","Грузовикам полностью запрещён въезд на межштатные автомагистрали с 7 до 9 утра","Грузовики должны использовать левую полосу, чтобы правые полосы оставались свободными для перестроения"],"explanation":"Act 1054 of 2007 внёс изменения в Ark. Code 27-65-107(a), чтобы транспортные средства более чем с двумя осями не использовали крайнюю левую полосу на обозначенных шестиполосных межштатных автомагистралях, отмеченных знаком «Trucks Use Right 2 Lanes». Источник: Act 1054 of 2007; Ark. Code Ann. 27-65-107(a)."},"72":{"q":"Если перестроение небезопасно или невозможно при приближении к стоящему уполномоченному транспортному средству в Арканзасе, чего требует закон Move Over?","options":["Полностью остановиться на проезжей части, пока уполномоченное транспортное средство не уедет","Продолжать движение с установленной скоростью, поскольку перестроение невозможно","Съехать на обочину позади уполномоченного транспортного средства и ждать","Снизить скорость, двигаться с осторожностью и сохранять пониженную скорость на протяжении всего участка"],"explanation":"Когда безопасное перестроение невозможно, Ark. Code 27-51-310 требует, чтобы водитель снизил скорость, двигался с осторожностью и сохранял пониженную скорость, соответствующую дорожным условиям, на участке, где стоит уполномоченное транспортное средство. Источник: Ark. Code Ann. 27-51-310."},"73":{"q":"Какова законная максимальная ширина транспортного средства или груза в Арканзасе, до превышения которой не требуется разрешение на негабаритный груз?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Законная максимальная ширина на системе автомагистралей штата Арканзас составляет 8 feet 6 inches; для всего, что шире, требуется разрешение на негабаритный груз. Источник: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"74":{"q":"На двухполосной дороге Арканзаса с движением в обоих направлениях, где остановившееся CMV должно выставить предупредительные треугольники?","options":["10 футов, 100 футов и 200 футов только в сторону задней части","В пределах 10 футов от транспортного средства, а также по 100 футов позади и впереди него","Только 25 футов позади и 25 футов впереди транспортного средства","Только 100 футов позади, без выставления впереди"],"explanation":"На двухполосной дороге с двусторонним движением (без разделительной полосы) выставьте один треугольник в пределах 10 футов от транспортного средства, один — на 100 футов позади и один — на 100 футов впереди. Источник: Arkansas Commercial Driver License Manual, раздел 2.5."},"75":{"q":"Какова законная максимальная высота транспортного средства на системе автомагистралей штата Арканзас, до превышения которой не требуется разрешение?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"explanation":"Законная максимальная высота в Арканзасе составляет 13 feet 6 inches; для грузов, превышающих её, требуется разрешение на негабаритный груз. Источник: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"76":{"q":"Красные флаги какого размера Арканзас требует размещать на задних углах негабаритного по ширине или длине разрешённого груза?","options":["Красные флаги 12 inch","Красные флаги 24 inch","Красные флаги 6 inch","Красные флаги 18 inch"],"explanation":"Арканзас требует размещать красные флаги размером 18 inch на нижних задних углах негабаритных по ширине и длине грузов, а также знаки OVERSIZE LOAD спереди и сзади. Источник: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"77":{"q":"В Арканзасе какова максимальная скорость, с которой можно двигаться транспортному средству, буксирующему промышленный или мобильный дом?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"Правила выдачи разрешений Арканзаса запрещают двигаться транспортному средству, буксирующему промышленный или мобильный дом, быстрее 55 mph. Источник: Code of Arkansas Rules 111-109 / ARDOT Permit Rules (перевозка негабаритных/сверхтяжёлых грузов)."},"78":{"q":"Штрафы Арканзаса за незаконный проезд мимо остановившегося школьного автобуса, выполняющего посадку или высадку детей, включают штраф в каком диапазоне?","options":["Фиксированный штраф $100 без тюремного заключения","Не менее $500 и не более $5,000","Не менее $250 и не более $1,000","Не менее $50 и не более $250"],"explanation":"Ark. Code 27-51-1001 устанавливает штраф за проезд мимо остановившегося школьного автобуса в размере не менее $250 и не более $1,000, с возможным тюремным заключением, приостановлением действия прав и общественными работами. Источник: Ark. Code Ann. 27-51-1001."},"79":{"q":"При остановке на железнодорожном переезде в Арканзасе коммерческий водитель должен также сделать что из перечисленного перед пересечением?","options":["Включить аварийную сигнализацию (four-way emergency flashers) и использовать карман для съезда, если он есть","Подавать звуковой сигнал непрерывно, пока транспортное средство не пересечёт пути","Переключиться на повышенную передачу, чтобы быстрее проехать пути","Остановиться прямо на ближайшем рельсе, чтобы максимально расширить обзор путей"],"explanation":"Когда на переезде требуется остановка, руководство Арканзаса предписывает водителям следить за движением сзади, останавливаясь плавно, использовать карман для съезда, если он есть, и включить аварийную сигнализацию; не переключать передачи во время пересечения. Источник: Arkansas Commercial Driver License Manual, раздел 2.15.4."},"80":{"q":"Какое государственное ведомство отвечает за выдачу коммерческих водительских удостоверений (CDL) в Арканзасе?","options":["Отдел безопасности дорожного движения полиции штата Арканзас (Arkansas State Police Highway Safety Division)","Департамент транспорта Арканзаса (Arkansas Department of Transportation, ARDOT)","Федеральное управление безопасности автоперевозчиков (Federal Motor Carrier Safety Administration, FMCSA)","Департамент финансов и администрации Арканзаса (DFA), Управление водительских услуг (Office of Driver Services)"],"explanation":"CDL в Арканзасе выдаются Департаментом финансов и администрации (DFA), Управлением водительских услуг (Office of Driver Services), которое администрирует и обеспечивает соблюдение законодательства о водительском лицензировании. Источник: страницы Arkansas DFA Office of Driver Services / CDL (dfa.arkansas.gov)."},"81":{"q":"В Арканзасе кто обычно проводит практический экзамен по навыкам CDL (вождение по дороге)?","options":["Любой клерк местного офиса доходов во время приёма по подаче заявления","Полиция штата Арканзас в назначенных пунктах тестирования или утверждённый сторонний экзаменатор","Персонал весовых станций Департамента транспорта Арканзаса","Только частные школы CDL, которые выдают удостоверение напрямую"],"explanation":"Хотя удостоверение выдаёт DFA, экзамены по навыкам CDL проводятся в назначенных пунктах тестирования полиции штата Арканзас или утверждёнными сторонними экзаменаторами. Источник: Arkansas DFA Driver Services / информация о тестировании CDL полиции штата Арканзас."},"82":{"q":"Прежде чем заявитель сможет сдать экзамен по навыкам CDL в Арканзасе, он должен сначала получить какой документ?","options":["Дополнение к водительскому удостоверению класса D (Class D operator's license endorsement)","Федеральный номер разрешения на междуштатную деятельность","Коммерческое ученическое разрешение (Commercial Learner's Permit, CLP)","Временное 30-дневное коммерческое разрешение на вождение по дороге"],"explanation":"Прежде чем сдавать экзамен по навыкам CDL в Арканзасе, заявитель должен сначала иметь коммерческое ученическое разрешение (CLP). Источник: страница Arkansas DFA CLP (dfa.arkansas.gov)."},"83":{"q":"Согласно правилам Арканзаса, как долго заявитель должен владеть коммерческим ученическим разрешением (CLP), прежде чем ему будет разрешено сдавать экзамен по навыкам CDL?","options":["Не менее 14 days после первоначальной выдачи CLP","Не менее 30 days после первоначальной выдачи CLP","Не менее 7 days после первоначальной выдачи CLP","Не менее 60 days после первоначальной выдачи CLP"],"explanation":"Арканзас, следуя федеральному стандарту CDL, запрещает сдачу экзамена по навыкам в первые 14 days после первоначальной выдачи CLP. Источник: страница Arkansas DFA CLP (стандарт 49 CFR 383.25, принятый Арканзасом)."},"84":{"q":"Каков максимальный срок действия коммерческого ученического разрешения (CLP) в Арканзасе, прежде чем потребуется пересдать экзамены на знание?","options":["До двух лет с момента выдачи","До одного года с момента выдачи","До 90 days с момента выдачи","До четырёх лет с момента выдачи"],"explanation":"CLP действует до одного года; если срок его действия истекает, держатель должен пересдать общий экзамен на знание и экзамены на любые дополнения, прежде чем сможет быть выдано новое разрешение. Источник: страница Arkansas DFA CLP (соответствует 49 CFR 383.25)."},"85":{"q":"Новый заявитель, впервые получающий CDL класса A в Арканзасе, должен пройти какую федерально обязательную подготовку перед сдачей экзамена на знание в процессе перехода от CLP к CDL?","options":["Курс с получением государственного сертификата по защитному вождению","Подготовку водителей начального уровня (Entry-Level Driver Training, ELDT) у поставщика, зарегистрированного в FMCSA","Сертификацию по оказанию первой помощи Национального совета безопасности (National Safety Council)","Спонсируемую работодателем стажировку продолжительностью 12 месяцев"],"explanation":"С 7 февраля 2022 года заявители, впервые получающие CDL, должны пройти подготовку водителей начального уровня (ELDT) у поставщика, указанного в реестре поставщиков обучения FMCSA (Training Provider Registry), перед тестированием. Арканзас проверяет прохождение через реестр. Источник: правило FMCSA ELDT / информация Arkansas DFA о CDL."},"86":{"q":"Прохождение теоретической части подготовки ELDT регистрируется в какой системе, которую Arkansas DFA проверяет перед выдачей CDL?","options":["Только в портале Arkansas DFA MyDMV","В Национальном реестре водителей (National Driver Register, NDR)","Только в Информационной системе коммерческих водительских удостоверений (Commercial Driver License Information System, CDLIS)","В реестре поставщиков обучения FMCSA (Training Provider Registry, TPR)"],"explanation":"Поставщики обучения подают данные о прохождении ELDT в реестр поставщиков обучения FMCSA (TPR); государственное лицензирующее ведомство, включая Arkansas DFA, проверяет TPR перед допуском к экзамену по навыкам или выдачей CDL. Источник: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov)."},"87":{"q":"ELDT требуется в Арканзасе для заявителя, обращающегося впервые, во всех следующих ситуациях, КРОМЕ:","options":["Получение CDL класса A или класса B впервые","Повышение имеющегося CDL класса B до CDL класса A","Продление имеющегося CDL класса A без новых дополнений","Получение дополнения на опасные материалы (H) впервые"],"explanation":"ELDT применяется к получению CDL класса A/B впервые, повышению с B до A и получению дополнений S, P или H впервые. Простое продление имеющегося CDL без новых дополнений не требует ELDT. Источник: правило FMCSA ELDT (49 CFR Part 380) в применении в Арканзасе."},"88":{"q":"Экзамен по навыкам CDL в Арканзасе состоит из каких трёх частей в порядке, в котором они обычно выполняются?","options":["Письменный экзамен на знание, проверка зрения и вождение по дороге","Проверка пневматических тормозов, обращение с опасными грузами и вождение по дороге","Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Базовое управление транспортным средством, экзамен на знание и предрейсовый осмотр"],"explanation":"Экзамен по навыкам CDL в Арканзасе состоит из трёх частей: предрейсового осмотра транспортного средства, навыков базового управления транспортным средством и экзамена по вождению на дороге. Источник: информация Arkansas DFA / полиции штата Арканзас об экзамене по навыкам CDL (49 CFR 383.113)."},"89":{"q":"Во время части экзамена по навыкам CDL в Арканзасе, посвящённой базовому управлению транспортным средством, экзаменатор в первую очередь оценивает способность заявителя:","options":["Точно маневрировать и сдавать назад транспортным средством в ограниченном пространстве","Перечислить по памяти федеральные ограничения рабочего времени (hours-of-service)","Рассчитать полную комбинированную весовую характеристику транспортного средства","Продемонстрировать размещение аварийных дорожных фальшфейеров"],"explanation":"Базовое управление транспортным средством проверяет способность водителя контролировать и позиционировать транспортное средство с помощью таких манёвров, как движение задним ходом по прямой, движение задним ходом со смещением и парковка в ограниченном пространстве. Источник: стандарты экзамена по навыкам Arkansas DFA / FMCSA (49 CFR 383.113)."},"90":{"q":"Федеральные правила медицинской сертификации, принятые Арканзасом, требуют, чтобы каждый держатель CLP и CDL самостоятельно отнёс себя к скольким возможным категориям эксплуатации?","options":["Две категории","Четыре категории","Три категории","Шесть категорий"],"explanation":"Каждый держатель CLP/CDL должен самостоятельно отнести себя к одной из четырёх категорий на основе междуштатной или внутриштатной эксплуатации и статуса с исключениями или без исключений. Источник: страница Arkansas DFA Medical Certification (49 CFR 383.71)."},"91":{"q":"Какая категория самостоятельной классификации требует, чтобы водитель соответствовал федеральным стандартам физической пригодности DOT и имел при себе медицинскую справку медицинского эксперта?","options":["Excepted Interstate (междуштатная с исключениями)","Excepted Intrastate (внутриштатная с исключениями)","Non-Excepted Interstate (междуштатная без исключений)","Hobby / Personal Use Only (только хобби / личное использование)"],"explanation":"Водитель, который самостоятельно относит себя к категории Non-Excepted Interstate, должен соответствовать федеральным стандартам физической пригодности DOT (49 CFR 391) и иметь действительную медицинскую справку медицинского эксперта. Источник: страница Arkansas DFA Medical Certification (49 CFR 383.71)."},"92":{"q":"Водитель, который работает только в пределах Арканзаса и НЕ подпадает под федеральные требования физической пригодности, наиболее точно отнесёт себя к категории:","options":["Non-Excepted Interstate (междуштатная без исключений)","Excepted Intrastate (внутриштатная с исключениями)","Excepted Interstate (междуштатная с исключениями)","Non-Excepted Federal (федеральная без исключений)"],"explanation":"Водитель, работающий только в пределах штата, который не обязан соответствовать федеральным стандартам физической пригодности, относит себя к категории Excepted Intrastate. Источник: страница Arkansas DFA Medical Certification (49 CFR 383.71)."},"93":{"q":"Когда заявитель на CDL в Арканзасе относит себя к категории Non-Excepted Interstate, медицинский эксперт DOT, проводящий медосмотр, должен быть:","options":["Сотрудником медицинского подразделения полиции штата Арканзас","Любым лицензированным фармацевтом в округе проживания заявителя","Индивидуально утверждённым руководителем местного офиса доходов","Внесён в Национальный реестр сертифицированных медицинских экспертов FMCSA (FMCSA National Registry of Certified Medical Examiners)"],"explanation":"Водители без исключений должны проходить медосмотр у медицинского эксперта, внесённого в Национальный реестр сертифицированных медицинских экспертов FMCSA, и эта справка подаётся в Управление водительских услуг (Office of Driver Services). Источник: страница Arkansas DFA Medical Certification (49 CFR 391.41 / National Registry)."},"94":{"q":"Что из перечисленного является допустимым способом подачи медицинской справки медицинского эксперта DOT и аффидевита о самостоятельной классификации в Управление водительских услуг Арканзаса (Arkansas Office of Driver Services)?","options":["Размещение её непосредственно на сайте FMCSA National Registry","Передача её придорожному патрульному полиции штата Арканзас при любой остановке","Личное предоставление её в любой офис доходов Арканзаса либо отправка по электронной почте/факсу в Управление водительских услуг","Загрузка её только на частный портал работодателя-автоперевозчика заявителя"],"explanation":"Арканзас принимает медицинскую справку и самостоятельную классификацию лично в любом офисе доходов штата, по почте в Управление водительских услуг или по каналам электронной почты/факса, которые публикует DFA. Источник: страницы Arkansas DFA Medical Certification / Register Medical Certificate."},"95":{"q":"Что происходит с коммерческими привилегиями держателя CDL Арканзаса без исключений, если срок действия его медицинской справки медицинского эксперта DOT истекает и новая не подаётся?","options":["Статус CDL меняется на «Not Certified», и коммерческие привилегии вождения теряются","Ничего не меняется до истечения полного срока действия CDL спустя годы","CDL автоматически понижается до CLP на один год","Водителя штрафуют, но он сохраняет все коммерческие привилегии"],"explanation":"Непредоставление действующей медицинской карты к дате истечения её срока переводит CDL в медицинский статус «Not Certified», что лишает коммерческих привилегий вождения до подачи действительной справки. Источник: страница Arkansas DFA Medical Certification."},"96":{"q":"При продлении CDL в Арканзасе водитель без исключений обычно должен предоставить всё из перечисленного, КРОМЕ:","options":["Нового сертификата подготовки водителей начального уровня (ELDT) для имеющегося класса","Своего текущего водительского удостоверения","Заполненного аффидевита о самостоятельной классификации","Действующей медицинской справки медицинского эксперта"],"explanation":"Продление имеющегося CDL того же класса без новых дополнений не требует ELDT; водителю необходимы его текущее удостоверение, аффидевит о самостоятельной классификации и (если без исключений) действующая медицинская справка. Источник: требования к продлению Arkansas DFA Driver Services / правило FMCSA ELDT."},"97":{"q":"Каков минимальный возраст для получения CDL Арканзаса, ограниченного внутриштатным (в пределах штата) коммерческим вождением?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Арканзас разрешает CDL для внутриштатной эксплуатации с 18 лет; для междуштатной эксплуатации водителю должен быть 21 год. Источник: требования к CDL Arkansas DFA (возрастные стандарты 49 CFR 383 / 391)."},"98":{"q":"В отношении сборов за подачу заявления на CDL в Арканзасе какое утверждение отражает правильное процессное ожидание?","options":["Подача заявления и тестирование на CDL в Арканзасе всегда бесплатны","Сбор постоянно зафиксирован федеральным законом и никогда не меняется","Только дополнение на опасные материалы влечёт за собой какой-либо сбор; все остальные услуги CDL бесплатны","Сборы устанавливаются штатом и могут меняться, поэтому заявителям следует уточнить текущую сумму в DFA перед подачей заявления"],"explanation":"Сборы за CDL в Арканзасе (за удостоверение, дополнения и тестирование) устанавливаются штатом и могут меняться, поэтому заявителям следует уточнить текущие суммы в DFA, а не полагаться на фиксированную цифру. Источник: график сборов Arkansas DFA Driver Services (может меняться)."}},"tr":{"0":{"q":"Arkansas karayollarında, özel bir izin gerekmeden önce bir aracın (yüklü veya yüksüz) izin verilen azami toplam dış genişliği nedir?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Arkansas Code Ann. 27-35-206, bir aracın azami yasal genişliğini yüklü veya yüksüz olarak 102 inches (8 feet 6 inches) olarak belirler; bundan daha geniş olan her şey için ARDOT/Arkansas Highway Police'ten bir gabari aşımı (oversize) izni gerekir."},"1":{"q":"Yürürlükteki Arkansas yasalarına göre, özel bir izin olmadan eyalet karayollarında izin verilen bir aracın (yükü dahil) azami yüksekliği nedir?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"Arkansas Code Ann. 27-35-207, 2021 tarihli Act 871 ile değiştirildiği şekliyle (28 Temmuz 2021'de yürürlüğe girdi), yasal yükseklik sınırını 13'6\" değerinden 14 feet değerine çıkardı. 14 feet değerini aşan bir araç için özel bir (yükseklik aşımı) izni gerekir."},"2":{"q":"Arkansas karayollarında, ağırlık aşımı izni olmadan izin verilen bir aracın veya kombinasyonun azami brüt ağırlığı nedir?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"Federal standart ve Arkansas Code Ann. 27-35-203 ile tutarlı olarak, azami yasal brüt ağırlık 80,000 pounds'tur. Bunu aşmak için ARDOT/Arkansas Highway Police Permit Section'dan bir ağırlık aşımı izni gerekir."},"3":{"q":"Arkansas'ta, izin olmadan tek bir aks üzerinde taşınabilecek azami yük nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Arkansas Code Ann. 27-35-203, tek bir aksı 20,000 pounds ile sınırlar. Bu, Arkansas karayollarında uygulanan federal tek aks sınırıyla aynıdır."},"4":{"q":"Arkansas'ta, izin olmadan bir tandem aks grubunda izin verilen azami yasal yük nedir?","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"explanation":"Arkansas Code Ann. 27-35-203, bir tandem aksı 34,000 pounds ile sınırlar. (İzinle bir tandem 46,000 pounds değerine ulaşabilir, ancak 34,000 izinsiz azami değerdir.)"},"5":{"q":"Arkansas Code 27-35-203 uyarınca, iki ardışık aks, merkezleri arasındaki mesafe şu olduğunda bir 'tandem aks' olarak kabul edilir:","options":["40 inches'tan fazla ancak 96 inches'tan fazla olmadığında","96 inches'tan fazla ancak 120 inches'tan fazla olmadığında","Tam olarak 48 inches olduğunda","40 inches'tan az olduğunda"],"explanation":"Arkansas Code Ann. 27-35-203, tandem aksı, merkezleri 40 inches'tan fazla ve 96 inches'tan fazla olmayacak şekilde aralıklı iki veya daha fazla ardışık aks olarak tanımlar ve birleşik sınırı 34,000 pounds'tur."},"6":{"q":"Arkansas karayollarında, izin olmadan çalıştırılan tek (düz) bir kamyonun azami uzunluğu nedir?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Arkansas Code Ann. 27-35-208, tek (düz) bir aracı yüklü veya yüksüz olarak toplam 40 feet uzunlukla sınırlar."},"7":{"q":"Arkansas karayollarında, bir çekici kamyonla kombinasyon halinde çalışan bir yarı römorkun eyaletin altına indiremeyeceği azami uzunluk nedir?","options":["48 feet","50 feet","53 feet 6 inches","57 feet"],"explanation":"Arkansas Code Ann. 27-35-208, eyaletin bir çekici kamyonla kombinasyon halinde çalıştırılan bir birime 53 feet 6 inches'tan az bir yarı römork/römork uzunluk sınırı uygulamayacağını öngörür."},"8":{"q":"Arkansas karayollarında bir çekici-yarı römork-römork (ikiz/çift) kombinasyonunda, her bir takılı birimin azami uzunluğu nedir?","options":["24 feet","28 feet","33 feet","40 feet"],"explanation":"Arkansas Code Ann. 27-35-208, bir çekici-yarı römork-römork (çift) kombinasyonundaki her yarı römork veya römorku, bağlantı cihazları hariç, toplam 28 feet uzunlukla sınırlar."},"9":{"q":"Arkansas, aralarındaki mesafeye göre bir aks grubu üzerindeki azami izin verilen ağırlığı belirlemek için hangi formülü kullanır?","options":["Federal Köprü Formülü (Formula B)","Arkansas Dara Ağırlığı Formülü","Brüt Kombinasyon Oranı Kuralı","Tandem Aralık Çarpanı"],"explanation":"Arkansas, bir aks grubunun aks sayısı (N) ve aralarındaki mesafeye (L) göre taşıyabileceği azami ağırlığı belirlemek için Federal Köprü Formülü'nü (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], uygular."},"10":{"q":"Arkansas'ta uygulandığı şekliyle Federal Köprü Formülü'nde, W = 500[LN/(N-1) + 12N + 36], 'N' neyi temsil eder?","options":["Dikkate alınan gruptaki aks sayısı","Aracın net (dara) ağırlığı","Tahrik aksındaki lastik sayısı","Karayolunun nominal hız sınırı"],"explanation":"Arkansas tarafından kullanılan Federal Köprü Formülü'nde, N dikkate alınan gruptaki aks sayısı, L grubun dış aksları arasındaki feet cinsinden aralık ve W azami izin verilen ağırlıktır."},"11":{"q":"Bir kamyoncunun yükü 9 feet 2 inches genişliğindedir. Arkansas karayollarında bu yük:","options":["10 feet'in altında olduğu için yasaldır","102 inches'ı aştığı için bir gabari aşımı izni gerektirir","Yalnızca eyaletler arası (Interstate) sistemde yasaldır","İzin değil, yalnızca bir bayrak gerektirir"],"explanation":"Code 27-35-206 uyarınca Arkansas yasal genişliği 102 inches'tır (8'6\"). 9'2\"lik bir yük (110 inches) yasal genişliği aşar ve ARDOT/Arkansas Highway Police'ten bir gabari aşımı izni gerektirir."},"12":{"q":"Arkansas State Highway System için gabari ve ağırlık aşımı hareket izinlerini hangi kurum verir?","options":["Arkansas Department of Finance and Administration","Arkansas Highway Police Permit Section aracılığıyla Arkansas Department of Transportation","Seyahat edilen her ilçedeki ilçe şerifi","Federal Motor Carrier Safety Administration"],"explanation":"ARDOT 2023 Permit Rules uyarınca, State Highway System için gabari/ağırlık aşımı izinleri, Arkansas Highway Police Permit Section aracılığıyla Arkansas Department of Transportation tarafından verilir."},"13":{"q":"Bir motorlu taşıyıcının Arkansas'ta ne zaman ağırlık aşımı iznine ihtiyacı vardır?","options":["Yalnızca yük bölünerek azaltılabildiğinde","Araç yasal brüt, tek aks veya tandem aks ağırlık sınırlarını aştığında","Yolculuk bir ilçe sınırını her geçtiğinde","Yalnızca gece seyahat ederken"],"explanation":"ARDOT Permit Rules ve Code 27-35-203/210 uyarınca, bir araç yasal sınırları (80,000 lbs brüt, 20,000 lbs tek aks veya 34,000 lbs tandem ya da bir köprü formülü sınırı) aştığında ağırlık aşımı izni gereklidir. Bu tür izinler genellikle yalnızca bölünemeyen yükler için verilir."},"14":{"q":"Arkansas'ta ağırlık aşımı izinleri genellikle yalnızca şu özellikteki yükler için verilir:","options":["Daha küçük yasal yüklere bölünebilen","Bölünemeyen (yasal ağırlığa makul şekilde indirilemeyen)","45 mph'den daha düşük hızda taşınan","Bir devlet kurumuna ait olan"],"explanation":"ARDOT Permit Rules uyarınca, ağırlık aşımı izni bölünemeyen yükler için, yani yasal ağırlık sınırlarını karşılayacak şekilde makul olarak parçalanamayan yükler için verilir. Bölünebilen yükler, izin almak yerine yasal ağırlığa indirilmelidir."},"15":{"q":"Arkansas, doğal halindeki agronomik veya hortikültürel ürünleri taşıyan en az beş akslı bir çekici/yarı römork kombinasyonu için hangi brüt ağırlığa kadar yıllık izin verir?","options":["84,000 pounds","90,000 pounds","100,000 pounds","112,000 pounds"],"explanation":"Arkansas Code Ann. 27-35-210, doğal halindeki agronomik veya hortikültürel ürünleri taşıyan, en az beş akslı bir çekici/yarı römork kombinasyonu için toplam 100,000 pounds brüt ağırlığa kadar yıllık izin verir."},"16":{"q":"Arkansas'ta izinli bir harekette, bir tandem aks grubu en fazla şu kadar yüklenebilir:","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"explanation":"ARDOT Permit Rules uyarınca, izinli bir tandem aks grubu, Code 27-35-203'teki 34,000 pound'luk izinsiz yasal sınırın aksine, 46,000 pounds'a kadar (hiçbir tek aks 23,000 pounds'u aşmayacak şekilde) taşıyabilir."},"17":{"q":"Arkansas'ta beş akslı bir çekici-yarı römork 80,000 lbs brüt, çeker (steer) aksta 20,000 lbs, tahrik tandeminde 34,000 lbs ve römork tandeminde 26,000 lbs olacak şekilde yüklenmiştir. Hangi durum yasal sınırın üzerindedir?","options":["Brüt ağırlık","Çeker (tek) aks ağırlığı","Tahrik tandemi ağırlığı","Bunların hiçbiri yasal sınırını aşmıyor"],"explanation":"Code 27-35-203 uyarınca, yasal sınırlar 80,000 lbs brüt, 20,000 lbs tek aks ve 34,000 lbs tandemdir. Buradaki her değer sınırında veya altındadır, dolayısıyla hiçbir aks veya brüt ağırlık yasal sınırın üzerinde değildir (köprü formülü aralığı yine de geçerlidir)."},"18":{"q":"Arkansas karayollarında bir çekici ve tek yarı römork için toplam kombinasyon uzunluğuyla ilgili hangi ifade doğrudur?","options":["Arkansas, toplam çekici-yarı römork kombinasyonunu tam olarak 65 feet ile sınırlar","Arkansas, çekici-ve-tek-yarı-römork kombinasyonuna sabit bir toplam uzunluk sınırı koymaz; yarı römorkun kendisi 53'6\"'a kadar olabilir","Arkansas, tüm yollarda toplam kombinasyonu 60 feet ile sınırlar","Arkansas, 48 feet'ten uzun hiçbir yarı römorka izin vermez"],"explanation":"Arkansas Code Ann. 27-35-208, yarı römork uzunluğunu sınırlar (53'6\"'tan daha az kısıtlanamaz) ancak federal STAA kurallarıyla tutarlı olarak bir çekici artı tek yarı römork kombinasyonuna sabit bir toplam uzunluk sınırı koymaz."},"19":{"q":"Arkansas'ta bir platform (flatbed), yükünün tepesine kadar 14 feet 4 inches yüksekliğindedir. İzin olmadan bu araç:","options":["Yasaldır, çünkü sınır 15 feet'tir","Yükseklik aşımıdır ve özel bir (yükseklik aşımı) izni gerektirir","Yalnızca eyaletler arası (Interstate) sistem dışında yasaldır","Yasaldır, çünkü Arkansas'ta yükseklik düzenlenmemiştir"],"explanation":"Code 27-35-207 (2021 tarihli Act 871 ile değiştirildiği şekliyle) uyarınca yürürlükteki Arkansas yasal yüksekliği 14 feet'tir. 14'4\" ölçen bir yük 14 feet'i aşar ve ARDOT/Arkansas Highway Police'ten bir yükseklik aşımı izni gerektirir."},"20":{"q":"Arkansas'ta, çekilen birimin GVWR'sinin 10,000 pounds'tan fazla olduğu ve gross combination weight rating (GCWR) değeri 26,001 pounds veya daha fazla olan bir araç kombinasyonunu çalıştırmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Arkansas, Class A CDL'yi, GVWR'si 10,000 pounds'tan fazla olan çekilen bir birim dahil, GCWR değeri 26,001 pounds veya daha fazla olan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: Arkansas CDL Manual, Section 1 (Classifications); Arkansas DFA Office of Driver Services CDL sayfası."},"21":{"q":"Arkansas kurallarına göre, GVWR değeri 26,001 pounds veya daha fazla olan tek bir araç (veya 10,000 pounds GVWR değerini aşmayan bir birim çeken böyle bir araç) hangi CDL sınıfını gerektirir?","options":["Class B","Class A","Class C","Class M"],"explanation":"Arkansas, Class B CDL'yi, GVWR değeri 26,001 pounds veya daha fazla olan herhangi bir tek araç ya da 10,000 pounds GVWR değerini aşmayan bir birim çeken böyle herhangi bir araç olarak tanımlar. Kaynak: Arkansas CDL Manual, Section 1 (Classifications); Arkansas DFA CDL sayfası."},"22":{"q":"Arkansas'ta, Class A veya Class B tanımını karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakartlı tehlikeli maddeler taşımak için kullanılan bir araç hangi CDL sınıfına girer?","options":["Class A","Class C","Class B","Class P"],"explanation":"Arkansas, Class C CDL'yi, Class A veya B'yi karşılamayan ancak sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da plakartlı tehlikeli madde veya 42 CFR Part 73 kapsamında bir seçili ajan/toksin taşıyan bir araç olarak tanımlar. Kaynak: Arkansas CDL Manual, Section 1; Arkansas DFA CDL sayfası."},"23":{"q":"Yalnızca eyalet içinde (intrastate ticaret) ticari motorlu araç kullanmakla sınırlı bir Arkansas CDL'si almak için asgari yaş nedir?","options":["16 years old","18 years old","19 years old","21 years old"],"explanation":"Arkansas, intrastate ticarette (yalnızca Arkansas içinde) ticari motorlu araç kullanmak için bir sürücünün en az 18 yaşında olmasını gerektirir. Kaynak: Arkansas DFA Office of Driver Services CDL gereklilikleri."},"24":{"q":"Eyalet sınırlarının ötesinde (interstate ticaret) araç kullanmak için geçerli bir Arkansas CDL'si almak için gereken asgari yaş nedir?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"Arkansas (federal standartları izleyerek), interstate ticarette ticari motorlu araç kullanmak için bir sürücünün en az 21 yaşında olmasını gerektirir. 18-20 yaşındaki bir sürücü intrastate operasyonla sınırlıdır. Kaynak: Arkansas DFA Office of Driver Services CDL gereklilikleri."},"25":{"q":"Arkansas'ta, bireysel tarifeli kapasitesi 119 gallons'tan fazla ve toplam tarifeli kapasitesi 1,000 gallons veya daha fazla olan bir tankta sıvı veya gaz taşımak için tasarlanmış bir tank aracını çalıştırmak için hangi onay (endorsement) gereklidir?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"Arkansas, bireysel tarifeli kapasitesi 119 gallons'tan fazla ve toplam tarifeli kapasitesi 1,000 gallons veya daha fazla olan bir tank veya tanklarda sıvı ya da gaz halindeki maddeleri taşımak için tasarlanmış araçlar için N (Tank Vehicle) onayını gerektirir. Kaynak: Arkansas CDL Manual, Section 1 (Endorsements) ve Section 8."},"26":{"q":"Arkansas'ta, 49 CFR Part 172 kapsamında tehlikeli olarak belirlenen ve plakartlanması gereken malzemeyi taşıyan bir aracı kullanmak için hangi onay gereklidir?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"explanation":"Arkansas, araç sınıfından bağımsız olarak, 49 U.S.C. 5103 kapsamında tehlikeli olarak belirlenen ve 49 CFR Part 172 kapsamında plakartlanması gereken malzemeyi taşıyan herhangi bir sürücü için H (Hazardous Materials) onayını gerektirir. Kaynak: Arkansas CDL Manual, Section 1 (Endorsements)."},"27":{"q":"Yazılı bilgi testini geçmenin ötesinde, Arkansas bir Hazardous Materials (H) onayı vermeden önce hangi ek adımı gerektirir?","options":["Bir göz doktoru tarafından yapılan görme muayenesi","Parmak izi ve geçmiş kontrolü içeren bir TSA güvenlik tehdidi değerlendirmesi","Bir tank aracında ikinci bir yol becerisi testi","Noter onaylı bir işveren sponsorluk mektubu"],"explanation":"Bir HazMat onayını almak, yenilemek veya devretmek için Arkansas, parmak izi alımını ve bir federal geçmiş kontrolünü (cezai, göçmenlik ve FBI kayıtları) içeren bir TSA güvenlik tehdidi değerlendirmesi gerektirir. Sürücüler en az 90 days ayırmalıdır. Kaynak: Arkansas DFA Hazardous Materials Endorsement sayfası; Arkansas CDL Manual, Section 1."},"28":{"q":"Arkansas, çift veya üçlü römork çekmek isteyen bir sürücü için hangi onayı gerektirir?","options":["T endorsement","N endorsement","S endorsement","X endorsement"],"explanation":"Arkansas, çift veya üçlü römork çekmek için T (Doubles/Triples) onayını gerektirir; başvuran, birden fazla römork çekmeyle ilgili sorunlar hakkında bir bilgi sınavını geçmelidir. Kaynak: Arkansas CDL Manual, Section 1 (Endorsements) ve Section 7."},"29":{"q":"Arkansas'ta, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı çalıştırmak isteyen bir sürücü hangi onayı almalıdır?","options":["S endorsement","T endorsement","P endorsement","N endorsement"],"explanation":"Arkansas, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracın sürücüleri için P (Passenger) onayını gerektirir. Başvuran, bir bilgi testini ve bir yolcu aracında bir beceri testini geçmelidir. Kaynak: Arkansas CDL Manual, Section 1 (Endorsements) ve Section 4."},"30":{"q":"Bir Arkansas sürücüsünün, Passenger (P) onayına ek olarak, okul otobüsü kullanmak için hangi onaya sahip olması gerekir?","options":["H endorsement","T endorsement","S endorsement","X endorsement"],"explanation":"Arkansas, okul otobüsü kullanmak için S (School Bus) onayını gerektirir; sürücü, bir okul otobüsü bilgi testini ve bir okul otobüsünde bir beceri testini geçmelidir ve onay herhangi bir sınıfta (A, B veya C) geçerlidir. Kaynak: Arkansas CDL Manual, Section 1 (Endorsements) ve Section 10."},"31":{"q":"Arkansas'ta, plakartlı tehlikeli maddeleri de taşıması gereken bir tank aracı sürücüsü hangi tek birleşik onayı almalıdır?","options":["T endorsement","X endorsement","P endorsement","S endorsement"],"explanation":"Arkansas, X onayını HazMat ve Tank Vehicle'ın bir kombinasyonu olarak verir; sürücü, hem tank araçları hem de tehlikeli maddeler için bilgi sınavlarını geçmelidir. Kaynak: Arkansas CDL Manual, Section 1 (Endorsements)."},"32":{"q":"Arkansas CDL Manual'a göre, bir Commercial Learner's Permit (CLP) üzerine eklenebilecek TEK onay kümesi hangisidir?","options":["H, N, and T","P, H, and X","P, S, and N","T, S, and H"],"explanation":"Arkansas CDL Manual, bir CLP'ye eklenebilecek tek onayların Passenger (P), School Bus (S) ve Tank Vehicle (N) olduğunu belirtir. Bir CLP üzerine bir HazMat (H) onayı verilemez. Kaynak: Arkansas CDL Manual, Section 1 (Endorsements/CLP)."},"33":{"q":"Arkansas'ta, bir CLP, bir Tank Vehicle (N) onayıyla verildiğinde, hangi kısıtlamayı taşımalıdır?","options":["Interstate operasyon yok (K)","Havalı fren donanımlı CMV yok (L)","Manuel şanzıman yok (E)","Bir CMV tank aracında kargo yok (X)"],"explanation":"Arkansas, bir N onayıyla verilen bir CLP'nin ayrıca X kısıtlamasını (Bir CMV tank aracında kargo yok) taşımasını gerektirir; sahibi yalnızca herhangi bir kalıntıdan arındırılmış boş bir tankı çalıştırabilir. Kaynak: Arkansas CDL Manual, Section 1 (Restrictions)."},"34":{"q":"Arkansas ve federal CLP kuralları uyarınca, bir CLP sahibinin CDL beceri testine girmeye hak kazanmadan önce ilk verilişten sonra ne kadar beklemesi gerekir?","options":["7 days","10 days","14 days","30 days"],"explanation":"Arkansas, bir CLP sahibinin CLP'nin ilk verilişinden sonraki ilk 14 days boyunca CDL beceri testine girmeye hak kazanmadığına dair federal kuralı uygular. Kaynak: Arkansas DFA Commercial Learner's Permit (CLP) sayfası; 49 CFR 383.25."},"35":{"q":"Bir Arkansas Commercial Learner's Permit (CLP), sahibinin genel ve onay bilgi testlerini yeniden vermesi gerekmeden önce ne kadar süreyle geçerlidir?","options":["60 days'e kadar","180 days'e kadar","1 year'a kadar","2 years'a kadar"],"explanation":"Bir Arkansas CLP'si 1 year'a kadar geçerlidir; süresi dolduktan sonra sahibi genel ve onay bilgi testlerini yeniden vermelidir. Kaynak: Arkansas DFA Commercial Learner's Permit (CLP) sayfası."},"36":{"q":"Arkansas'ta Commercial Driver License (CDL) hangi eyalet kurumu tarafından verilir?","options":["Arkansas State Police","Arkansas Department of Finance and Administration, Office of Driver Services","Arkansas Department of Transportation (ARDOT)","Federal Motor Carrier Safety Administration"],"explanation":"Arkansas'ta CDL, Department of Finance and Administration (DFA), Office of Driver Services tarafından verilir. ARDOT yolları/izinleri yönetir ve FMCSA federal düzenleyicidir, ancak lisanslama kurumu DFA Driver Services'tir. Kaynak: Arkansas DFA Driver Services CDL sayfası."},"37":{"q":"Bir Arkansas CDL veya CLP başvurusunda bulunurken, Office of Driver Services bir başvuranın hangi belge kombinasyonunu sunmasını gerektirir?","options":["Yalnızca bir Social Security kartı ve bir fatura","Yalnızca bir A.B.D. pasaportu","Kimlik/doğum tarihi kanıtı, Social Security numarası, Arkansas ikamet kanıtı ve yasal mevcudiyet kanıtı","Bir lise diploması ve istihdam kanıtı"],"explanation":"Arkansas DFA, başvuranların kimlik ve doğum tarihi kanıtı, Social Security numarası kanıtı, Arkansas ikamet kanıtı (güncel adres) ve yasal mevcudiyet/yasal A.B.D. mevcudiyeti kanıtı sunmasını gerektirir. Kaynak: Arkansas DFA Driver Services belge gereklilikleri ('Do You Have What You Need?')."},"38":{"q":"Arkansas'ta uygulanan federal Entry-Level Driver Training (ELDT) kuralları uyarınca (7 Şubat 2022'de yürürlüğe girdi), ilk kez başvuran biri test öncesinde gerekli eğitimi nerede tamamlamalıdır?","options":["Arkansas'taki herhangi bir community college","Bir Arkansas DFA gelir ofisi","FMCSA Training Provider Registry (TPR) üzerinde listelenen bir sağlayıcı","Yalnızca bir işverenin kurum içi oryantasyonu"],"explanation":"ELDT, ilk kez başvuran Class A/B başvuranların ve P, S veya H onayı başvuranlarının, eyalet tarafından uygulanan testten önce FMCSA Training Provider Registry üzerinde listelenen bir sağlayıcıdan eğitim almasını gerektirir; H için eğitim, bilgi testinden önce yalnızca teoriktir, Class A/B, P ve S ise beceri testinden önce teori artı direksiyon başında eğitim gerektirir. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380), 7 Şubat 2022'de yürürlüğe girdi; FMCSA Training Provider Registry."},"39":{"q":"Bir Arkansas CDL'si için başvururken, bir sürücü dört tıbbi sertifikasyon kategorisinden birine kendi beyanını yapmalıdır. Aşağıdakilerden hangisi bu dört kategoriden biridir?","options":["Recreational interstate","Hazmat-exempt interstate","Provisional intrastate","Non-excepted interstate"],"explanation":"Arkansas sürücüleri dört kategoriden birine kendi beyanını yapmalıdır: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate veya Excepted Intrastate. Non-excepted interstate sürücüleri bir federal tıbbi muayene sertifikasını bulundurmak zorundadır. Kaynak: Arkansas CDL Manual, Section 1.2 (Self-Certification); 49 CFR 383.71."},"40":{"q":"Arkansas'ta, bir kişi blood alcohol concentration (BAC) değeri hangi seviyede veya üzerinde olduğunda ticari motorlu araç (CMV) kullanırken etkisi altında (under the influence) kabul edilir ve diskalifiyeye tabi olur?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"Arkansas federal CMV standardını benimser: bir CMV'yi 0.04% veya daha yüksek bir BAC ile kullanmak etkisi altında araç kullanmaktır ve diskalifiye eden büyük bir suçtur, bu da ticari olmayan sürücüler için olan 0.08% sınırının yarısıdır. Kaynak: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"41":{"q":"Arkansas yasalarına göre, plakartlı tehlikeli madde taşımayan bir CDL sahibinin İLK büyük suçu (örneğin bir CMV'de DUI) için asgari diskalifiye süresi nedir?","options":["1 year","60 days","3 years","6 months"],"explanation":"İlk büyük suç (DUI, 0.04+ BAC, test reddi, olay yerini terk etme vb.) Arkansas'ta 1 yıllık (1 year) bir CDL diskalifiyesiyle sonuçlanır. Kaynak: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"42":{"q":"Arkansas'ta, bir sürücü plakartlı tehlikeli madde taşıyan bir CMV'yi kullanırken ilk büyük suçu işlerse, diskalifiye süresi şuna yükselir:","options":["3 years","1 year","5 years","Ömür boyu"],"explanation":"Arkansas, suç plakartlı tehlikeli madde taşınırken işlendiğinde ilk büyük suç diskalifiyesini 1 year değerinden 3 years değerine yükseltir. Kaynak: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"43":{"q":"Arkansas'ta bir CDL sahibinin ayrı bir olayda işlediği İKİNCİ büyük suç için diskalifiye süresi nedir?","options":["Ömür boyu","10 years","3 years","5 years"],"explanation":"İkinci bir büyük suç, Arkansas'ta CDL'nin ömür boyu (kalıcı) diskalifiyesiyle sonuçlanır. Kaynak: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"44":{"q":"Arkansas'ta bir CMV kullanırken gerekli bir alkol/BAC testine girmeyi reddetmek, ilk durum için hangi diskalifiyeyle sonuçlanır?","options":["1 year","90 days","30 days","Diskalifiye yok, yalnızca para cezası"],"explanation":"Test reddi büyük bir suç olarak ele alınır ve bir DUI ile aynı 1 yıllık (1 year) diskalifiyeyi taşır (plakartlı hazmat taşınıyorsa 3 years). Reddetme, CMV operatörleri için Arkansas'ın zımni rıza (implied-consent) kuralı kapsamındadır. Kaynak: Ark. Code 27-23-112; Arkansas DFA CDL/CMV Offenses; 49 CFR 383.51."},"45":{"q":"Arkansas'ın ticari sürücüler için zımni rıza hükmü uyarınca, eyalette bir CMV kullanan bir kişi şuna rıza göstermiş sayılır:","options":["Alkol veya kontrollü maddeler için kan, nefes veya idrar testine","Sebep olmaksızın rastgele araç aramalarına","Herhangi bir diskalifiye konusunda duruşma hakkından feragate","Yıllık zorunlu uyuşturucu rehabilitasyonuna"],"explanation":"Arkansas'ın zımni rıza kuralı, bir CMV kullanan herkesin, alkollü araç kullanma ve 0.04% kurallarını uygulamak için gerekli olan alkol/kontrollü madde testine rıza göstermiş sayıldığını öngörür. Kaynak: Ark. Code 27-23-112/27-23-113; Arkansas DFA CDL/CMV Offenses."},"46":{"q":"Arkansas'ta bir CMV kullanırken HERHANGİ bir ölçülen veya tespit edilen alkol varlığına (0.04%'in altında) sahip olduğu tespit edilen bir CDL sahibi şu işleme tabi tutulmalıdır:","options":["24 saat boyunca hizmet dışı (out of service) bırakılma","1 year diskalifiye edilme","$2,500 para cezası ve 60 days diskalifiye","Derhal DUI'den tutuklanma"],"explanation":"Arkansas Code 27-23-113, herhangi bir ölçülen veya tespit edilen alkolle bir CMV kullanmayı yasaklar; ihlal eden bir sürücü 24 saat boyunca hizmet dışı bırakılır. Tam bir DUI diskalifiyesi yalnızca 0.04% veya üzerinde geçerlidir. Kaynak: Ark. Code 27-23-113."},"47":{"q":"Arkansas'ta, 3 yıllık (3-year) bir süre içinde ayrı bir olayda işlenen İKİNCİ ciddi trafik ihlali ne kadar süreyle diskalifiyeyle sonuçlanır?","options":["60 days","30 days","120 days","1 year"],"explanation":"3 yıl içinde ayrı olaylarda iki ciddi trafik ihlali, Arkansas'ta 60 günlük (60 days) bir diskalifiyeyle sonuçlanır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"48":{"q":"3 yıllık (3-year) bir süre içinde ayrı olaylarda işlenen ÜÇÜNCÜ (veya sonraki) ciddi trafik ihlali hangi Arkansas diskalifiyesiyle sonuçlanır?","options":["120 days","60 days","1 year","90 days"],"explanation":"3 yıl içinde ayrı olaylarda üç veya daha fazla ciddi trafik ihlali, Arkansas'ta 120 günlük (120 days) bir diskalifiyeyle sonuçlanır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"49":{"q":"Aşağıdakilerden hangisi bir Arkansas CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır (büyük bir suç değil)?","options":["Aşırı hız, limitin 15 mph veya daha fazla üzerinde","Bir CMV'yi 0.04% BAC ile kullanmak","Bir CMV'de kaza yerini terk etmek","Bir suç işlemek için bir CMV kullanmak"],"explanation":"Aşırı hız (limitin 15+ mph üzerinde), dikkatsiz sürüş, uygunsuz/düzensiz şerit değiştirme, çok yakından takip etme ve mesajlaşma/elde telefon kullanımı ciddi trafik ihlalleridir. Listelenen diğer seçenekler büyük suçlardır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"50":{"q":"Arkansas'ta HERHANGİ bir diskalifiye süresi tetiklenmeden önce 3 yıllık (3-year) bir süre içinde kaç ciddi trafik ihlali gereklidir?","options":["2","1","3","4"],"explanation":"Tek bir ciddi ihlal diskalifiye etmez; ilk diskalifiye (60 days) 3 yıl içindeki ikinci ciddi ihlalle tetiklenir ve bir üçüncüsü 120 days'i tetikler. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"51":{"q":"Bir Arkansas CDL sahibinin bir CMV kullanırken İLK demiryolu-karayolu hemzemin geçit ihlali mahkumiyeti için asgari diskalifiye nedir?","options":["60 days","30 days","120 days","1 year"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, Arkansas'ta asgari 60 günlük (60 days) bir diskalifiye taşır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"52":{"q":"3 yıllık (3-year) bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali hangi asgari Arkansas diskalifiyesiyle sonuçlanır?","options":["120 days","60 days","1 year","90 days"],"explanation":"3 yıl içinde ikinci bir hemzemin geçit ihlali, Arkansas'ta asgari 120 günlük (120 days) bir diskalifiye taşır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"53":{"q":"3 yıllık (3-year) bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali hangi asgari Arkansas diskalifiyesiyle sonuçlanır?","options":["1 year","120 days","180 days","60 days"],"explanation":"3 yıl içinde üçüncü bir hemzemin geçit ihlali, Arkansas'ta asgari 1 yıllık (1 year) bir diskalifiye taşır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"54":{"q":"Hangi eylem, bir Arkansas CDL sahibini diskalifiye edebilecek bir demiryolu-karayolu hemzemin geçit ihlalidir?","options":["Geçişten durmadan tamamen geçecek yeterli alana sahip olmamak","Raylara yakın limitin 5 mph üzerinde sürmek","Geçişten önce korna çalmak","En yakın raydan 15 feet'ten fazla uzakta durmak"],"explanation":"Hemzemin geçit ihlalleri arasında yavaşlamayıp trenleri kontrol etmemek, gerektiğinde durmamak, geçişi tamamen geçecek alana sahip olmamak, geçit trafik kontrol cihazlarına uymamak ve yetersiz alt takım açıklığı yer alır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"55":{"q":"Bir Arkansas CDL sahibinin bir sürücü veya araç hizmet dışı (out-of-service, OOS) emrini ihlal etmesine ilişkin İLK mahkumiyeti için asgari diskalifiye süresi nedir?","options":["180 days","60 days","1 year","90 days"],"explanation":"Bir hizmet dışı emrini ihlal etmeye ilişkin ilk mahkumiyet, Arkansas'ta asgari 180 günlük (180 days) bir diskalifiye (1 year'a kadar) taşır. Kaynak: Ark. Code 27-23-112/27-23-114; Arkansas CDL manual; 49 CFR 383.51."},"56":{"q":"Bir hizmet dışı emrini ihlal etmeye ilişkin 10 yıllık (10 years) bir süre içinde İKİNCİ bir mahkumiyet hangi asgari Arkansas diskalifiyesiyle sonuçlanır?","options":["2 years","180 days","1 year","5 years"],"explanation":"10 yıl içinde ikinci bir OOS emri ihlali, Arkansas'ta asgari 2 yıllık (2 years) bir diskalifiye (5 years'a kadar) taşır. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"57":{"q":"Diskalifiyenin yanı sıra, Arkansas'ta bir hizmet dışı emrini ihlal etmekten mahkum edilen bir sürücü, ilk mahkumiyet için en az ne kadar tutarında bir hukuki para cezasına tabidir?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"Arkansas, diskalifiyenin yanı sıra, ilk hizmet dışı emri ihlali için bir sürücüye en az $2,500 (ve bir ikincisi için en az $5,000) hukuki para cezası uygular. Kaynak: Ark. Code 27-23-114."},"58":{"q":"Arkansas ve federal kurallar uyarınca, bir CDL sürücüsünün bir CMV kullanırken elde mobil telefon kullanması veya mesajlaşması diskalifiye açısından nasıl ele alınır?","options":["Tekrarlanan suçlarda diskalifiyeye yol açabilen ciddi bir trafik ihlali olarak","1 yıllık diskalifiye içeren büyük bir suç olarak","Ömür boyu diskalifiye eden bir suç olarak","Hiçbir diskalifiye sonucu taşımaz, yalnızca bir ceza tutanağı"],"explanation":"Bir CMV kullanırken mesajlaşma veya elde telefon kullanma ciddi bir trafik ihlalidir; birden fazla mahkumiyet, sürücüler için $2,750'ye kadar para cezalarıyla birlikte 2 ihlal (60 days) / 3 ihlal (120 days) diskalifiyesine sayılır. Kaynak: Arkansas CDL manual; Ark. Code 27-51-1504; FMCSA 49 CFR 383.51/392.80-82."},"59":{"q":"Kontrollü bir maddenin imalatı, dağıtımı veya temini içeren bir suçun işlenmesinde bir CMV kullanan bir Arkansas CDL sahibi hangi diskalifiyeyle karşılaşır?","options":["Yeniden lisans alma olasılığı olmaksızın ömür boyu","1 year","3 years","10 years"],"explanation":"Kontrollü maddeleri imal etmek, dağıtmak veya temin etmek için bir CMV kullanmak, 10 yıl sonra yeniden lisans almaya izin verebilen diğer ömür boyu yasaklardan farklı olarak, yeniden lisans alma olmaksızın zorunlu ömür boyu diskalifiye taşıyan büyük bir suçtur. Kaynak: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"60":{"q":"Arkansas'ta, bir otobüsün veya tehlikeli madde levhası taşıyan bir aracın bir demir yolu-kara yolu geçidinde durması gerektiğinde, en yakın raydan ne kadar uzakta durmalıdır?","options":["15 feet'ten daha yakın ve 50 feet'ten daha uzak olmayacak şekilde","10 feet'ten daha yakın ve 40 feet'ten daha uzak olmayacak şekilde","25 feet'ten daha yakın ve 75 feet'ten daha uzak olmayacak şekilde","5 feet'ten daha yakın ve 15 feet'ten daha uzak olmayacak şekilde"],"explanation":"Arkansas, otobüslerin ve levha taşıyan HazMat araçlarının, sürücünün rayları en iyi gördüğü yerde, en yakın raydan 15 feet'ten daha yakın ve 50 feet'ten daha uzak olmayacak şekilde durmasını ister. Kaynak: Arkansas Commercial Driver License Manual, Bölüm 2.15, 4.3.5 ve 9."},"61":{"q":"Arkansas'ın Move Over yasası kapsamında, çok şeritli bir kara yolundaki bir sürücü, ışıkları yanıp sönerek durmuş yetkili bir araca yaklaşırken ne yapmalıdır?","options":["Yetkili araç hareket edene kadar tamamen durmalıdır","Aracı güvenli bir şekilde geçene kadar duran araçtan mümkün olan en uzak şeride geçmelidir","Belirtilen hızı korumalı ve geçerken kornaya basmalıdır","Trafik akışını sürdürmek için duran araca en yakın şeride geçmelidir"],"explanation":"Arkansas Code 27-51-310, çok şeritli bir yoldaki sürücülerin, durmuş yetkili araçtan mümkün olan en uzak şeride veya konuma geçmesini ve aracı güvenli bir şekilde geçene kadar orada kalmasını gerektirir. Kaynak: Ark. Code Ann. 27-51-310 (Move Over yasası)."},"62":{"q":"Arkansas'taki kontrollü erişimi olmayan bir kara yolunda, bir buçuk ton veya daha fazla kapasiteye sahip bir kamyon için yasal azami hız nedir?","options":["55 mph","60 mph","50 mph","65 mph"],"explanation":"Arkansas, kontrollü erişimi olmayan kara yollarında bir buçuk ton veya daha fazla kapasiteye sahip kamyonlar için azami 50 mph belirler; aynı yerlerdeki diğer araçlar için bu sınır 60 mph'dir. Kaynak: Ark. Code Ann. 27-51-201."},"63":{"q":"Arkansas'ta, bir okul otobüsü iki şeritli bir yolda durduğunda ve çocukları bindirmek veya indirmek için dönüşümlü kırmızı uyarı ışıklarını gösterdiğinde, hangi sürücüler durmak zorundadır?","options":["Yalnızca otobüsün arkasında aynı yönde ilerleyen sürücüler","Yalnızca otobüsün hemen yanındaki şeritteki sürücüler","Yalnızca otobüse 100 feet mesafedeki sürücüler","Otobüse herhangi bir yönden karşılaşan veya onu geçen sürücüler"],"explanation":"İki şeritli bir yolda, Arkansas Code 27-51-1004, otobüse herhangi bir yönden karşılaşan veya onu geçen her sürücünün kırmızı ışıklar yanıp sönerken tamamen durmasını gerektirir. Kaynak: Ark. Code Ann. 27-51-1004."},"64":{"q":"2021 tarihli hangi Arkansas yasası, çok şeritli bir kara yolundaki en sol şeridin kullanımını yalnızca sollama ile sınırlandırır?","options":["Act 1054 of 2007","Act 1090 of 2021","Act 27 of 2021","Act 310 of 2019"],"explanation":"Act 1090 of 2021, çok şeritli kara yollarında en sol şeridi sollama için ayırır; şeritlerin kapalı olduğu durumlar dışında, sürücüler seyahat için sağ şeritleri kullanmalıdır. Kaynak: Act 1090 of 2021; ARDOT'un Sol Şerit Sürüş Yasası hakkındaki kamuoyu duyurusu."},"65":{"q":"Bir ticari aracın Arkansas kara yolunun banketinde durması gerekirse, sürücü acil durum uyarı cihazlarını (reflektörlü üçgenler) ne kadar süre içinde yerleştirmelidir?","options":["5 dakika içinde","15 dakika içinde","10 dakika içinde","30 dakika içinde"],"explanation":"Bir yolda veya bankette durmak zorunda kalan bir sürücü, acil durum uyarı cihazlarını 10 dakika içinde yerleştirmelidir. Kaynak: Arkansas Commercial Driver License Manual, Bölüm 2.5 (İletişim)."},"66":{"q":"Tek yönlü veya bölünmüş bir Arkansas kara yolunda, durmuş bir ticari araç üç uyarı üçgenini nereye yerleştirmelidir?","options":["Her iki tarafta 10 feet, 100 feet ve 100 feet","Yaklaşan trafiğe doğru 25 feet, 100 feet ve 300 feet","Yaklaşan trafiğe doğru 50 feet, 150 feet ve 250 feet","Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet"],"explanation":"Tek yönlü veya bölünmüş bir kara yolunda üçgenler, araçtan yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet mesafeye yerleştirilir. Kaynak: Arkansas Commercial Driver License Manual, Bölüm 2.5."},"67":{"q":"Hangi araç grubu, Arkansas'ın Move Over yasasının (Ark. Code 27-51-310) kapsadığı 'yetkili araçlar' arasında DEĞİLDİR?","options":["4'lü flaşörleri açık olan herhangi bir özel binek otomobil","Çekme işlemi yapan çekici kamyonlar","Arkansas Department of Transportation araçları","Yanıp sönen ışıklar gösteren altyapı şirketi araçları"],"explanation":"Arkansas'ın Move Over yasası, yanıp sönen/dönen ışıklar gösteren acil müdahale, kolluk kuvveti, ARDOT, ARDOT yüklenicisi, altyapı ve çekme araçlarını kapsar; yalnızca dörtlü flaşörlerini kullanan sıradan bir özel otomobil 'yetkili araç' değildir. Kaynak: Ark. Code Ann. 27-51-310."},"68":{"q":"Kontrollü erişimi olmayan bir Arkansas kara yolunda, binek otomobiller için genel hız sınırı, bir buçuk ton veya daha fazla kapasiteye sahip kamyonlara göre ne kadar daha yüksektir?","options":["5 mph daha yüksek (55 mph'ye karşı 50 mph)","15 mph daha yüksek (65 mph'ye karşı 50 mph)","10 mph daha yüksek (60 mph'ye karşı 50 mph)","Fark yoktur; her ikisi de 55 mph'dir"],"explanation":"Arkansas, kontrollü erişimi olmayan kara yollarında diğer araçlar için 60 mph'ye izin verir, ancak ağır kamyonlar için yalnızca 50 mph'ye izin verir; bu 10 mph'lik bir farktır. Kaynak: Ark. Code Ann. 27-51-201."},"69":{"q":"Arkansas'ın okul otobüsü yasası kapsamında, hangi yol türünde karşıdan gelen sürücüler çocukları bindiren veya indiren bir okul otobüsü için durmak zorunda DEĞİLDİR?","options":["İki şeritli bir yol","Ortada dönüş şeridi bulunan iki şeritli bir yol","Refüjü olmayan dört şeritli bir yol","Refüj ile ayrılmış dört veya daha fazla şeritli bölünmüş bir kara yolu"],"explanation":"Arkansas, refüj ile ayrılmış dört veya daha fazla şeritli bölünmüş bir kara yolu dışında, her iki yöndeki tüm trafiğin durmasını gerektirir; bölünmüş yolda yalnızca otobüsü takip eden trafik durmak zorundadır. Ortadaki bir dönüş şeridi refüj değildir. Kaynak: Ark. Code Ann. 27-51-1004; resmi Arkansas okul otobüsü güvenlik yasası kılavuzu."},"70":{"q":"Arkansas yasası, kontrollü erişimli kara yollarında ağır kamyonların (1,5 ton veya daha fazla) azami hızının otomobil azami hızının ne kadar altında belirlenmesini gerektirir?","options":["Otomobiller için azami hızın 10 mph altında","Otomobiller için azami hızın 5 mph altında","Otomobiller için azami hızın 15 mph altında","Otomobiller için azami hızla aynı"],"explanation":"Ark. Code 27-51-201, bir buçuk ton veya daha fazla kapasiteye sahip kamyonların kontrollü erişimli kara yollarındaki azami izin verilen hızının otomobil azami hızının 10 mph altında belirlenmesini öngörür (örneğin, otomobillerin 75'te gidebildiği yerde kamyonlar için 70 mph). Kaynak: Ark. Code Ann. 27-51-201."},"71":{"q":"Bazı altı şeritli Eyaletler Arası yollarda 'Trucks Use Right 2 Lanes' (Kamyonlar Sağdaki 2 Şeridi Kullansın) olarak işaretlenen Arkansas'a özgü şerit kısıtlaması hangisidir?","options":["Tüm kamyonlar her zaman yalnızca orta şeritte seyahat etmelidir","İkiden fazla dingile sahip araçlar, belirlenmiş altı şeritli Eyaletler Arası yollarda en sol şeridi kullanamaz","Kamyonlar saat 7.00 ile 9.00 arasında Eyaletler Arası yollardan tamamen yasaklanmıştır","Kamyonlar, sağdaki şeritleri katılım için açık tutmak amacıyla sol şeridi kullanmalıdır"],"explanation":"Act 1054 of 2007, ikiden fazla dingile sahip araçları, 'Trucks Use Right 2 Lanes' olarak işaretlenmiş belirlenmiş altı şeritli Eyaletler Arası yollarda en sol şeritten uzak tutmak için Ark. Code 27-65-107(a)'yı değiştirmiştir. Kaynak: Act 1054 of 2007; Ark. Code Ann. 27-65-107(a)."},"72":{"q":"Arkansas'ta durmuş yetkili bir araca yaklaşırken şerit değiştirmek güvenli değilse veya mümkün değilse, Move Over yasası neyi gerektirir?","options":["Yetkili araç ayrılana kadar yolda tamamen durmak","Şerit değiştirmek mümkün olmadığından belirtilen hızda devam etmek","Yetkili aracın arkasında bankete çekip beklemek","Hızı azaltmak, dikkatle ilerlemek ve bölge boyunca azaltılmış bir hızı korumak"],"explanation":"Güvenli bir şerit değişikliği mümkün olmadığında, Ark. Code 27-51-310, sürücünün hızı azaltmasını, dikkatle ilerlemesini ve yetkili aracın durduğu bölge boyunca yol koşullarına uygun azaltılmış bir hızı korumasını gerektirir. Kaynak: Ark. Code Ann. 27-51-310."},"73":{"q":"Arkansas'ta bir oversize (büyük boy) izni gerekmeden önce bir aracın veya yükün yasal azami genişliği nedir?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Arkansas'ın State Highway System üzerindeki yasal azami genişliği 8 feet 6 inches'tir; bundan daha geniş olan herhangi bir şey bir oversize izni gerektirir. Kaynak: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"74":{"q":"Her iki yönde de trafik taşıyan iki şeritli bir Arkansas yolunda, durmuş bir CMV uyarı üçgenlerini nereye yerleştirmelidir?","options":["Yalnızca arkaya doğru 10 feet, 100 feet ve 200 feet","Aracın 10 feet içinde ve önünde 100 feet ile arkasında 100 feet","Yalnızca aracın 25 feet arkasında ve 25 feet önünde","Yalnızca 100 feet arkasında, önüne hiçbiri yerleştirilmeden"],"explanation":"İki şeritli, çift yönlü (bölünmemiş) bir yolda, bir üçgeni aracın 10 feet içine, birini 100 feet arkasına ve birini 100 feet önüne yerleştirin. Kaynak: Arkansas Commercial Driver License Manual, Bölüm 2.5."},"75":{"q":"Arkansas'ın State Highway System üzerinde bir izin gerekmeden önce bir aracın yasal azami yüksekliği nedir?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"explanation":"Arkansas'ın yasal azami yüksekliği 13 feet 6 inches'tir; bunu aşan yükler bir oversize izni gerektirir. Kaynak: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"76":{"q":"Arkansas, aşırı geniş veya aşırı uzun izinli bir yükün arka köşelerinde ne büyüklükte kırmızı bayraklar ister?","options":["12-inch kırmızı bayraklar","24-inch kırmızı bayraklar","6-inch kırmızı bayraklar","18-inch kırmızı bayraklar"],"explanation":"Arkansas, aşırı geniş ve aşırı uzun yüklerin alt arka köşelerinde, önde ve arkada OVERSIZE LOAD tabelalarıyla birlikte 18-inch kırmızı bayraklar ister. Kaynak: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"77":{"q":"Arkansas'ta, prefabrik veya seyyar bir ev çeken bir aracın sürülebileceği azami hız nedir?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"Arkansas izin kuralları, prefabrik veya seyyar bir ev çeken bir aracın 55 mph'den daha hızlı sürülmesini yasaklar. Kaynak: Code of Arkansas Rules 111-109 / ARDOT Permit Rules (oversize/overweight hareketi)."},"78":{"q":"Çocukları bindiren veya indiren durmuş bir okul otobüsünü yasadışı şekilde geçmeye ilişkin Arkansas cezaları, hangi aralıkta bir para cezası içerir?","options":["Hapis cezası olmadan sabit 100 dolar para cezası","500 dolardan az ve 5.000 dolardan fazla olmamak üzere","250 dolardan az ve 1.000 dolardan fazla olmamak üzere","50 dolardan az ve 250 dolardan fazla olmamak üzere"],"explanation":"Ark. Code 27-51-1001, durmuş bir okul otobüsünü geçme cezasını 250 dolardan az ve 1.000 dolardan fazla olmamak üzere belirler; olası hapis, ehliyetin askıya alınması ve kamu hizmeti ile birlikte. Kaynak: Ark. Code Ann. 27-51-1001."},"79":{"q":"Arkansas'ta bir demir yolu-kara yolu geçidinde dururken, bir ticari sürücü geçmeden önce ayrıca aşağıdakilerden hangisini yapmalıdır?","options":["Dörtlü acil flaşörleri açmalı ve varsa bir kenara çekilme şeridi kullanmalıdır","Araç rayları geçene kadar sürekli kornaya basmalıdır","Rayları daha hızlı geçmek için daha yüksek bir vitese geçmelidir","Rayların görüşünü en üst düzeye çıkarmak için doğrudan en yakın rayın üzerinde durmalıdır"],"explanation":"Bir hemzemin geçitte durmak gerektiğinde, Arkansas kılavuzu sürücülere kademeli olarak dururken arkadaki trafiği kontrol etmelerini, varsa bir kenara çekilme şeridi kullanmalarını ve dörtlü flaşörleri açmalarını söyler; geçerken vites değiştirmeyin. Kaynak: Arkansas Commercial Driver License Manual, Bölüm 2.15.4."},"80":{"q":"Arkansas'ta Ticari Sürücü Belgelerini (CDL) vermekten hangi eyalet kurumu sorumludur?","options":["Arkansas State Police Highway Safety Division","Arkansas Department of Transportation (ARDOT)","Federal Motor Carrier Safety Administration (FMCSA)","Arkansas Department of Finance and Administration (DFA), Office of Driver Services"],"explanation":"Arkansas'ta CDL'ler, sürücü belgesi yasasını yöneten ve uygulayan Department of Finance and Administration (DFA), Office of Driver Services tarafından verilir. Kaynak: Arkansas DFA Office of Driver Services / CDL sayfaları (dfa.arkansas.gov)."},"81":{"q":"Arkansas'ta CDL beceri (yol) testini genellikle kim uygular?","options":["Başvuru randevusu sırasında herhangi bir yerel gelir dairesi memuru","Belirlenmiş test merkezlerindeki Arkansas State Police veya onaylı bir üçüncü taraf test uzmanı","Arkansas Department of Transportation tartı istasyonu personeli","Yalnızca belgeyi doğrudan veren özel CDL okulları"],"explanation":"Belgeyi DFA verirken, CDL beceri testleri belirlenmiş Arkansas State Police test merkezlerinde veya onaylı üçüncü taraf test uzmanları tarafından uygulanır. Kaynak: Arkansas DFA Driver Services / Arkansas State Police CDL test bilgileri."},"82":{"q":"Bir başvuru sahibi Arkansas'ta CDL beceri testine girmeden önce, ilk olarak hangi belgeyi almalıdır?","options":["Bir Class D sürücü belgesi ek yetkisi","Bir federal eyaletler arası işletme yetki numarası","Bir Commercial Learner's Permit (CLP)","Geçici 30 günlük bir ticari yol izni"],"explanation":"Bir başvuru sahibi, Arkansas'ta CDL beceri testine girmeden önce ilk olarak bir Commercial Learner's Permit (CLP) sahibi olmalıdır. Kaynak: Arkansas DFA CLP sayfası (dfa.arkansas.gov)."},"83":{"q":"Arkansas kurallarına göre, bir başvuru sahibinin CDL beceri testine girmesine izin verilmeden önce bir Commercial Learner's Permit (CLP) ne kadar süre elinde tutması gerekir?","options":["CLP'nin ilk verilmesinden sonra en az 14 gün","CLP'nin ilk verilmesinden sonra en az 30 gün","CLP'nin ilk verilmesinden sonra en az 7 gün","CLP'nin ilk verilmesinden sonra en az 60 gün"],"explanation":"Arkansas, federal CDL standardını izleyerek, CLP'nin ilk verilmesinden sonraki ilk 14 gün içinde beceri testine girilmesini yasaklar. Kaynak: Arkansas DFA CLP sayfası (Arkansas tarafından benimsenen 49 CFR 383.25 standardı)."},"84":{"q":"Bilgi testlerinin yeniden alınması gerekmeden önce bir Commercial Learner's Permit (CLP) Arkansas'ta geçerli kaldığı azami süre nedir?","options":["Verilişinden itibaren iki yıla kadar","Verilişinden itibaren bir yıla kadar","Verilişinden itibaren 90 güne kadar","Verilişinden itibaren dört yıla kadar"],"explanation":"CLP bir yıla kadar geçerlidir; süresi dolarsa, sahibinin yeni bir izin verilebilmeden önce genel ve varsa ek yetki bilgi testlerini yeniden alması gerekir. Kaynak: Arkansas DFA CLP sayfası (49 CFR 383.25 ile tutarlı)."},"85":{"q":"Arkansas'ta ilk kez bir Class A CDL almak isteyen yeni bir başvuru sahibi, CLP'den CDL'ye geçiş süreci için bilgi testine girmeden önce hangi federal olarak gerekli eğitimi tamamlamalıdır?","options":["Eyalet tarafından yürütülen bir savunmacı sürüş sertifika kursu","FMCSA kayıtlı bir sağlayıcıdan Entry-Level Driver Training (ELDT)","Bir National Safety Council ilk yardım sertifikası","İşveren destekli 12 ay süren bir çıraklık"],"explanation":"7 Şubat 2022'den bu yana, ilk kez CDL başvuru sahipleri, teste girmeden önce FMCSA Training Provider Registry'de listelenen bir sağlayıcı aracılığıyla Entry-Level Driver Training (ELDT) tamamlamalıdır. Arkansas, tamamlamayı kayıt üzerinden doğrular. Kaynak: FMCSA ELDT kuralı / Arkansas DFA CDL bilgileri."},"86":{"q":"ELDT teori eğitiminin tamamlanması, Arkansas DFA'nın bir CDL vermeden önce kontrol ettiği hangi sisteme bildirilir?","options":["Yalnızca Arkansas DFA MyDMV portalı","National Driver Register (NDR)","Yalnızca Commercial Driver License Information System (CDLIS)","FMCSA Training Provider Registry (TPR)"],"explanation":"Eğitim sağlayıcılar, ELDT tamamlamasını FMCSA Training Provider Registry'ye (TPR) gönderir; Arkansas DFA dahil eyalet belge kurumu, beceri testine izin vermeden veya CDL vermeden önce TPR'yi kontrol eder. Kaynak: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov)."},"87":{"q":"Aşağıdaki durumların hepsinde ELDT, Arkansas'ta ilk kez başvuran biri için gereklidir, ŞU DURUM HARİÇ:","options":["İlk kez bir Class A veya Class B CDL almak","Mevcut bir Class B CDL'yi bir Class A CDL'ye yükseltmek","Yeni ek yetkisi olmayan mevcut bir Class A CDL'yi yenilemek","İlk kez bir tehlikeli madde (H) ek yetkisi almak"],"explanation":"ELDT, ilk kez alınan Class A/B CDL'ler, B'den A'ya yükseltmeler ve ilk kez alınan S, P veya H ek yetkileri için geçerlidir. Yeni ek yetkisi olmayan mevcut bir CDL'nin basit bir yenilenmesi ELDT'yi tetiklemez. Kaynak: Arkansas'ta uygulandığı şekliyle FMCSA ELDT kuralı (49 CFR Part 380)."},"88":{"q":"Arkansas'taki CDL beceri testi, genellikle gerçekleştirildikleri sırayla hangi üç bölümden oluşur?","options":["Yazılı bilgi, görme taraması ve yol üzerinde sürüş","Hava freni kontrolü, tehlikeli madde elleçleme ve yol üzerinde sürüş","Sefer öncesi muayene, temel araç kontrolü ve yol üzerinde sürüş","Temel araç kontrolü, bilgi testi ve sefer öncesi muayene"],"explanation":"Arkansas CDL beceri testi üç bölümden oluşur: sefer öncesi araç muayenesi, temel araç kontrol becerileri ve yol üzerinde sürüş testi. Kaynak: Arkansas DFA / Arkansas State Police CDL beceri testi bilgileri (49 CFR 383.113)."},"89":{"q":"Arkansas CDL beceri testinin temel araç kontrolü bölümü sırasında, sınav görevlisi öncelikle başvuru sahibinin hangi becerisini değerlendirir:","options":["Aracı dar bir alanda hassas bir şekilde manevra yapma ve geri geri sürme","Federal hizmet saati sınırlarını ezberden okuma","Aracın brüt kombinasyon ağırlık derecesini hesaplama","Acil durum yol kenarı işaret fişeği yerleştirmesini gösterme"],"explanation":"Temel araç kontrolü, sürücünün düz çizgide geri geri gitme, kaydırmalı geri geri gitme ve dar bir alanda park etme gibi manevralarla aracı kontrol etme ve konumlandırma becerisini test eder. Kaynak: Arkansas DFA / FMCSA beceri testi standartları (49 CFR 383.113)."},"90":{"q":"Arkansas tarafından benimsenen federal tıbbi sertifikasyon kuralları, her CLP ve CDL sahibinin kaç olası işletme kategorisine kendini sertifikalandırmasını gerektirir?","options":["İki kategori","Dört kategori","Üç kategori","Altı kategori"],"explanation":"Her CLP/CDL sahibi, eyaletler arası ve eyalet içi işletme ile istisna tutulan ve istisna tutulmayan durumuna göre dört kategoriden birine kendini sertifikalandırmalıdır. Kaynak: Arkansas DFA Medical Certification sayfası (49 CFR 383.71)."},"91":{"q":"Hangi kendini sertifikalandırma kategorisi, sürücünün federal DOT fiziksel yeterlilik standartlarını karşılamasını ve bir tıbbi muayene sertifikası taşımasını gerektirir?","options":["Excepted Interstate (İstisna Tutulan Eyaletler Arası)","Excepted Intrastate (İstisna Tutulan Eyalet İçi)","Non-Excepted Interstate (İstisna Tutulmayan Eyaletler Arası)","Hobi / Yalnızca Kişisel Kullanım"],"explanation":"Kendini Non-Excepted Interstate olarak sertifikalandıran bir sürücü, federal DOT fiziksel yeterlilik standartlarını (49 CFR 391) karşılamalı ve geçerli bir tıbbi muayene sertifikası bulundurmalıdır. Kaynak: Arkansas DFA Medical Certification sayfası (49 CFR 383.71)."},"92":{"q":"Yalnızca Arkansas içinde faaliyet gösteren ve federal fiziksel yeterlilik gerekliliklerine TABİ OLMAYAN bir sürücü, en doğru şekilde nasıl kendini sertifikalandırır:","options":["Non-Excepted Interstate (İstisna Tutulmayan Eyaletler Arası)","Excepted Intrastate (İstisna Tutulan Eyalet İçi)","Excepted Interstate (İstisna Tutulan Eyaletler Arası)","Non-Excepted Federal (İstisna Tutulmayan Federal)"],"explanation":"Yalnızca eyalet içinde faaliyet gösteren ve federal fiziksel yeterlilik standartlarını karşılaması gerekmeyen bir sürücü, kendini Excepted Intrastate olarak sertifikalandırır. Kaynak: Arkansas DFA Medical Certification sayfası (49 CFR 383.71)."},"93":{"q":"Arkansas'taki bir CDL başvuru sahibi kendini Non-Excepted Interstate olarak sertifikalandırdığında, fiziksel muayeneyi yapan DOT tıbbi muayene görevlisi şu olmalıdır:","options":["Arkansas State Police tıbbi biriminde istihdam edilen biri","Başvuru sahibinin ikamet ettiği ilçedeki herhangi bir ruhsatlı eczacı","Yerel gelir dairesi müdürü tarafından bireysel olarak onaylanmış biri","FMCSA National Registry of Certified Medical Examiners'da listelenmiş biri"],"explanation":"İstisna tutulmayan sürücüler, fiziksel muayenelerini FMCSA National Registry of Certified Medical Examiners'da listelenen bir tıbbi muayene görevlisinden almalıdır ve bu sertifika Office of Driver Services'a sunulur. Kaynak: Arkansas DFA Medical Certification sayfası (49 CFR 391.41 / National Registry)."},"94":{"q":"Aşağıdakilerden hangisi, bir DOT Tıbbi Muayene Sertifikası ve Kendini Sertifikalandırma Beyannamesini Arkansas Office of Driver Services'a sunmanın kabul edilen bir yoludur?","options":["Doğrudan FMCSA National Registry web sitesine göndermek","Herhangi bir trafik durdurmasında yol kenarındaki bir Arkansas State Police polisine teslim etmek","Herhangi bir Arkansas gelir dairesine şahsen götürmek veya Office of Driver Services'a e-posta/faks ile göndermek","Yalnızca başvuru sahibinin özel nakliye işvereni portalına yüklemek"],"explanation":"Arkansas, tıbbi sertifikayı ve kendini sertifikalandırmayı herhangi bir eyalet gelir dairesinde şahsen, Office of Driver Services'a posta yoluyla veya DFA'nın yayımladığı e-posta/faks kanallarıyla kabul eder. Kaynak: Arkansas DFA Medical Certification / Register Medical Certificate sayfaları."},"95":{"q":"İstisna tutulmayan bir Arkansas CDL sahibinin DOT tıbbi muayene sertifikasının süresi dolar ve yenisi sunulmazsa, ticari ayrıcalıklarına ne olur?","options":["CDL bir 'Not Certified' (Sertifikalı Değil) durumuna getirilir ve ticari sürüş ayrıcalıkları kaybedilir","Tam CDL süresi yıllar sonra dolana kadar hiçbir şey değişmez","CDL bir yıllığına otomatik olarak bir CLP'ye düşürülür","Sürücüye para cezası kesilir ancak tam ticari ayrıcalıklarını korur"],"explanation":"Süresi dolduğunda güncel bir tıbbi kart sağlamamak, geçerli bir sertifika sunulana kadar ticari sürüş ayrıcalıklarını kaldırarak CDL'yi bir 'Not Certified' tıbbi durumuna sokar. Kaynak: Arkansas DFA Medical Certification sayfası."},"96":{"q":"Arkansas'ta bir CDL'yi yenilerken, istisna tutulmayan bir sürücü genellikle aşağıdakilerin hepsini sağlamalıdır, ŞU HARİÇ:","options":["Mevcut sınıf için yeni bir Entry-Level Driver Training (ELDT) sertifikası","Mevcut sürücü belgesi","Doldurulmuş bir Kendini Sertifikalandırma Beyannamesi","Güncel bir Tıbbi Muayene Sertifikası"],"explanation":"Aynı sınıftan mevcut bir CDL'yi yeni ek yetkisi olmadan yenilemek ELDT gerektirmez; sürücünün mevcut belgesine, bir kendini sertifikalandırma beyannamesine ve (istisna tutulmuyorsa) güncel bir tıbbi sertifikaya ihtiyacı vardır. Kaynak: Arkansas DFA Driver Services yenileme gereklilikleri / FMCSA ELDT kuralı."},"97":{"q":"Eyalet içi (eyalet sınırları içinde) ticari sürüş ile sınırlı bir Arkansas CDL almak için asgari yaş nedir?","options":["18 yaşında","21 yaşında","19 yaşında","16 yaşında"],"explanation":"Arkansas, eyalet içi işletme için 18 yaşında bir CDL'ye izin verir; eyaletler arası işletme, sürücünün 21 yaşında olmasını gerektirir. Kaynak: Arkansas DFA CDL gereklilikleri (49 CFR 383 / 391 yaş standartları)."},"98":{"q":"Arkansas'taki CDL başvuru ücretlerine ilişkin olarak, hangi ifade doğru süreç odaklı beklentiyi yansıtır?","options":["CDL başvurusu ve testi Arkansas'ta her zaman ücretsizdir","Ücret federal yasayla kalıcı olarak sabitlenmiştir ve asla değişmez","Yalnızca tehlikeli madde ek yetkisi bir ücret taşır; diğer tüm CDL hizmetleri ücretsizdir","Ücretler eyalet tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri başvurmadan önce güncel tutarı DFA ile teyit etmelidir"],"explanation":"Arkansas CDL ücretleri (belge, ek yetki ve test) eyalet tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri sabit bir rakama güvenmek yerine güncel tutarları DFA ile doğrulamalıdır. Kaynak: Arkansas DFA Driver Services ücret çizelgesi (değişebilir)."}},"es":{"0":{"q":"En las carreteras de Arkansas, ¿cuál es el ancho exterior total máximo de un vehículo (con o sin carga) antes de que se requiera un permiso especial?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"El Arkansas Code Ann. 27-35-206 establece el ancho legal máximo de un vehículo en 102 inches (8 feet 6 inches), sin carga o con carga; cualquier vehículo más ancho requiere un permiso de sobredimensión de ARDOT/la Policía de Carreteras de Arkansas."},"1":{"q":"Conforme a la ley actual de Arkansas, ¿cuál es la altura máxima de un vehículo (incluida su carga) permitida en las carreteras estatales sin un permiso especial?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"El Arkansas Code Ann. 27-35-207, según fue modificado por el Act 871 of 2021 (vigente desde el 28 de julio de 2021), elevó el límite legal de altura de 13'6\" a 14 feet. Un vehículo que exceda los 14 feet requiere un permiso especial (de sobrealtura)."},"2":{"q":"¿Cuál es el peso bruto máximo de un vehículo o combinación permitido en las carreteras de Arkansas sin un permiso de sobrepeso?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"De acuerdo con el estándar federal y el Arkansas Code Ann. 27-35-203, el peso bruto legal máximo es de 80,000 pounds. Excederlo requiere un permiso de sobrepeso de la Sección de Permisos de ARDOT/la Policía de Carreteras de Arkansas."},"3":{"q":"En Arkansas, ¿cuál es la carga máxima que puede llevarse sobre un solo eje sin un permiso?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"El Arkansas Code Ann. 27-35-203 limita un solo eje a 20,000 pounds. Esto coincide con el límite federal de eje sencillo aplicado en las carreteras de Arkansas."},"4":{"q":"¿Cuál es la carga legal máxima sobre un grupo de ejes en tándem en Arkansas sin un permiso?","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"explanation":"El Arkansas Code Ann. 27-35-203 limita un eje en tándem a 34,000 pounds. (Con un permiso, un tándem puede alcanzar 46,000 pounds, pero 34,000 es el máximo sin permiso.)"},"5":{"q":"Conforme al Arkansas Code 27-35-203, dos ejes consecutivos se consideran un 'eje en tándem' cuando la separación entre sus centros es:","options":["More than 40 inches but not more than 96 inches","More than 96 inches but not more than 120 inches","Exactamente 48 inches","Less than 40 inches"],"explanation":"El Arkansas Code Ann. 27-35-203 define un eje en tándem como dos o más ejes consecutivos cuyos centros están separados por más de 40 inches y no más de 96 inches, con un límite combinado de 34,000 pounds."},"6":{"q":"¿Cuál es la longitud máxima de un camión sencillo (rígido) operado en las carreteras de Arkansas sin un permiso?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"El Arkansas Code Ann. 27-35-208 limita un vehículo sencillo (rígido) a una longitud total de 40 feet, sin carga o con carga."},"7":{"q":"En las carreteras de Arkansas, ¿cuál es la longitud máxima de un semirremolque que opera en combinación con un tractocamión por debajo de la cual el estado no puede restringirlo?","options":["48 feet","50 feet","53 feet 6 inches","57 feet"],"explanation":"El Arkansas Code Ann. 27-35-208 dispone que el estado no impondrá un límite de longitud de semirremolque/remolque inferior a 53 feet 6 inches a una unidad operada en combinación con un tractocamión."},"8":{"q":"En una combinación de tractocamión-semirremolque-remolque (combinación doble/gemela) en las carreteras de Arkansas, ¿cuál es la longitud máxima de cada unidad de arrastre?","options":["24 feet","28 feet","33 feet","40 feet"],"explanation":"El Arkansas Code Ann. 27-35-208 limita cada semirremolque o remolque en una combinación de tractocamión-semirremolque-remolque (doble) a una longitud total de 28 feet, sin incluir los dispositivos de acople."},"9":{"q":"¿Qué fórmula utiliza Arkansas para determinar el peso máximo permitido sobre un grupo de ejes en relación con la distancia entre ellos?","options":["The Federal Bridge Formula (Formula B)","La Fórmula de Tara de Arkansas","La Regla de Relación de Combinación Bruta","El Multiplicador de Separación de Tándem"],"explanation":"Arkansas aplica la Federal Bridge Formula (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], para establecer el peso máximo que un grupo de ejes dado puede llevar con base en el número de ejes (N) y la distancia (L) entre ellos."},"10":{"q":"En la Federal Bridge Formula aplicada en Arkansas, W = 500[LN/(N-1) + 12N + 36], ¿qué representa 'N'?","options":["El número de ejes en el grupo considerado","El peso neto (tara) del vehículo","El número de llantas en el eje de tracción","El límite de velocidad nominal de la carretera"],"explanation":"En la Federal Bridge Formula utilizada por Arkansas, N es el número de ejes en el grupo bajo consideración, L es la separación en feet entre los ejes exteriores del grupo, y W es el peso máximo permitido."},"11":{"q":"La carga de un camionero mide 9 feet 2 inches de ancho. En las carreteras de Arkansas, esta carga:","options":["Es legal porque mide menos de 10 feet","Requiere un permiso de sobredimensión porque excede las 102 inches","Es legal solo en el sistema interestatal (Interstate)","Requiere solo una bandera, no un permiso"],"explanation":"El ancho legal de Arkansas es de 102 inches (8'6\") según el Code 27-35-206. Una carga de 9'2\" (110 inches) excede el ancho legal y requiere un permiso de sobredimensión de ARDOT/la Policía de Carreteras de Arkansas."},"12":{"q":"¿Qué agencia emite los permisos de movimiento de sobredimensión y sobrepeso para el Sistema de Carreteras Estatales de Arkansas?","options":["El Arkansas Department of Finance and Administration","El Arkansas Department of Transportation a través de la Sección de Permisos de la Policía de Carreteras de Arkansas","El sheriff de cada condado por donde se transita","La Federal Motor Carrier Safety Administration"],"explanation":"Conforme a las Reglas de Permisos 2023 de ARDOT, los permisos de sobredimensión/sobrepeso para el Sistema de Carreteras Estatales son emitidos por el Arkansas Department of Transportation a través de la Sección de Permisos de la Policía de Carreteras de Arkansas."},"13":{"q":"¿Cuándo necesita un transportista un permiso de sobrepeso en Arkansas?","options":["Solo cuando la carga puede reducirse dividiéndola","Cuando el vehículo excede los límites legales de peso bruto, de eje sencillo o de eje en tándem","Cada vez que el viaje cruza el límite de un condado","Solo cuando se viaja de noche"],"explanation":"Según las Reglas de Permisos de ARDOT y el Code 27-35-203/210, se requiere un permiso de sobrepeso siempre que un vehículo exceda los límites legales (80,000 lbs bruto, 20,000 lbs eje sencillo, o 34,000 lbs tándem, o un límite de la fórmula de puente). Dichos permisos por lo general se emiten solo para cargas indivisibles."},"14":{"q":"Los permisos de sobrepeso en Arkansas por lo general se emiten solo para cargas que son:","options":["Divisibles en cargas legales más pequeñas","Indivisibles (no pueden reducirse razonablemente al peso legal)","Transportadas a menos de 45 mph","Propiedad de una agencia gubernamental"],"explanation":"Conforme a las Reglas de Permisos de ARDOT, se emite un permiso de sobrepeso para cargas indivisibles, aquellas que no pueden desglosarse razonablemente para cumplir con los límites legales de peso. Las cargas divisibles deben reducirse al peso legal en lugar de obtener un permiso."},"15":{"q":"Arkansas permite un permiso anual para una combinación de tractocamión/semirremolque de al menos cinco ejes que transporte cultivos agronómicos u hortícolas en su estado natural hasta qué peso bruto?","options":["84,000 pounds","90,000 pounds","100,000 pounds","112,000 pounds"],"explanation":"El Arkansas Code Ann. 27-35-210 autoriza un permiso anual para una combinación de tractocamión/semirremolque de un mínimo de cinco ejes que transporte cultivos agronómicos u hortícolas en estado natural hasta un peso bruto total de 100,000 pounds."},"16":{"q":"En un movimiento con permiso en Arkansas, un grupo de ejes en tándem puede cargarse hasta un máximo de:","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"explanation":"Conforme a las Reglas de Permisos de ARDOT, un grupo de ejes en tándem con permiso puede llevar hasta 46,000 pounds (sin que ningún eje sencillo exceda las 23,000 pounds), en comparación con el límite legal sin permiso de 34,000 pounds del Code 27-35-203."},"17":{"q":"Un tractocamión-semirremolque de cinco ejes en Arkansas está cargado a 80,000 lbs bruto, 20,000 lbs sobre el eje direccional, 34,000 lbs sobre el tándem de tracción, y 26,000 lbs sobre el tándem del remolque. ¿Qué condición está por encima del límite legal?","options":["El peso bruto","El peso del eje direccional (sencillo)","El peso del tándem de tracción","Ninguno de estos excede su límite legal"],"explanation":"Según el Code 27-35-203, los límites legales son 80,000 lbs bruto, 20,000 lbs eje sencillo, y 34,000 lbs tándem. Cada valor aquí está en o por debajo de su límite, por lo que ningún eje ni el peso bruto excede el límite legal (la separación de la fórmula de puente sigue aplicando)."},"18":{"q":"¿Cuál afirmación sobre la longitud total de la combinación en las carreteras de Arkansas es correcta para un tractocamión con un solo semirremolque?","options":["Arkansas limita la combinación total de tractocamión-semirremolque a exactamente 65 feet","Arkansas no impone un límite fijo de longitud total a una combinación de tractocamión con un solo semirremolque; el semirremolque en sí puede medir hasta 53'6\"","Arkansas limita la combinación total a 60 feet en todas las vías","Arkansas no permite ningún semirremolque de más de 48 feet"],"explanation":"El Arkansas Code Ann. 27-35-208 limita la longitud del semirremolque (no puede restringirse a menos de 53'6\") pero no establece un límite fijo de longitud total para una combinación de tractocamión más un solo semirremolque, de manera consistente con las reglas federales STAA."},"19":{"q":"Una plataforma (flatbed) en Arkansas mide 14 feet 4 inches de alto hasta la parte superior de su carga. Sin un permiso, este vehículo es:","options":["Legal, porque el límite es de 15 feet","De sobrealtura y requiere un permiso especial (de sobrealtura)","Legal solo fuera del sistema interestatal (Interstate)","Legal porque la altura no está regulada en Arkansas"],"explanation":"La altura legal actual de Arkansas es de 14 feet según el Code 27-35-207 (modificado por el Act 871 of 2021). Una carga que mide 14'4\" excede los 14 feet y requiere un permiso de sobrealtura de ARDOT/la Policía de Carreteras de Arkansas."},"20":{"q":"En Arkansas, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 pounds o más, donde la unidad remolcada tiene un GVWR de más de 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Arkansas define una CDL Class A como cualquier combinación de vehículos con un GCWR de 26,001 pounds o más, incluida una unidad remolcada con un GVWR de más de 10,000 pounds. Fuente: Arkansas CDL Manual, Section 1 (Clasificaciones); página de CDL de la Office of Driver Services de Arkansas DFA."},"21":{"q":"Conforme a las reglas de Arkansas, un vehículo sencillo con un GVWR de 26,001 pounds o más (o tal vehículo remolcando una unidad que no exceda los 10,000 pounds GVWR) requiere qué clase de CDL?","options":["Class B","Class A","Class C","Class M"],"explanation":"Arkansas define una CDL Class B como cualquier vehículo sencillo con un GVWR de 26,001 pounds o más, o cualquier vehículo de ese tipo remolcando una unidad que no exceda los 10,000 pounds GVWR. Fuente: Arkansas CDL Manual, Section 1 (Clasificaciones); página de CDL de Arkansas DFA."},"22":{"q":"En Arkansas, un vehículo que no cumple con la definición de Class A o Class B pero está diseñado para transportar 16 o más pasajeros (incluido el conductor) o se usa para transportar materiales peligrosos con rótulo (placarded) corresponde a qué clase de CDL?","options":["Class A","Class C","Class B","Class P"],"explanation":"Arkansas define una CDL Class C como un vehículo que no cumple con la Class A o B pero está diseñado para llevar 16 o más pasajeros incluido el conductor, o que transporta materiales peligrosos con rótulo (placarded) o un agente/toxina selecto bajo 42 CFR Part 73. Fuente: Arkansas CDL Manual, Section 1; página de CDL de Arkansas DFA."},"23":{"q":"¿Cuál es la edad mínima para obtener una CDL de Arkansas limitada a conducir un vehículo motorizado comercial únicamente dentro del estado (comercio intraestatal)?","options":["16 years old","18 years old","19 years old","21 years old"],"explanation":"Arkansas requiere que un conductor tenga al menos 18 años para operar un vehículo motorizado comercial en comercio intraestatal (únicamente dentro de Arkansas). Fuente: requisitos de CDL de la Office of Driver Services de Arkansas DFA."},"24":{"q":"¿Cuál es la edad mínima requerida para obtener una CDL de Arkansas válida para conducir cruzando líneas estatales (comercio interestatal)?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"Arkansas (siguiendo los estándares federales) requiere que un conductor tenga al menos 21 años para operar un vehículo motorizado comercial en comercio interestatal. Un conductor de 18 a 20 años está limitado a la operación intraestatal. Fuente: requisitos de CDL de la Office of Driver Services de Arkansas DFA."},"25":{"q":"¿Qué endoso se requiere en Arkansas para operar un vehículo cisterna diseñado para transportar líquido o gas en un tanque con una capacidad nominal individual de más de 119 gallons y una capacidad nominal agregada de 1,000 gallons o más?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"Arkansas requiere el endoso N (vehículo cisterna / Tank Vehicle) para vehículos diseñados para transportar materiales líquidos o gaseosos en un tanque o tanques que tengan una capacidad nominal individual de más de 119 gallons y una capacidad nominal agregada de 1,000 gallons o más. Fuente: Arkansas CDL Manual, Section 1 (Endosos) y Section 8."},"26":{"q":"En Arkansas, ¿qué endoso se requiere para conducir un vehículo que transporta material designado como peligroso y que debe llevar rótulo (placarded) bajo 49 CFR Part 172?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"explanation":"Arkansas requiere el endoso H (materiales peligrosos / HazMat), sin importar la clase del vehículo, para cualquier conductor que transporte material designado como peligroso bajo 49 U.S.C. 5103 y que deba llevar rótulo (placarded) bajo 49 CFR Part 172. Fuente: Arkansas CDL Manual, Section 1 (Endosos)."},"27":{"q":"Además de aprobar un examen escrito de conocimientos, ¿qué paso adicional requiere Arkansas antes de emitir un endoso de materiales peligrosos (H)?","options":["Un examen de la vista realizado por un oftalmólogo","Una evaluación de amenaza de seguridad de la TSA con huellas dactilares y una verificación de antecedentes","Un segundo examen de habilidades de manejo en un vehículo cisterna","Una carta de patrocinio del empleador notariada"],"explanation":"Para obtener, renovar o transferir un endoso de HazMat, Arkansas requiere una evaluación de amenaza de seguridad de la TSA que incluye toma de huellas dactilares y una verificación federal de antecedentes (registros penales, de inmigración y del FBI). Los conductores deben prever al menos 90 días. Fuente: página de Hazardous Materials Endorsement de Arkansas DFA; Arkansas CDL Manual, Section 1."},"28":{"q":"¿Qué endoso requiere Arkansas para un conductor que quiere remolcar remolques dobles o triples?","options":["T endorsement","N endorsement","S endorsement","X endorsement"],"explanation":"Arkansas requiere el endoso T (dobles/triples / Doubles/Triples) para remolcar remolques dobles o triples; el solicitante debe aprobar un examen de conocimientos sobre los problemas asociados con el remolque de múltiples remolques. Fuente: Arkansas CDL Manual, Section 1 (Endosos) y Section 7."},"29":{"q":"En Arkansas, un conductor que desea operar un vehículo diseñado para llevar 16 o más personas, incluido el conductor, debe obtener qué endoso?","options":["S endorsement","T endorsement","P endorsement","N endorsement"],"explanation":"Arkansas requiere el endoso P (pasajeros / Passenger) para los conductores de un vehículo diseñado para llevar 16 o más personas incluido el conductor. El solicitante debe aprobar un examen de conocimientos y un examen de habilidades en un vehículo de pasajeros. Fuente: Arkansas CDL Manual, Section 1 (Endosos) y Section 4."},"30":{"q":"¿Qué endoso debe tener un conductor de Arkansas para conducir un autobús escolar, además del endoso de pasajeros (P)?","options":["H endorsement","T endorsement","S endorsement","X endorsement"],"explanation":"Arkansas requiere el endoso S (autobús escolar / School Bus) para conducir un autobús escolar; el conductor debe aprobar un examen de conocimientos de autobús escolar y un examen de habilidades en un autobús escolar, y el endoso aplica en cualquier clase (A, B o C). Fuente: Arkansas CDL Manual, Section 1 (Endosos) y Section 10."},"31":{"q":"En Arkansas, un conductor de un vehículo cisterna que también debe transportar materiales peligrosos con rótulo (placarded) debe obtener qué endoso combinado único?","options":["T endorsement","X endorsement","P endorsement","S endorsement"],"explanation":"Arkansas emite el endoso X como una combinación de HazMat y vehículo cisterna (Tank Vehicle); el conductor debe aprobar los exámenes de conocimientos tanto de vehículos cisterna como de materiales peligrosos. Fuente: Arkansas CDL Manual, Section 1 (Endosos)."},"32":{"q":"Según el Arkansas CDL Manual, ¿qué conjunto de endosos son los ÚNICOS que pueden agregarse a un Permiso de Aprendiz Comercial (CLP)?","options":["H, N, and T","P, H, and X","P, S, and N","T, S, and H"],"explanation":"El Arkansas CDL Manual establece que los únicos endosos que pueden agregarse a un CLP son pasajeros (P), autobús escolar (S) y vehículo cisterna (N). Un endoso de HazMat (H) no puede emitirse en un CLP. Fuente: Arkansas CDL Manual, Section 1 (Endosos/CLP)."},"33":{"q":"En Arkansas, cuando se emite un CLP con un endoso de vehículo cisterna (N), ¿qué restricción debe llevar?","options":["Sin operación interestatal (K)","Sin CMV equipado con frenos de aire (L)","Sin transmisión manual (E)","Sin carga en un vehículo cisterna CMV (X)"],"explanation":"Arkansas requiere que un CLP emitido con un endoso N también lleve la restricción X (sin carga en un vehículo cisterna CMV); el titular solo puede operar un tanque vacío que haya sido purgado de cualquier residuo. Fuente: Arkansas CDL Manual, Section 1 (Restricciones)."},"34":{"q":"Conforme a las reglas de CLP de Arkansas y federales, ¿cuánto tiempo debe esperar el titular de un CLP después de la emisión inicial antes de ser elegible para presentar el examen de habilidades de la CDL?","options":["7 days","10 days","14 days","30 days"],"explanation":"Arkansas aplica la regla federal de que el titular de un CLP no es elegible para presentar el examen de habilidades de la CDL durante los primeros 14 days posteriores a la emisión inicial del CLP. Fuente: página de Commercial Learner's Permit (CLP) de Arkansas DFA; 49 CFR 383.25."},"35":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Arkansas antes de que el titular deba volver a presentar los exámenes de conocimientos generales y de endoso?","options":["Up to 60 days","Up to 180 days","Up to 1 year","Up to 2 years"],"explanation":"Un CLP de Arkansas es válido por hasta 1 year; después de su vencimiento el titular debe volver a presentar los exámenes de conocimientos generales y de endoso. Fuente: página de Commercial Learner's Permit (CLP) de Arkansas DFA."},"36":{"q":"¿Qué agencia estatal emite la Licencia de Conducir Comercial (CDL) en Arkansas?","options":["Arkansas State Police","Arkansas Department of Finance and Administration, Office of Driver Services","Arkansas Department of Transportation (ARDOT)","Federal Motor Carrier Safety Administration"],"explanation":"En Arkansas la CDL es emitida por el Department of Finance and Administration (DFA), Office of Driver Services. ARDOT se encarga de las carreteras/permisos y la FMCSA es el regulador federal, pero la agencia que emite las licencias es DFA Driver Services. Fuente: página de CDL de Arkansas DFA Driver Services."},"37":{"q":"Al solicitar una CDL o CLP de Arkansas, ¿qué combinación de comprobantes requiere la Office of Driver Services que presente el solicitante?","options":["Solo una tarjeta de Seguro Social y una factura de servicios públicos","Solo un pasaporte de EE. UU.","Comprobante de identidad/fecha de nacimiento, número de Seguro Social, residencia en Arkansas y presencia legal","Un diploma de preparatoria y comprobante de empleo"],"explanation":"Arkansas DFA requiere que los solicitantes proporcionen comprobante de identidad y fecha de nacimiento, comprobante del número de Seguro Social, comprobante de residencia en Arkansas (domicilio actual) y comprobante de presencia legal/presencia legal en EE. UU. Fuente: requisitos de documentación de Arkansas DFA Driver Services ('Do You Have What You Need?')."},"38":{"q":"Conforme a las reglas federales de Capacitación de Conductores de Nivel Inicial (ELDT) aplicadas en Arkansas (vigentes desde el 7 de febrero de 2022), ¿dónde debe un solicitante por primera vez completar la capacitación requerida antes de presentar el examen?","options":["Cualquier colegio comunitario en Arkansas","Una oficina de ingresos (revenue office) de Arkansas DFA","Un proveedor inscrito en el FMCSA Training Provider Registry (TPR)","Únicamente una orientación interna del empleador"],"explanation":"ELDT requiere que los solicitantes de Class A/B por primera vez y los solicitantes del endoso P, S o H completen la capacitación con un proveedor inscrito en el FMCSA Training Provider Registry antes del examen administrado por el estado; para H la capacitación es solo teórica antes del examen de conocimientos, mientras que Class A/B, P y S requieren teoría más práctica al volante antes del examen de habilidades. Fuente: regla ELDT de la FMCSA (49 CFR Part 380), vigente desde el 7 de febrero de 2022; FMCSA Training Provider Registry."},"39":{"q":"Al solicitar una CDL de Arkansas, un conductor debe autocertificarse en una de las cuatro categorías de certificación médica. ¿Cuál de las siguientes es una de esas cuatro categorías?","options":["Interestatal recreativo","Interestatal exento de hazmat","Intraestatal provisional","Interestatal no exceptuado (Non-excepted interstate)"],"explanation":"Los conductores de Arkansas deben autocertificarse en una de cuatro categorías: Interestatal no exceptuado, Interestatal exceptuado, Intraestatal no exceptuado o Intraestatal exceptuado. Los conductores interestatales no exceptuados deben mantener un certificado de examinador médico federal. Fuente: Arkansas CDL Manual, Section 1.2 (Autocertificación); 49 CFR 383.71."},"40":{"q":"En Arkansas, se considera que una persona conduce un vehículo motorizado comercial (CMV) bajo los efectos del alcohol y queda sujeta a descalificación si su concentración de alcohol en la sangre (BAC) está en o por encima de qué nivel?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"Arkansas adopta el estándar federal para CMV: operar un CMV con un BAC de 0.04% o más es conducir bajo los efectos del alcohol y una infracción mayor descalificante, la mitad del límite de 0.08% para conductores no comerciales. Fuente: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"41":{"q":"Conforme a la ley de Arkansas, ¿cuál es el período mínimo de descalificación para la PRIMERA infracción mayor de un titular de CDL (como un DUI en un CMV) cuando NO transporta materiales peligrosos con rótulo (placarded)?","options":["1 year","60 days","3 years","6 months"],"explanation":"Una primera infracción mayor (DUI, BAC de 0.04+, negarse a la prueba, abandonar la escena, etc.) resulta en una descalificación de la CDL de 1 year en Arkansas. Fuente: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"42":{"q":"En Arkansas, si un conductor comete una primera infracción mayor mientras opera un CMV que transporta materiales peligrosos con rótulo (placarded), el período de descalificación aumenta a:","options":["3 years","1 year","5 years","De por vida"],"explanation":"Arkansas aumenta la descalificación por primera infracción mayor de 1 year a 3 years cuando la infracción ocurre mientras se transportan materiales peligrosos con rótulo (placarded). Fuente: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"43":{"q":"¿Cuál es el período de descalificación en Arkansas para una SEGUNDA infracción mayor cometida en un incidente separado por un titular de CDL?","options":["De por vida","10 years","3 years","5 years"],"explanation":"Una segunda infracción mayor resulta en la descalificación de por vida (permanente) de la CDL en Arkansas. Fuente: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51."},"44":{"q":"Negarse a someterse a una prueba requerida de alcohol/BAC mientras se opera un CMV en Arkansas resulta en qué descalificación por una primera ocurrencia?","options":["1 year","90 days","30 days","Sin descalificación, solo una multa"],"explanation":"Negarse a la prueba se trata como una infracción mayor, con la misma descalificación de 1 year que un DUI (3 years si se transportan materiales peligrosos con rótulo). La negativa está cubierta por la regla de consentimiento implícito de Arkansas para operadores de CMV. Fuente: Ark. Code 27-23-112; Arkansas DFA CDL/CMV Offenses; 49 CFR 383.51."},"45":{"q":"Conforme a la disposición de consentimiento implícito de Arkansas para conductores comerciales, se considera que una persona que opera un CMV en el estado ha dado su consentimiento para:","options":["La prueba de sangre, aliento u orina para detectar alcohol o sustancias controladas","Registros aleatorios del vehículo sin causa","Renunciar al derecho a una audiencia sobre cualquier descalificación","Rehabilitación anual obligatoria por drogas"],"explanation":"La regla de consentimiento implícito de Arkansas dispone que cualquier persona que conduce un CMV se considera que ha consentido la prueba de alcohol/sustancias controladas requerida para hacer cumplir las reglas de conducción con facultades disminuidas y de 0.04%. Fuente: Ark. Code 27-23-112/27-23-113; Arkansas DFA CDL/CMV Offenses."},"46":{"q":"Un titular de CDL en Arkansas a quien se le detecte o mida CUALQUIER presencia de alcohol (por debajo de 0.04%) mientras opera un CMV debe ser:","options":["Puesto fuera de servicio durante 24 horas","Descalificado por 1 year","Multado con $2,500 y descalificado por 60 days","Arrestado por DUI de inmediato"],"explanation":"El Arkansas Code 27-23-113 prohíbe operar un CMV con cualquier alcohol medido o detectado; un conductor que se encuentre en infracción es puesto fuera de servicio durante 24 horas. Una descalificación completa por DUI aplica solo en 0.04% o por encima. Fuente: Ark. Code 27-23-113."},"47":{"q":"En Arkansas, una SEGUNDA infracción de tránsito grave cometida en un incidente separado dentro de un período de 3 años resulta en descalificación por cuánto tiempo?","options":["60 days","30 days","120 days","1 year"],"explanation":"Dos infracciones de tránsito graves en incidentes separados dentro de 3 años resultan en una descalificación de 60 days en Arkansas. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"48":{"q":"Una TERCERA (o subsiguiente) infracción de tránsito grave en incidentes separados dentro de un período de 3 años resulta en qué descalificación en Arkansas?","options":["120 days","60 days","1 year","90 days"],"explanation":"Tres o más infracciones de tránsito graves en incidentes separados dentro de 3 años resultan en una descalificación de 120 days en Arkansas. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"49":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE para un titular de CDL de Arkansas (no una infracción mayor)?","options":["Exceso de velocidad, 15 mph o más por encima del límite","Conducir un CMV con un BAC de 0.04%","Abandonar la escena de un accidente en un CMV","Usar un CMV para cometer un delito grave (felony)"],"explanation":"El exceso de velocidad (15+ mph por encima del límite), la conducción imprudente, los cambios de carril indebidos/erráticos, seguir demasiado de cerca y enviar mensajes de texto/usar el teléfono de mano son infracciones de tránsito graves. Las otras opciones enumeradas son infracciones mayores. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"50":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años se requieren antes de que se active CUALQUIER período de descalificación en Arkansas?","options":["2","1","3","4"],"explanation":"Una sola infracción grave no descalifica; la primera descalificación (60 days) se activa con la segunda infracción grave dentro de 3 años, y una tercera activa 120 days. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"51":{"q":"¿Cuál es la descalificación mínima para la PRIMERA condena de un titular de CDL de Arkansas por una infracción en un cruce a nivel de ferrocarril-carretera mientras opera un CMV?","options":["60 days","30 days","120 days","1 year"],"explanation":"Una primera infracción en un cruce a nivel de ferrocarril-carretera conlleva una descalificación mínima de 60 days en Arkansas. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"52":{"q":"Una SEGUNDA infracción en un cruce a nivel de ferrocarril-carretera dentro de un período de 3 años resulta en qué descalificación mínima en Arkansas?","options":["120 days","60 days","1 year","90 days"],"explanation":"Una segunda infracción en un cruce a nivel dentro de 3 años conlleva una descalificación mínima de 120 days en Arkansas. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"53":{"q":"Una TERCERA infracción en un cruce a nivel de ferrocarril-carretera dentro de un período de 3 años resulta en qué descalificación mínima en Arkansas?","options":["1 year","120 days","180 days","60 days"],"explanation":"Una tercera infracción en un cruce a nivel dentro de 3 años conlleva una descalificación mínima de 1 year en Arkansas. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"54":{"q":"¿Qué acción es una infracción en un cruce a nivel de ferrocarril-carretera que puede descalificar a un titular de CDL de Arkansas?","options":["No tener espacio suficiente para conducir completamente a través del cruce sin detenerse","Conducir 5 mph por encima del límite cerca de las vías","Tocar la bocina antes de cruzar","Detenerse a más de 15 feet del riel más cercano"],"explanation":"Las infracciones en cruces a nivel incluyen no reducir la velocidad ni verificar la presencia de trenes, no detenerse cuando es requerido, no tener espacio para despejar el cruce, desobedecer los dispositivos de control de tránsito del cruce y tener una distancia al suelo insuficiente del tren de aterrizaje/chasis. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"55":{"q":"¿Cuál es el período mínimo de descalificación para la PRIMERA condena de un titular de CDL de Arkansas por violar una orden de fuera de servicio (OOS) de conductor o vehículo?","options":["180 days","60 days","1 year","90 days"],"explanation":"Una primera condena por violar una orden de fuera de servicio conlleva una descalificación mínima de 180 days (hasta 1 year) en Arkansas. Fuente: Ark. Code 27-23-112/27-23-114; Arkansas CDL manual; 49 CFR 383.51."},"56":{"q":"Una SEGUNDA condena dentro de 10 años por violar una orden de fuera de servicio resulta en qué descalificación mínima en Arkansas?","options":["2 years","180 days","1 year","5 years"],"explanation":"Una segunda violación de una orden OOS dentro de 10 años conlleva una descalificación mínima de 2 years (hasta 5 years) en Arkansas. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"57":{"q":"Además de la descalificación, un conductor condenado por violar una orden de fuera de servicio en Arkansas está sujeto a una sanción civil de al menos qué monto por una primera condena?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"Arkansas impone una sanción civil de no menos de $2,500 a un conductor por una primera violación de una orden de fuera de servicio (y de no menos de $5,000 por una segunda), además de la descalificación. Fuente: Ark. Code 27-23-114."},"58":{"q":"Conforme a las reglas de Arkansas y federales, ¿cómo se trata para fines de descalificación el uso por parte de un conductor de CDL de un teléfono móvil de mano o el envío de mensajes de texto mientras conduce un CMV?","options":["Como una infracción de tránsito grave que, en caso de infracciones repetidas, puede llevar a la descalificación","Como una infracción mayor con una descalificación de 1 year","Como una infracción descalificante de por vida","No conlleva ninguna consecuencia de descalificación, solo una citación"],"explanation":"Enviar mensajes de texto o usar un teléfono de mano mientras se conduce un CMV es una infracción de tránsito grave; varias condenas cuentan para la descalificación de 2 infracciones (60 days) / 3 infracciones (120 days), con multas de hasta $2,750 para los conductores. Fuente: Arkansas CDL manual; Ark. Code 27-51-1504; FMCSA 49 CFR 383.51/392.80-82."},"59":{"q":"Un titular de CDL de Arkansas que usa un CMV en la comisión de un delito grave (felony) que involucra la fabricación, distribución o dispensación de una sustancia controlada enfrenta qué descalificación?","options":["De por vida, sin posibilidad de reinstalación","1 year","3 years","10 years"],"explanation":"Usar un CMV para fabricar, distribuir o dispensar sustancias controladas es una infracción mayor que conlleva una descalificación obligatoria de por vida sin reinstalación, distinta de otras prohibiciones de por vida que pueden permitir la reinstalación después de 10 años. Fuente: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51."},"60":{"q":"En Arkansas, cuando un autobús o un vehículo que transporta materiales peligrosos con carteles (placards) debe detenerse en un cruce de ferrocarril con carretera, ¿a qué distancia del riel más cercano debe detenerse?","options":["A no menos de 15 pies y no más de 50 pies","A no menos de 10 pies y no más de 40 pies","A no menos de 25 pies y no más de 75 pies","A no menos de 5 pies y no más de 15 pies"],"explanation":"Arkansas exige que los autobuses y los vehículos de HazMat con carteles (placards) se detengan a no menos de 15 pies y no más de 50 pies del riel más cercano, donde el conductor tiene la mejor visibilidad de las vías. Fuente: Manual de Licencia de Conducir Comercial de Arkansas, Secciones 2.15, 4.3.5 y 9."},"61":{"q":"Bajo la ley de \"Move Over\" (cámbiese de carril) de Arkansas, ¿qué debe hacer un conductor en una carretera de varios carriles al acercarse a un vehículo autorizado detenido con luces intermitentes?","options":["Detenerse por completo hasta que el vehículo autorizado se mueva","Cambiarse al carril más alejado posible del vehículo detenido hasta haberlo pasado de forma segura","Mantener la velocidad indicada y tocar la bocina al pasar","Cambiarse al carril más cercano al vehículo detenido para mantener el flujo del tráfico"],"explanation":"El Código de Arkansas 27-51-310 exige que los conductores en una carretera de varios carriles se cambien al carril o posición más alejada posible del vehículo autorizado detenido y permanezcan allí hasta haberlo pasado de forma segura. Fuente: Ark. Code Ann. 27-51-310 (ley de Move Over)."},"62":{"q":"En una carretera de Arkansas de acceso no controlado, ¿cuál es la velocidad máxima permitida por ley para un camión con capacidad de una tonelada y media o más?","options":["55 mph","60 mph","50 mph","65 mph"],"explanation":"Arkansas establece un máximo de 50 mph para camiones con capacidad de una tonelada y media o más en carreteras que no son de acceso controlado, en comparación con 60 mph para otros vehículos en esos mismos lugares. Fuente: Ark. Code Ann. 27-51-201."},"63":{"q":"En Arkansas, cuando un autobús escolar se detiene en una carretera de dos carriles y enciende sus luces de advertencia rojas intermitentes para recoger o dejar pasajeros, ¿qué conductores deben detenerse?","options":["Solo los conductores que viajan detrás del autobús en la misma dirección","Solo los conductores en el carril que está justo al lado del autobús","Solo los conductores que estén a menos de 100 pies del autobús","Los conductores que se aproximan o que adelantan al autobús desde cualquier dirección"],"explanation":"En una carretera de dos carriles, el Código de Arkansas 27-51-1004 exige que todo conductor que se aproxime o que adelante al autobús desde cualquier dirección se detenga por completo mientras las luces rojas estén intermitentes. Fuente: Ark. Code Ann. 27-51-1004."},"64":{"q":"¿Qué ley de Arkansas de 2021 restringe el uso del carril más a la izquierda en una carretera de varios carriles únicamente para rebasar?","options":["Act 1054 of 2007","Act 1090 of 2021","Act 27 of 2021","Act 310 of 2019"],"explanation":"La Act 1090 of 2021 reserva el carril más a la izquierda para rebasar en carreteras de varios carriles; salvo cuando hay carriles bloqueados, los conductores deben usar los carriles de la derecha para circular. Fuente: Act 1090 of 2021; aviso público de ARDOT sobre la Left Lane Driving Law (Ley de Conducción en el Carril Izquierdo)."},"65":{"q":"Si un vehículo comercial debe detenerse en el acotamiento de una carretera de Arkansas, ¿dentro de cuánto tiempo debe el conductor colocar los dispositivos de advertencia de emergencia (triángulos reflectantes)?","options":["Dentro de 5 minutos","Dentro de 15 minutos","Dentro de 10 minutos","Dentro de 30 minutos"],"explanation":"Un conductor que deba detenerse en la carretera o en el acotamiento debe colocar los dispositivos de advertencia de emergencia dentro de 10 minutos. Fuente: Manual de Licencia de Conducir Comercial de Arkansas, Sección 2.5 (Comunicación)."},"66":{"q":"En una carretera de Arkansas de un solo sentido o dividida, ¿dónde debe colocar sus tres triángulos de advertencia un vehículo comercial detenido?","options":["A 10 pies, 100 pies y 100 pies a cada lado","A 25 pies, 100 pies y 300 pies hacia el tráfico que se aproxima","A 50 pies, 150 pies y 250 pies hacia el tráfico que se aproxima","A 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima"],"explanation":"En una carretera de un solo sentido o dividida, los triángulos se colocan a 10 pies, 100 pies y 200 pies del vehículo hacia el tráfico que se aproxima. Fuente: Manual de Licencia de Conducir Comercial de Arkansas, Sección 2.5."},"67":{"q":"¿Cuál grupo de vehículos NO está entre los \"vehículos autorizados\" cubiertos por la ley de Move Over de Arkansas (Ark. Code 27-51-310)?","options":["Cualquier automóvil particular de pasajeros con sus luces intermitentes de emergencia (4-way) encendidas","Grúas de remolque que están realizando una operación de remolque","Vehículos del Departamento de Transporte de Arkansas","Vehículos de compañías de servicios públicos que muestran luces intermitentes"],"explanation":"La ley de Move Over de Arkansas cubre a los vehículos de respuesta a emergencias, de las fuerzas del orden, de ARDOT, de contratistas de ARDOT, de servicios públicos y de remolque que muestran luces intermitentes o giratorias; un automóvil particular común que solo usa sus luces intermitentes de emergencia no es un \"vehículo autorizado\". Fuente: Ark. Code Ann. 27-51-310."},"68":{"q":"En una carretera de Arkansas de acceso no controlado, ¿cuánto más alto es el límite general de velocidad para los automóviles de pasajeros que para los camiones con capacidad de una tonelada y media o más?","options":["5 mph más alto (55 mph frente a 50 mph)","15 mph más alto (65 mph frente a 50 mph)","10 mph más alto (60 mph frente a 50 mph)","No hay diferencia; ambos son 55 mph"],"explanation":"Arkansas permite 60 mph para otros vehículos pero solo 50 mph para camiones pesados en carreteras de acceso no controlado, una diferencia de 10 mph. Fuente: Ark. Code Ann. 27-51-201."},"69":{"q":"Bajo la ley de autobuses escolares de Arkansas, ¿en qué tipo de vía NO se exige que los conductores que circulan en sentido contrario se detengan ante un autobús escolar que recoge o deja niños?","options":["Una carretera de dos carriles","Una carretera de dos carriles con un carril central de giro","Una carretera de cuatro carriles sin mediana","Una carretera dividida de cuatro o más carriles con separación por mediana"],"explanation":"Arkansas exige que todo el tráfico en ambas direcciones se detenga, excepto en una carretera dividida de cuatro o más carriles con separación por mediana, donde solo debe detenerse el tráfico que va detrás del autobús. Un carril central de giro no es una mediana. Fuente: Ark. Code Ann. 27-51-1004; orientación oficial de la ley de seguridad de autobuses escolares de Arkansas."},"70":{"q":"¿Cuánto exige la ley de Arkansas que la velocidad máxima de los camiones pesados (1.5 toneladas o más) se fije por debajo de la máxima para automóviles en carreteras de acceso controlado?","options":["10 mph por debajo de la máxima para automóviles","5 mph por debajo de la máxima para automóviles","15 mph por debajo de la máxima para automóviles","La misma que la máxima para automóviles"],"explanation":"El Ark. Code 27-51-201 dispone que la velocidad máxima permitida para camiones con capacidad de una tonelada y media o más en carreteras de acceso controlado se fije 10 mph por debajo de la máxima para automóviles (por ejemplo, 70 mph para camiones donde los autos pueden circular a 75). Fuente: Ark. Code Ann. 27-51-201."},"71":{"q":"¿Cuál restricción de carril distintiva de Arkansas está señalizada en ciertas Interestatales de seis carriles como \"Trucks Use Right 2 Lanes\" (los camiones usan los 2 carriles de la derecha)?","options":["Todos los camiones deben circular únicamente en el carril central en todo momento","Los vehículos con más de dos ejes no pueden usar el carril más a la izquierda en las Interestatales de seis carriles designadas","Los camiones tienen prohibido el acceso a las Interestatales por completo entre las 7 a.m. y las 9 a.m.","Los camiones deben usar el carril izquierdo para mantener libres los carriles de la derecha para incorporaciones"],"explanation":"La Act 1054 of 2007 modificó el Ark. Code 27-65-107(a) para mantener a los vehículos con más de dos ejes fuera del carril más a la izquierda en las Interestatales de seis carriles designadas, señalizadas como \"Trucks Use Right 2 Lanes\". Fuente: Act 1054 of 2007; Ark. Code Ann. 27-65-107(a)."},"72":{"q":"En Arkansas, si cambiar de carril es inseguro o imposible al acercarse a un vehículo autorizado detenido, ¿qué exige la ley de Move Over?","options":["Detenerse por completo sobre la carretera hasta que el vehículo autorizado se retire","Continuar a la velocidad indicada ya que no es posible cambiar de carril","Orillarse al acotamiento detrás del vehículo autorizado y esperar","Reducir la velocidad, proceder con precaución y mantener una velocidad reducida a lo largo de la zona"],"explanation":"Cuando no es posible un cambio de carril seguro, el Ark. Code 27-51-310 exige que el conductor reduzca la velocidad, proceda con precaución y mantenga una velocidad reducida apropiada a las condiciones de la carretera a lo largo de la zona donde el vehículo autorizado está detenido. Fuente: Ark. Code Ann. 27-51-310."},"73":{"q":"¿Cuál es el ancho máximo legal de un vehículo o carga en Arkansas antes de que se requiera un permiso de sobredimensión?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"El ancho máximo legal de Arkansas en el Sistema de Carreteras Estatales es de 8 feet 6 inches; cualquier cosa más ancha requiere un permiso de sobredimensión. Fuente: Reglas de Permisos de ARDOT para el Movimiento de Vehículos Sobredimensionados y con Sobrepeso."},"74":{"q":"En una carretera de Arkansas de dos carriles que lleva tráfico en ambas direcciones, ¿dónde debe colocar sus triángulos de advertencia un CMV detenido?","options":["A 10 pies, 100 pies y 200 pies únicamente hacia la parte trasera","A menos de 10 pies del vehículo, y a 100 pies detrás y a 100 pies delante de él","A 25 pies detrás y a 25 pies delante del vehículo únicamente","A 100 pies detrás únicamente, sin colocar ninguno adelante"],"explanation":"En una carretera de dos carriles y doble sentido (sin dividir), coloque un triángulo a menos de 10 pies del vehículo, uno a 100 pies detrás y uno a 100 pies delante. Fuente: Manual de Licencia de Conducir Comercial de Arkansas, Sección 2.5."},"75":{"q":"¿Cuál es la altura máxima legal de un vehículo en el Sistema de Carreteras Estatales de Arkansas antes de que se requiera un permiso?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"explanation":"La altura máxima legal de Arkansas es de 13 feet 6 inches; las cargas que la excedan requieren un permiso de sobredimensión. Fuente: Reglas de Permisos de ARDOT para el Movimiento de Vehículos Sobredimensionados y con Sobrepeso."},"76":{"q":"¿Qué tamaño de banderas rojas exige Arkansas en las esquinas traseras de una carga con permiso por sobreancho o sobrelargo?","options":["Banderas rojas de 12 pulgadas","Banderas rojas de 24 pulgadas","Banderas rojas de 6 pulgadas","Banderas rojas de 18 pulgadas"],"explanation":"Arkansas exige banderas rojas de 18 pulgadas en las esquinas traseras inferiores de las cargas sobreanchas y sobrelargas, junto con letreros de OVERSIZE LOAD (CARGA SOBREDIMENSIONADA) al frente y atrás. Fuente: Reglas de Permisos de ARDOT para el Movimiento de Vehículos Sobredimensionados y con Sobrepeso."},"77":{"q":"En Arkansas, ¿cuál es la velocidad máxima a la que se puede conducir un vehículo que remolca una casa prefabricada o móvil?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"Las reglas de permisos de Arkansas prohíben conducir un vehículo que remolca una casa prefabricada o móvil a más de 55 mph. Fuente: Code of Arkansas Rules 111-109 / Reglas de Permisos de ARDOT (movimiento de cargas sobredimensionadas/con sobrepeso)."},"78":{"q":"Las sanciones de Arkansas por rebasar ilegalmente un autobús escolar detenido que está recogiendo o dejando niños incluyen una multa dentro de qué rango?","options":["Una multa fija de $100 sin cárcel","No menos de $500 ni más de $5,000","No menos de $250 ni más de $1,000","No menos de $50 ni más de $250"],"explanation":"El Ark. Code 27-51-1001 establece la multa por rebasar un autobús escolar detenido en no menos de $250 ni más de $1,000, con posible cárcel, suspensión de licencia y servicio comunitario. Fuente: Ark. Code Ann. 27-51-1001."},"79":{"q":"Al detenerse en un cruce de ferrocarril con carretera en Arkansas, ¿cuál de las siguientes acciones también debe realizar un conductor comercial antes de cruzar?","options":["Encender las luces intermitentes de emergencia (4-way) y usar un carril de salida (pullout) si está disponible","Tocar la bocina de forma continua hasta que el vehículo haya cruzado las vías","Cambiar a una marcha más alta para librar las vías más rápido","Detenerse directamente sobre el riel más cercano para maximizar la visibilidad de las vías"],"explanation":"Cuando se requiere una parada en un cruce a nivel, el manual de Arkansas indica a los conductores que vigilen el tráfico detrás mientras se detienen de forma gradual, que usen un carril de salida (pullout) si está disponible y que enciendan las luces intermitentes de emergencia (4-way); no cambie de marcha mientras cruza. Fuente: Manual de Licencia de Conducir Comercial de Arkansas, Sección 2.15.4."},"80":{"q":"¿Cuál agencia estatal es responsable de emitir las Licencias de Conducir Comerciales (CDL) en Arkansas?","options":["La División de Seguridad Vial de la Policía Estatal de Arkansas","El Departamento de Transporte de Arkansas (ARDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Arkansas Department of Finance and Administration (DFA), Office of Driver Services"],"explanation":"Las CDL en Arkansas son emitidas por el Department of Finance and Administration (DFA), Office of Driver Services, que administra y hace cumplir la ley de licencias de conducir. Fuente: páginas de Arkansas DFA Office of Driver Services / CDL (dfa.arkansas.gov)."},"81":{"q":"En Arkansas, ¿quién suele administrar el examen de habilidades (de manejo en carretera) de la CDL?","options":["Cualquier empleado de la oficina local de ingresos durante la cita de solicitud","La Policía Estatal de Arkansas en lugares de examen designados, o un examinador externo aprobado","El personal de las estaciones de pesaje del Departamento de Transporte de Arkansas","Únicamente las escuelas privadas de CDL que emiten la licencia directamente"],"explanation":"Si bien el DFA emite la licencia, los exámenes de habilidades de la CDL se administran en lugares de examen designados de la Policía Estatal de Arkansas o por examinadores externos aprobados. Fuente: información de exámenes de CDL de Arkansas DFA Driver Services / Policía Estatal de Arkansas."},"82":{"q":"Antes de que un solicitante pueda tomar el examen de habilidades de la CDL en Arkansas, primero debe obtener cuál credencial?","options":["Un endoso de licencia de operador Clase D","Un número federal de autoridad de operación interestatal","Un Permiso de Aprendiz Comercial (CLP)","Un permiso comercial temporal de carretera de 30 días"],"explanation":"Un solicitante primero debe poseer un Permiso de Aprendiz Comercial (CLP) antes de tomar el examen de habilidades de la CDL en Arkansas. Fuente: página de CLP de Arkansas DFA (dfa.arkansas.gov)."},"83":{"q":"Bajo las reglas de Arkansas, ¿durante cuánto tiempo debe un solicitante poseer un Permiso de Aprendiz Comercial (CLP) antes de que se le permita tomar el examen de habilidades de la CDL?","options":["Al menos 14 days después de la emisión inicial del CLP","Al menos 30 days después de la emisión inicial del CLP","Al menos 7 days después de la emisión inicial del CLP","Al menos 60 days después de la emisión inicial del CLP"],"explanation":"Arkansas, siguiendo el estándar federal de la CDL, prohíbe tomar el examen de habilidades durante los primeros 14 days posteriores a la emisión inicial del CLP. Fuente: página de CLP de Arkansas DFA (estándar 49 CFR 383.25 adoptado por Arkansas)."},"84":{"q":"¿Cuál es el período máximo durante el cual un Permiso de Aprendiz Comercial (CLP) permanece válido en Arkansas antes de que deban repetirse los exámenes de conocimientos?","options":["Hasta dos años desde la emisión","Hasta un año desde la emisión","Hasta 90 days desde la emisión","Hasta cuatro años desde la emisión"],"explanation":"El CLP es válido hasta por un año; si vence, el titular debe repetir el examen general de conocimientos y los de cualquier endoso antes de que se pueda emitir un nuevo permiso. Fuente: página de CLP de Arkansas DFA (en consonancia con 49 CFR 383.25)."},"85":{"q":"Un nuevo solicitante que busca una CDL Clase A por primera vez en Arkansas debe completar cuál capacitación exigida a nivel federal antes de tomar el examen de conocimientos para el proceso de CLP a CDL?","options":["Un curso estatal con certificado de manejo defensivo","Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor registrado ante la FMCSA","Una certificación de primeros auxilios del National Safety Council","Un aprendizaje patrocinado por el empleador con duración de 12 meses"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de CDL por primera vez deben completar la Capacitación para Conductores de Nivel Inicial (ELDT) a través de un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes de presentar el examen. Arkansas verifica la finalización a través del registro. Fuente: regla de ELDT de la FMCSA / información de CDL de Arkansas DFA."},"86":{"q":"La finalización de la capacitación teórica de ELDT se reporta a cuál sistema que el Arkansas DFA verifica antes de emitir una CDL?","options":["Únicamente el portal MyDMV de Arkansas DFA","El Registro Nacional de Conductores (NDR)","Únicamente el Sistema de Información de Licencias de Conducir Comerciales (CDLIS)","El Registro de Proveedores de Capacitación (TPR) de la FMCSA"],"explanation":"Los proveedores de capacitación reportan la finalización de la ELDT al Registro de Proveedores de Capacitación (TPR) de la FMCSA; la agencia estatal de licencias, incluida Arkansas DFA, verifica el TPR antes de permitir el examen de habilidades o de emitir la CDL. Fuente: Registro de Proveedores de Capacitación de la FMCSA (tpr.fmcsa.dot.gov)."},"87":{"q":"La ELDT se exige en Arkansas para un solicitante por primera vez en todas las siguientes situaciones, EXCEPTO:","options":["Obtener una CDL Clase A o Clase B por primera vez","Mejorar una CDL Clase B existente a una CDL Clase A","Renovar una CDL Clase A existente sin nuevos endosos","Obtener un endoso de materiales peligrosos (H) por primera vez"],"explanation":"La ELDT aplica a las CDL Clase A/B por primera vez, a las mejoras de B a A y a los endosos S, P o H por primera vez. Una simple renovación de una CDL existente sin un nuevo endoso no activa la ELDT. Fuente: regla de ELDT de la FMCSA (49 CFR Part 380) según se aplica en Arkansas."},"88":{"q":"El examen de habilidades de la CDL en Arkansas consta de cuáles tres partes, en el orden en que generalmente se realizan?","options":["Conocimientos escritos, examen de la vista y manejo en carretera","Revisión de frenos de aire, manejo de materiales peligrosos y manejo en carretera","Inspección previetaje (pre-trip), control básico del vehículo y manejo en carretera","Control básico del vehículo, examen de conocimientos e inspección previaje (pre-trip)"],"explanation":"El examen de habilidades de la CDL de Arkansas tiene tres partes: la inspección del vehículo previa al viaje (pre-trip), las habilidades de control básico del vehículo y el examen de manejo en carretera. Fuente: información del examen de habilidades de CDL de Arkansas DFA / Policía Estatal de Arkansas (49 CFR 383.113)."},"89":{"q":"Durante la parte de control básico del vehículo del examen de habilidades de la CDL de Arkansas, el examinador evalúa principalmente la capacidad del solicitante de:","options":["Maniobrar y dar reversa con el vehículo de forma precisa en un área reducida","Recitar de memoria los límites federales de horas de servicio","Calcular la clasificación de peso bruto combinado del vehículo","Demostrar la colocación de bengalas de emergencia al borde de la carretera"],"explanation":"El control básico del vehículo evalúa la capacidad del conductor de controlar y posicionar el vehículo mediante maniobras como dar reversa en línea recta, dar reversa con desplazamiento lateral (offset) y estacionarse en un área reducida. Fuente: estándares del examen de habilidades de Arkansas DFA / FMCSA (49 CFR 383.113)."},"90":{"q":"Las reglas federales de certificación médica adoptadas por Arkansas exigen que todo titular de CLP y CDL se autocertifique en cuántas categorías posibles de operación?","options":["Dos categorías","Cuatro categorías","Tres categorías","Seis categorías"],"explanation":"Todo titular de CLP/CDL debe autocertificarse en una de cuatro categorías según la operación interestatal frente a la intraestatal y el estatus de exceptuado frente a no exceptuado. Fuente: página de Certificación Médica de Arkansas DFA (49 CFR 383.71)."},"91":{"q":"¿Cuál categoría de autocertificación exige que el conductor cumpla con los estándares federales de calificación física del DOT y porte un certificado de examinador médico?","options":["Excepted Interstate","Excepted Intrastate","Non-Excepted Interstate","Pasatiempo / Solo Uso Personal"],"explanation":"Un conductor que se autocertifica como Non-Excepted Interstate debe cumplir con los estándares federales de calificación física del DOT (49 CFR 391) y mantener un certificado de examinador médico válido. Fuente: página de Certificación Médica de Arkansas DFA (49 CFR 383.71)."},"92":{"q":"Un conductor que opera únicamente dentro de Arkansas y que NO está sujeto a los requisitos federales de calificación física se autocertificaría con mayor precisión como:","options":["Non-Excepted Interstate","Excepted Intrastate","Excepted Interstate","Non-Excepted Federal"],"explanation":"Un conductor que opera únicamente dentro del estado y que no está obligado a cumplir con los estándares federales de calificación física se autocertifica como Excepted Intrastate. Fuente: página de Certificación Médica de Arkansas DFA (49 CFR 383.71)."},"93":{"q":"Cuando un solicitante de CDL en Arkansas se autocertifica como Non-Excepted Interstate, el examinador médico del DOT que realiza el examen físico debe:","options":["Estar empleado por la unidad médica de la Policía Estatal de Arkansas","Ser cualquier farmacéutico con licencia en el condado de residencia del solicitante","Ser aprobado individualmente por el gerente de la oficina local de ingresos","Estar incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA"],"explanation":"Los conductores no exceptuados deben obtener su examen físico de un examinador médico incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA, y ese certificado se presenta a la Office of Driver Services. Fuente: página de Certificación Médica de Arkansas DFA (49 CFR 391.41 / Registro Nacional)."},"94":{"q":"¿Cuál de las siguientes es una forma aceptada de presentar un Certificado de Examinador Médico del DOT y una Declaración Jurada de Autocertificación a la Arkansas Office of Driver Services?","options":["Publicarlo directamente en el sitio web del Registro Nacional de la FMCSA","Entregarlo a un agente de la Policía Estatal de Arkansas al borde de la carretera en cualquier parada de tráfico","Llevarlo en persona a cualquier oficina de ingresos de Arkansas, o enviarlo por correo electrónico/fax a la Office of Driver Services","Subirlo únicamente al portal privado del empleador de transporte del solicitante"],"explanation":"Arkansas acepta el certificado médico y la autocertificación en persona en cualquier oficina estatal de ingresos, por correo a la Office of Driver Services, o por los canales de correo electrónico/fax que publica el DFA. Fuente: páginas de Certificación Médica / Registro de Certificado Médico de Arkansas DFA."},"95":{"q":"¿Qué ocurre con los privilegios comerciales de un titular de CDL no exceptuado de Arkansas si su certificado de examinador médico del DOT vence y no se presenta uno nuevo?","options":["La CDL se cambia a un estatus de \"Not Certified\" y se pierden los privilegios de manejo comercial","Nada cambia hasta que venza el término completo de la CDL años después","La CDL se degrada automáticamente a un CLP por un año","Se multa al conductor pero conserva todos los privilegios comerciales"],"explanation":"No proporcionar una tarjeta médica vigente antes de su vencimiento coloca la CDL en un estatus médico de \"Not Certified\", eliminando los privilegios de manejo comercial hasta que se presente un certificado válido. Fuente: página de Certificación Médica de Arkansas DFA."},"96":{"q":"Al renovar una CDL en Arkansas, un conductor no exceptuado debe presentar normalmente todo lo siguiente, EXCEPTO:","options":["Un nuevo certificado de Capacitación para Conductores de Nivel Inicial (ELDT) para la clase existente","Su licencia de conducir actual","Una Declaración Jurada de Autocertificación completada","Un Certificado de Examinador Médico vigente"],"explanation":"Renovar una CDL existente de la misma clase sin un nuevo endoso no requiere ELDT; el conductor sí necesita su licencia actual, una declaración jurada de autocertificación y (si es no exceptuado) un certificado médico vigente. Fuente: requisitos de renovación de Arkansas DFA Driver Services / regla de ELDT de la FMCSA."},"97":{"q":"¿Cuál es la edad mínima para obtener una CDL de Arkansas limitada al manejo comercial intraestatal (dentro del estado)?","options":["18 años","21 años","19 años","16 años"],"explanation":"Arkansas permite una CDL para operación intraestatal a los 18 años; la operación interestatal exige que el conductor tenga 21 años. Fuente: requisitos de CDL de Arkansas DFA (estándares de edad de 49 CFR 383 / 391)."},"98":{"q":"Con respecto a las tarifas de solicitud de la CDL en Arkansas, ¿cuál afirmación refleja la expectativa correcta orientada al proceso?","options":["La solicitud y el examen de la CDL siempre son gratuitos en Arkansas","La tarifa está fijada permanentemente por la ley federal y nunca cambia","Solo el endoso de materiales peligrosos tiene alguna tarifa; todos los demás servicios de CDL son gratuitos","Las tarifas las fija el estado y pueden cambiar, por lo que los solicitantes deben confirmar el monto actual con el DFA antes de presentar la solicitud"],"explanation":"Las tarifas de CDL de Arkansas (licencia, endoso y examen) las fija el estado y están sujetas a cambios, por lo que los solicitantes deben verificar los montos actuales con el DFA en lugar de basarse en una cifra fija. Fuente: tarifario de Arkansas DFA Driver Services (sujeto a cambios)."}},"hi":{"0":{"q":"अर्कांसस के राजमार्गों पर, विशेष परमिट की आवश्यकता होने से पहले किसी वाहन (भार के साथ या बिना) की अधिकतम कुल बाहरी चौड़ाई कितनी होती है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Arkansas Code Ann. 27-35-206 किसी वाहन की अधिकतम कानूनी चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है, चाहे वह बिना भार के हो या भार के साथ; इससे अधिक चौड़े किसी भी वाहन के लिए ARDOT/Arkansas Highway Police से ओवरसाइज़ परमिट की आवश्यकता होती है।"},"1":{"q":"वर्तमान अर्कांसस कानून के अनुसार, बिना विशेष परमिट के राज्य राजमार्गों पर किसी वाहन (उसके भार सहित) की अधिकतम ऊँचाई कितनी अनुमत है?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"Arkansas Code Ann. 27-35-207, जैसा कि Act 871 of 2021 (28 जुलाई 2021 से प्रभावी) द्वारा संशोधित किया गया, ने कानूनी ऊँचाई सीमा को 13'6\" से बढ़ाकर 14 feet कर दिया। 14 feet से अधिक ऊँचाई वाले वाहन के लिए विशेष (अधिक-ऊँचाई) परमिट की आवश्यकता होती है।"},"2":{"q":"अर्कांसस के राजमार्गों पर बिना ओवरवेट परमिट के किसी वाहन या संयोजन का अधिकतम सकल भार कितना अनुमत है?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"संघीय मानक और Arkansas Code Ann. 27-35-203 के अनुरूप, अधिकतम कानूनी सकल भार 80,000 pounds है। इससे अधिक होने पर ARDOT/Arkansas Highway Police Permit Section से ओवरवेट परमिट की आवश्यकता होती है।"},"3":{"q":"अर्कांसस में, बिना परमिट के एक एकल धुरी (single axle) पर अधिकतम कितना भार ले जाया जा सकता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Arkansas Code Ann. 27-35-203 एकल धुरी को 20,000 pounds तक सीमित करता है। यह अर्कांसस के राजमार्गों पर लागू संघीय एकल-धुरी सीमा से मेल खाता है।"},"4":{"q":"अर्कांसस में बिना परमिट के एक टैंडम धुरी समूह (tandem axle group) पर अधिकतम कानूनी भार कितना होता है?","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"explanation":"Arkansas Code Ann. 27-35-203 एक टैंडम धुरी को 34,000 pounds तक सीमित करता है। (परमिट के साथ, एक टैंडम 46,000 pounds तक पहुँच सकता है, लेकिन बिना परमिट के अधिकतम सीमा 34,000 है।)"},"5":{"q":"Arkansas Code 27-35-203 के अंतर्गत, दो लगातार धुरियों को 'टैंडम धुरी' (tandem axle) तब माना जाता है जब उनके केंद्रों के बीच की दूरी हो:","options":["More than 40 inches but not more than 96 inches","More than 96 inches but not more than 120 inches","Exactly 48 inches","Less than 40 inches"],"explanation":"Arkansas Code Ann. 27-35-203 एक टैंडम धुरी को दो या अधिक लगातार धुरियों के रूप में परिभाषित करता है जिनके केंद्र more than 40 inches और not more than 96 inches की दूरी पर हों, जिनकी संयुक्त सीमा 34,000 pounds हो।"},"6":{"q":"अर्कांसस के राजमार्गों पर बिना परमिट के संचालित एकल (सीधे) ट्रक की अधिकतम लंबाई कितनी होती है?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Arkansas Code Ann. 27-35-208 एकल (सीधे) वाहन की कुल लंबाई को 40 feet तक सीमित करता है, चाहे वह बिना भार के हो या भार के साथ।"},"7":{"q":"अर्कांसस के राजमार्गों पर, ट्रक ट्रैक्टर के साथ संयोजन में संचालित होने वाले सेमीट्रेलर की वह अधिकतम लंबाई कितनी है जिससे कम राज्य प्रतिबंध नहीं लगा सकता?","options":["48 feet","50 feet","53 feet 6 inches","57 feet"],"explanation":"Arkansas Code Ann. 27-35-208 यह प्रावधान करता है कि राज्य किसी ट्रक ट्रैक्टर के साथ संयोजन में संचालित इकाई पर 53 feet 6 inches से कम की सेमीट्रेलर/ट्रेलर लंबाई सीमा नहीं लगाएगा।"},"8":{"q":"अर्कांसस के राजमार्गों पर ट्रक-ट्रैक्टर-सेमीट्रेलर-ट्रेलर (ट्विन/डबल) संयोजन में, प्रत्येक पिछली इकाई की अधिकतम लंबाई कितनी होती है?","options":["24 feet","28 feet","33 feet","40 feet"],"explanation":"Arkansas Code Ann. 27-35-208 ट्रक-ट्रैक्टर-सेमीट्रेलर-ट्रेलर (डबल) संयोजन में प्रत्येक सेमीट्रेलर या ट्रेलर को कुल लंबाई 28 feet तक सीमित करता है, कपलिंग उपकरणों को छोड़कर।"},"9":{"q":"अर्कांसस किस फॉर्मूले का उपयोग धुरियों के समूह के बीच की दूरी के सापेक्ष उस समूह पर अधिकतम अनुमेय भार निर्धारित करने के लिए करता है?","options":["The Federal Bridge Formula (Formula B)","The Arkansas Tare Weight Formula","The Gross Combination Ratio Rule","The Tandem Spacing Multiplier"],"explanation":"अर्कांसस Federal Bridge Formula (Bridge Formula B), W = 500[LN/(N-1) + 12N + 36], लागू करता है ताकि धुरियों की संख्या (N) और उनके बीच की दूरी (L) के आधार पर किसी दिए गए धुरी समूह द्वारा वहन किए जा सकने वाले अधिकतम भार को निर्धारित किया जा सके।"},"10":{"q":"अर्कांसस में लागू Federal Bridge Formula में, W = 500[LN/(N-1) + 12N + 36], 'N' क्या दर्शाता है?","options":["The number of axles in the group being considered","The net (tare) weight of the vehicle","The number of tires on the drive axle","The nominal speed limit of the highway"],"explanation":"अर्कांसस द्वारा उपयोग किए जाने वाले Federal Bridge Formula में, N विचाराधीन समूह में धुरियों की संख्या है, L समूह की बाहरी धुरियों के बीच की दूरी (फीट में) है, और W अधिकतम अनुमेय भार है।"},"11":{"q":"एक ट्रक चालक का भार 9 feet 2 inches चौड़ा है। अर्कांसस के राजमार्गों पर यह भार:","options":["Is legal because it is under 10 feet","Requires an oversize permit because it exceeds 102 inches","Is legal only on the Interstate system","Requires only a flag, not a permit"],"explanation":"Code 27-35-206 के अनुसार अर्कांसस की कानूनी चौड़ाई 102 inches (8'6\") है। एक 9'2\" भार (110 inches) कानूनी चौड़ाई से अधिक है और इसके लिए ARDOT/Arkansas Highway Police से ओवरसाइज़ परमिट की आवश्यकता होती है।"},"12":{"q":"Arkansas State Highway System के लिए ओवरसाइज़ और ओवरवेट संचलन परमिट कौन सी एजेंसी जारी करती है?","options":["The Arkansas Department of Finance and Administration","The Arkansas Department of Transportation through the Arkansas Highway Police Permit Section","The county sheriff in each county of travel","The Federal Motor Carrier Safety Administration"],"explanation":"ARDOT 2023 Permit Rules के अंतर्गत, State Highway System के लिए ओवरसाइज़/ओवरवेट परमिट Arkansas Department of Transportation द्वारा Arkansas Highway Police Permit Section के माध्यम से जारी किए जाते हैं।"},"13":{"q":"अर्कांसस में किसी मोटर वाहक को ओवरवेट परमिट की आवश्यकता कब होती है?","options":["Only when the load can be reduced by splitting it","When the vehicle exceeds the legal gross, single-axle, or tandem-axle weight limits","Any time the trip crosses a county line","Only when traveling at night"],"explanation":"ARDOT Permit Rules और Code 27-35-203/210 के अनुसार, ओवरवेट परमिट तब आवश्यक होता है जब कोई वाहन कानूनी सीमाओं (80,000 lbs सकल, 20,000 lbs एकल धुरी, या 34,000 lbs टैंडम, या एक ब्रिज-फॉर्मूला सीमा) से अधिक हो। ऐसे परमिट आमतौर पर केवल अविभाज्य भार के लिए जारी किए जाते हैं।"},"14":{"q":"अर्कांसस में ओवरवेट परमिट आमतौर पर केवल उन्हीं भारों के लिए जारी किए जाते हैं जो हैं:","options":["Divisible into smaller legal loads","Nondivisible (cannot reasonably be reduced to legal weight)","Carried at less than 45 mph","Owned by a government agency"],"explanation":"ARDOT Permit Rules के अंतर्गत, ओवरवेट परमिट अविभाज्य भारों के लिए जारी किया जाता है, यानी वे जिन्हें कानूनी भार सीमाओं को पूरा करने के लिए उचित रूप से छोटा नहीं किया जा सकता। विभाज्य भारों को परमिट देने के बजाय कानूनी भार तक कम किया जाना चाहिए।"},"15":{"q":"अर्कांसस कम से कम पाँच धुरियों वाले ट्रक-ट्रैक्टर/सेमीट्रेलर संयोजन के लिए, जो अपनी प्राकृतिक अवस्था में कृषि-संबंधी या बागवानी फसलों को ढोता है, किस सकल भार तक का वार्षिक परमिट अनुमत करता है?","options":["84,000 pounds","90,000 pounds","100,000 pounds","112,000 pounds"],"explanation":"Arkansas Code Ann. 27-35-210 न्यूनतम पाँच-धुरी वाले ट्रक-ट्रैक्टर/सेमीट्रेलर संयोजन के लिए, जो प्राकृतिक-अवस्था की कृषि-संबंधी या बागवानी फसलों को ढोता है, कुल सकल भार 100,000 pounds तक का वार्षिक परमिट अधिकृत करता है।"},"16":{"q":"अर्कांसस में एक परमिट-प्राप्त संचलन पर, एक टैंडम धुरी समूह को अधिकतम कितने तक लोड किया जा सकता है:","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"explanation":"ARDOT Permit Rules के अंतर्गत, एक परमिट-प्राप्त टैंडम धुरी समूह 46,000 pounds तक ले जा सकता है (किसी एकल धुरी पर 23,000 pounds से अधिक नहीं), जबकि Code 27-35-203 में बिना परमिट की कानूनी सीमा 34,000 pounds है।"},"17":{"q":"अर्कांसस में एक पाँच-धुरी ट्रैक्टर-सेमीट्रेलर 80,000 lbs सकल भार तक लोड है, स्टीयर धुरी पर 20,000 lbs, ड्राइव टैंडम पर 34,000 lbs, और ट्रेलर टैंडम पर 26,000 lbs है। कौन सी स्थिति कानूनी सीमा से अधिक है?","options":["The gross weight","The steer (single) axle weight","The drive tandem weight","None of these exceed their legal limit"],"explanation":"Code 27-35-203 के अनुसार, कानूनी सीमाएँ हैं 80,000 lbs सकल, 20,000 lbs एकल धुरी, और 34,000 lbs टैंडम। यहाँ प्रत्येक मान अपनी सीमा पर या उससे नीचे है, इसलिए कोई भी धुरी या सकल भार कानूनी सीमा से अधिक नहीं है (ब्रिज-फॉर्मूला दूरी अभी भी लागू होती है)।"},"18":{"q":"ट्रक-ट्रैक्टर और एकल सेमीट्रेलर के लिए अर्कांसस के राजमार्गों पर कुल संयोजन लंबाई के बारे में कौन सा कथन सही है?","options":["Arkansas caps the overall tractor-semitrailer combination at exactly 65 feet","Arkansas does not impose a fixed overall length limit on a tractor-and-single-semitrailer combination; the semitrailer itself may be up to 53'6\"","Arkansas caps the overall combination at 60 feet on all roads","Arkansas allows no semitrailer longer than 48 feet"],"explanation":"Arkansas Code Ann. 27-35-208 सेमीट्रेलर की लंबाई को सीमित करता है (53'6\" से कम प्रतिबंधित नहीं किया जा सकता) लेकिन ट्रक-ट्रैक्टर और एकल सेमीट्रेलर संयोजन पर कोई निश्चित कुल लंबाई सीमा निर्धारित नहीं करता, जो संघीय STAA नियमों के अनुरूप है।"},"19":{"q":"अर्कांसस में एक फ्लैटबेड अपने भार के शीर्ष तक 14 feet 4 inches ऊँचा मापता है। बिना परमिट के, यह वाहन है:","options":["Legal, because the limit is 15 feet","Over height and requires a special (over-height) permit","Legal only off the Interstate system","Legal because height is not regulated in Arkansas"],"explanation":"Code 27-35-207 (जैसा कि Act 871 of 2021 द्वारा संशोधित) के अंतर्गत वर्तमान अर्कांसस कानूनी ऊँचाई 14 feet है। 14'4\" मापने वाला भार 14 feet से अधिक है और इसके लिए ARDOT/Arkansas Highway Police से अधिक-ऊँचाई परमिट की आवश्यकता होती है।"},"20":{"q":"अर्कांसस में, 26,001 pounds या उससे अधिक की सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के संयोजन को संचालित करने के लिए कौन सी CDL श्रेणी आवश्यक है, जहाँ खींची जाने वाली इकाई का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"अर्कांसस एक Class A CDL को वाहनों के किसी भी ऐसे संयोजन के रूप में परिभाषित करता है जिसका GCWR 26,001 pounds या उससे अधिक हो, जिसमें 10,000 pounds से अधिक GVWR वाली खींची जाने वाली इकाई शामिल हो। स्रोत: Arkansas CDL Manual, Section 1 (Classifications); Arkansas DFA Office of Driver Services CDL page।"},"21":{"q":"अर्कांसस नियमों के अंतर्गत, 26,001 pounds या उससे अधिक GVWR वाले एकल वाहन (या ऐसा वाहन जो 10,000 pounds GVWR से अधिक न होने वाली इकाई को खींच रहा हो) के लिए कौन सी CDL श्रेणी आवश्यक है?","options":["Class B","Class A","Class C","Class M"],"explanation":"अर्कांसस एक Class B CDL को किसी भी ऐसे एकल वाहन के रूप में परिभाषित करता है जिसका GVWR 26,001 pounds या उससे अधिक हो, या ऐसा कोई वाहन जो 10,000 pounds GVWR से अधिक न होने वाली इकाई को खींच रहा हो। स्रोत: Arkansas CDL Manual, Section 1 (Classifications); Arkansas DFA CDL page।"},"22":{"q":"अर्कांसस में, एक ऐसा वाहन जो Class A या Class B की परिभाषा को पूरा नहीं करता लेकिन 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या प्लैकार्ड किए गए खतरनाक पदार्थों को ले जाने के लिए उपयोग किया जाता है, किस CDL श्रेणी में आता है?","options":["Class A","Class C","Class B","Class P"],"explanation":"अर्कांसस एक Class C CDL को ऐसे वाहन के रूप में परिभाषित करता है जो Class A या B को पूरा नहीं करता लेकिन चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है, या प्लैकार्ड किए गए खतरनाक पदार्थ या 42 CFR Part 73 के अंतर्गत चयनित एजेंट/टॉक्सिन को ले जाता है। स्रोत: Arkansas CDL Manual, Section 1; Arkansas DFA CDL page।"},"23":{"q":"केवल राज्य के भीतर (इंट्रास्टेट कॉमर्स) वाणिज्यिक मोटर वाहन चलाने तक सीमित अर्कांसस CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16 years old","18 years old","19 years old","21 years old"],"explanation":"अर्कांसस में इंट्रास्टेट कॉमर्स में (केवल अर्कांसस के भीतर) वाणिज्यिक मोटर वाहन संचालित करने के लिए चालक का कम से कम 18 वर्ष का होना आवश्यक है। स्रोत: Arkansas DFA Office of Driver Services CDL requirements।"},"24":{"q":"राज्य की सीमाओं के पार वाहन चलाने (इंटरस्टेट कॉमर्स) के लिए मान्य अर्कांसस CDL प्राप्त करने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"अर्कांसस (संघीय मानकों का पालन करते हुए) में इंटरस्टेट कॉमर्स में वाणिज्यिक मोटर वाहन संचालित करने के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है। 18-20 वर्ष का चालक इंट्रास्टेट संचालन तक सीमित है। स्रोत: Arkansas DFA Office of Driver Services CDL requirements।"},"25":{"q":"अर्कांसस में, एक टैंक वाहन को संचालित करने के लिए कौन सा एंडोर्समेंट आवश्यक है जो तरल या गैस को ऐसे टैंक में ले जाने के लिए डिज़ाइन किया गया है जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक और कुल रेटेड क्षमता 1,000 gallons या उससे अधिक हो?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"अर्कांसस को ऐसे वाहनों के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है जो तरल या गैसीय पदार्थों को ऐसे टैंक या टैंकों में ले जाने के लिए डिज़ाइन किए गए हैं जिनकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक और कुल रेटेड क्षमता 1,000 gallons या उससे अधिक हो। स्रोत: Arkansas CDL Manual, Section 1 (Endorsements) and Section 8।"},"26":{"q":"अर्कांसस में, ऐसे पदार्थ को ढोने वाले वाहन को चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है जिसे खतरनाक के रूप में नामित किया गया है और 49 CFR Part 172 के अंतर्गत प्लैकार्ड करना आवश्यक है?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"explanation":"अर्कांसस को किसी भी ऐसे चालक के लिए, वाहन श्रेणी की परवाह किए बिना, H (Hazardous Materials) एंडोर्समेंट आवश्यक है जो 49 U.S.C. 5103 के अंतर्गत खतरनाक के रूप में नामित और 49 CFR Part 172 के अंतर्गत प्लैकार्ड करने के लिए आवश्यक पदार्थ ढो रहा हो। स्रोत: Arkansas CDL Manual, Section 1 (Endorsements)।"},"27":{"q":"लिखित ज्ञान परीक्षा पास करने के अलावा, Hazardous Materials (H) एंडोर्समेंट जारी करने से पहले अर्कांसस किस अतिरिक्त चरण की आवश्यकता रखता है?","options":["A vision exam by an ophthalmologist","A TSA security threat assessment with fingerprints and a background check","A second road skills test in a tank vehicle","A notarized employer sponsorship letter"],"explanation":"HazMat एंडोर्समेंट प्राप्त करने, नवीनीकृत करने या स्थानांतरित करने के लिए, अर्कांसस को एक TSA security threat assessment आवश्यक है जिसमें फिंगरप्रिंटिंग और एक संघीय पृष्ठभूमि जाँच (आपराधिक, आव्रजन, और FBI रिकॉर्ड) शामिल है। चालकों को कम से कम 90 days का समय रखना चाहिए। स्रोत: Arkansas DFA Hazardous Materials Endorsement page; Arkansas CDL Manual, Section 1।"},"28":{"q":"ऐसे चालक के लिए जो डबल या ट्रिपल ट्रेलर खींचना चाहता है, अर्कांसस किस एंडोर्समेंट की आवश्यकता रखता है?","options":["T endorsement","N endorsement","S endorsement","X endorsement"],"explanation":"अर्कांसस को डबल या ट्रिपल ट्रेलर खींचने के लिए T (Doubles/Triples) एंडोर्समेंट आवश्यक है; आवेदक को कई ट्रेलर खींचने से जुड़ी समस्याओं पर एक ज्ञान परीक्षा पास करनी होगी। स्रोत: Arkansas CDL Manual, Section 1 (Endorsements) and Section 7।"},"29":{"q":"अर्कांसस में, एक ऐसा चालक जो चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन को संचालित करना चाहता है, उसे कौन सा एंडोर्समेंट प्राप्त करना होगा?","options":["S endorsement","T endorsement","P endorsement","N endorsement"],"explanation":"अर्कांसस को चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन के चालकों के लिए P (Passenger) एंडोर्समेंट आवश्यक है। आवेदक को एक यात्री वाहन में एक ज्ञान परीक्षा और एक कौशल परीक्षा पास करनी होगी। स्रोत: Arkansas CDL Manual, Section 1 (Endorsements) and Section 4।"},"30":{"q":"अर्कांसस के किसी चालक को स्कूल बस चलाने के लिए, Passenger (P) एंडोर्समेंट के अतिरिक्त, कौन सा एंडोर्समेंट रखना होगा?","options":["H endorsement","T endorsement","S endorsement","X endorsement"],"explanation":"अर्कांसस को स्कूल बस चलाने के लिए S (School Bus) एंडोर्समेंट आवश्यक है; चालक को एक स्कूल-बस ज्ञान परीक्षा और एक स्कूल बस में कौशल परीक्षा पास करनी होगी, और यह एंडोर्समेंट किसी भी श्रेणी (A, B, या C) में लागू होता है। स्रोत: Arkansas CDL Manual, Section 1 (Endorsements) and Section 10।"},"31":{"q":"अर्कांसस में, एक टैंक वाहन के ऐसे चालक को जिसे प्लैकार्ड किए गए खतरनाक पदार्थ भी ढोने हों, कौन सा एकल संयोजन एंडोर्समेंट प्राप्त करना चाहिए?","options":["T endorsement","X endorsement","P endorsement","S endorsement"],"explanation":"अर्कांसस HazMat और Tank Vehicle के संयोजन के रूप में X एंडोर्समेंट जारी करता है; चालक को टैंक वाहनों और खतरनाक पदार्थों दोनों के लिए ज्ञान परीक्षाएँ पास करनी होंगी। स्रोत: Arkansas CDL Manual, Section 1 (Endorsements)।"},"32":{"q":"Arkansas CDL Manual के अनुसार, कौन से एंडोर्समेंट का समूह एकमात्र ऐसा है जिसे Commercial Learner's Permit (CLP) में जोड़ा जा सकता है?","options":["H, N, and T","P, H, and X","P, S, and N","T, S, and H"],"explanation":"Arkansas CDL Manual में कहा गया है कि CLP में जोड़े जा सकने वाले एकमात्र एंडोर्समेंट Passenger (P), School Bus (S), और Tank Vehicle (N) हैं। CLP पर HazMat (H) एंडोर्समेंट जारी नहीं किया जा सकता। स्रोत: Arkansas CDL Manual, Section 1 (Endorsements/CLP)।"},"33":{"q":"अर्कांसस में, जब एक CLP Tank Vehicle (N) एंडोर्समेंट के साथ जारी किया जाता है, तो उस पर कौन सा प्रतिबंध होना चाहिए?","options":["No interstate operation (K)","No air brake equipped CMV (L)","No manual transmission (E)","No cargo in a CMV tank vehicle (X)"],"explanation":"अर्कांसस की आवश्यकता है कि N एंडोर्समेंट के साथ जारी किए गए CLP पर X प्रतिबंध (No cargo in a CMV tank vehicle) भी हो; धारक केवल एक खाली टैंक को संचालित कर सकता है जिसे किसी भी अवशेष से साफ कर दिया गया हो। स्रोत: Arkansas CDL Manual, Section 1 (Restrictions)।"},"34":{"q":"अर्कांसस और संघीय CLP नियमों के अंतर्गत, एक CLP धारक को CDL कौशल परीक्षा देने के योग्य होने से पहले प्रारंभिक जारी करने के बाद कितने समय तक प्रतीक्षा करनी होगी?","options":["7 days","10 days","14 days","30 days"],"explanation":"अर्कांसस उस संघीय नियम को लागू करता है कि एक CLP धारक CLP के प्रारंभिक जारी होने के बाद पहले 14 days के दौरान CDL कौशल परीक्षा देने के योग्य नहीं है। स्रोत: Arkansas DFA Commercial Learner's Permit (CLP) page; 49 CFR 383.25।"},"35":{"q":"एक अर्कांसस Commercial Learner's Permit (CLP) कितने समय तक मान्य रहता है, इससे पहले कि धारक को सामान्य और एंडोर्समेंट ज्ञान परीक्षाएँ दोबारा देनी पड़ें?","options":["Up to 60 days","Up to 180 days","Up to 1 year","Up to 2 years"],"explanation":"एक अर्कांसस CLP up to 1 year तक मान्य रहता है; समाप्ति के बाद धारक को सामान्य और एंडोर्समेंट ज्ञान परीक्षाएँ दोबारा देनी होंगी। स्रोत: Arkansas DFA Commercial Learner's Permit (CLP) page।"},"36":{"q":"अर्कांसस में Commercial Driver License (CDL) कौन सी राज्य एजेंसी जारी करती है?","options":["Arkansas State Police","Arkansas Department of Finance and Administration, Office of Driver Services","Arkansas Department of Transportation (ARDOT)","Federal Motor Carrier Safety Administration"],"explanation":"अर्कांसस में CDL, Department of Finance and Administration (DFA), Office of Driver Services द्वारा जारी किया जाता है। ARDOT सड़कों/परमिट को संभालता है और FMCSA संघीय नियामक है, लेकिन लाइसेंस जारी करने वाली एजेंसी DFA Driver Services है। स्रोत: Arkansas DFA Driver Services CDL page।"},"37":{"q":"अर्कांसस CDL या CLP के लिए आवेदन करते समय, Office of Driver Services आवेदक से कौन से प्रमाणों का संयोजन प्रस्तुत करने की आवश्यकता रखता है?","options":["Only a Social Security card and a utility bill","Only a U.S. passport","Proof of identity/date of birth, Social Security number, Arkansas residency, and lawful presence","A high school diploma and proof of employment"],"explanation":"Arkansas DFA को आवेदकों से पहचान और जन्म तिथि का प्रमाण, Social Security number का प्रमाण, अर्कांसस निवास का प्रमाण (वर्तमान पता), और वैध उपस्थिति/कानूनी U.S. उपस्थिति का प्रमाण प्रदान करना आवश्यक है। स्रोत: Arkansas DFA Driver Services documentation requirements ('Do You Have What You Need?')।"},"38":{"q":"अर्कांसस में लागू संघीय Entry-Level Driver Training (ELDT) नियमों (7 फरवरी 2022 से प्रभावी) के अंतर्गत, एक पहली बार आवेदन करने वाले को परीक्षण से पहले आवश्यक प्रशिक्षण कहाँ पूरा करना होगा?","options":["Any community college in Arkansas","An Arkansas DFA revenue office","A provider listed on the FMCSA Training Provider Registry (TPR)","An employer's in-house orientation only"],"explanation":"ELDT के अनुसार पहली बार Class A/B आवेदकों और P, S, या H एंडोर्समेंट के आवेदकों को राज्य द्वारा प्रशासित परीक्षा से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से प्रशिक्षण पूरा करना होगा; H के लिए प्रशिक्षण ज्ञान परीक्षा से पहले केवल सैद्धांतिक होता है, जबकि Class A/B, P, और S के लिए कौशल परीक्षा से पहले सैद्धांतिक प्लस बिहाइंड-द-व्हील आवश्यक है। स्रोत: FMCSA ELDT rule (49 CFR Part 380), effective Feb. 7, 2022; FMCSA Training Provider Registry।"},"39":{"q":"अर्कांसस CDL के लिए आवेदन करते समय, एक चालक को चार चिकित्सा प्रमाणन श्रेणियों में से किसी एक में स्व-प्रमाणित करना होगा। निम्नलिखित में से कौन सी उन चार श्रेणियों में से एक है?","options":["Recreational interstate","Hazmat-exempt interstate","Provisional intrastate","Non-excepted interstate"],"explanation":"अर्कांसस के चालकों को चार श्रेणियों में से किसी एक में स्व-प्रमाणित करना होगा: Non-excepted Interstate, Excepted Interstate, Non-excepted Intrastate, या Excepted Intrastate। Non-excepted interstate चालकों को एक संघीय मेडिकल परीक्षक का प्रमाणपत्र बनाए रखना होगा। स्रोत: Arkansas CDL Manual, Section 1.2 (Self-Certification); 49 CFR 383.71।"},"40":{"q":"अर्कांसस में, किसी व्यक्ति को वाणिज्यिक मोटर वाहन (CMV) नशे की हालत में चलाने वाला और अयोग्यता के अधीन तब माना जाता है जब उसकी रक्त अल्कोहल सांद्रता (BAC) किस स्तर पर या उससे अधिक हो?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"अर्कांसस संघीय CMV मानक अपनाता है: 0.04% या उससे अधिक BAC के साथ CMV संचालित करना नशे की हालत में चलाना और एक अयोग्यता-कारक प्रमुख अपराध है, जो गैर-वाणिज्यिक चालकों के लिए 0.08% सीमा का आधा है। स्रोत: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51।"},"41":{"q":"अर्कांसस कानून के अंतर्गत, जब कोई CDL धारक प्लैकार्ड किए गए खतरनाक पदार्थ नहीं ढो रहा हो, तो उसके पहले प्रमुख अपराध (जैसे CMV में DUI) के लिए न्यूनतम अयोग्यता अवधि क्या है?","options":["1 year","60 days","3 years","6 months"],"explanation":"एक पहला प्रमुख अपराध (DUI, 0.04+ BAC, परीक्षण से इनकार, दुर्घटनास्थल छोड़ना, आदि) के परिणामस्वरूप अर्कांसस में 1-year की CDL अयोग्यता होती है। स्रोत: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51।"},"42":{"q":"अर्कांसस में, यदि कोई चालक प्लैकार्ड किए गए खतरनाक पदार्थ ढो रहे CMV को संचालित करते समय पहला प्रमुख अपराध करता है, तो अयोग्यता अवधि बढ़कर हो जाती है:","options":["3 years","1 year","5 years","Lifetime"],"explanation":"अर्कांसस पहले-प्रमुख-अपराध की अयोग्यता को 1 year से बढ़ाकर 3 years कर देता है जब अपराध प्लैकार्ड किए गए खतरनाक पदार्थ ढोते समय होता है। स्रोत: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51।"},"43":{"q":"किसी CDL धारक द्वारा एक अलग घटना में किए गए दूसरे प्रमुख अपराध के लिए अर्कांसस में अयोग्यता अवधि क्या है?","options":["Lifetime","10 years","3 years","5 years"],"explanation":"एक दूसरे प्रमुख अपराध के परिणामस्वरूप अर्कांसस में CDL की आजीवन (स्थायी) अयोग्यता होती है। स्रोत: Arkansas DFA CDL/CMV Offenses; Ark. Code 27-23-112; 49 CFR 383.51।"},"44":{"q":"अर्कांसस में CMV संचालित करते समय आवश्यक अल्कोहल/BAC परीक्षण देने से इनकार करने पर पहली बार के लिए क्या अयोग्यता होती है?","options":["1 year","90 days","30 days","No disqualification, only a fine"],"explanation":"परीक्षण से इनकार को एक प्रमुख अपराध के रूप में माना जाता है, जो DUI के समान 1-year की अयोग्यता वहन करता है (यदि प्लैकार्ड किए गए हैज़मैट ढो रहे हों तो 3 years)। इनकार अर्कांसस के CMV संचालकों के लिए निहित-सहमति नियम के अंतर्गत आता है। स्रोत: Ark. Code 27-23-112; Arkansas DFA CDL/CMV Offenses; 49 CFR 383.51।"},"45":{"q":"अर्कांसस के वाणिज्यिक चालकों के लिए निहित-सहमति प्रावधान के अंतर्गत, राज्य में CMV संचालित करने वाला व्यक्ति किसके लिए सहमति देने वाला माना जाता है:","options":["Testing of blood, breath, or urine for alcohol or controlled substances","Random vehicle searches without cause","Waiving the right to a hearing on any disqualification","Annual mandatory drug rehabilitation"],"explanation":"अर्कांसस का निहित-सहमति नियम यह प्रावधान करता है कि कोई भी व्यक्ति जो CMV चलाता है, वह बिगड़े-चालन और 0.04% नियमों को लागू करने के लिए आवश्यक अल्कोहल/नियंत्रित-पदार्थ परीक्षण के लिए सहमति देने वाला माना जाता है। स्रोत: Ark. Code 27-23-112/27-23-113; Arkansas DFA CDL/CMV Offenses।"},"46":{"q":"अर्कांसस में एक CDL धारक जिसके बारे में पाया जाता है कि CMV संचालित करते समय उसमें अल्कोहल की कोई भी मापी या पता लगाई गई उपस्थिति (0.04% से नीचे) है, उसे क्या किया जाना चाहिए:","options":["Placed out of service for 24 hours","Disqualified for 1 year","Fined $2,500 and disqualified for 60 days","Arrested for DUI immediately"],"explanation":"Arkansas Code 27-23-113 किसी भी मापी या पता लगाई गई अल्कोहल के साथ CMV संचालित करने पर रोक लगाता है; उल्लंघन में पाए गए चालक को 24 hours के लिए सेवा से बाहर (out of service) कर दिया जाता है। पूर्ण DUI अयोग्यता केवल 0.04% या उससे अधिक पर लागू होती है। स्रोत: Ark. Code 27-23-113।"},"47":{"q":"अर्कांसस में, 3 साल की अवधि के भीतर एक अलग घटना में किया गया दूसरा गंभीर यातायात उल्लंघन कितने समय की अयोग्यता का परिणाम देता है?","options":["60 days","30 days","120 days","1 year"],"explanation":"3 साल के भीतर अलग घटनाओं में दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप अर्कांसस में 60-day की अयोग्यता होती है। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"48":{"q":"3 साल की अवधि के भीतर अलग घटनाओं में तीसरा (या बाद का) गंभीर यातायात उल्लंघन किस अर्कांसस अयोग्यता का परिणाम देता है?","options":["120 days","60 days","1 year","90 days"],"explanation":"3 साल के भीतर अलग घटनाओं में तीन या अधिक गंभीर यातायात उल्लंघनों के परिणामस्वरूप अर्कांसस में 120-day की अयोग्यता होती है। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"49":{"q":"निम्नलिखित में से कौन सा अर्कांसस CDL धारक के लिए एक गंभीर यातायात उल्लंघन (न कि प्रमुख अपराध) के रूप में वर्गीकृत है?","options":["Excessive speeding, 15 mph or more over the limit","Driving a CMV with a 0.04% BAC","Leaving the scene of an accident in a CMV","Using a CMV to commit a felony"],"explanation":"अत्यधिक तेज़ गति (सीमा से 15+ mph अधिक), लापरवाह चालन, अनुचित/अनियमित लेन परिवर्तन, बहुत करीब से पीछा करना, और टेक्स्टिंग/हैंडहेल्ड फोन का उपयोग गंभीर यातायात उल्लंघन हैं। सूचीबद्ध अन्य विकल्प प्रमुख अपराध हैं। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"50":{"q":"अर्कांसस में किसी भी अयोग्यता अवधि के लागू होने से पहले 3 साल की अवधि के भीतर कितने गंभीर यातायात उल्लंघन आवश्यक हैं?","options":["2","1","3","4"],"explanation":"एक अकेला गंभीर उल्लंघन अयोग्य नहीं करता; पहली अयोग्यता (60 days) 3 साल के भीतर दूसरे गंभीर उल्लंघन से लागू होती है, और तीसरा 120 days लागू करता है। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"51":{"q":"CMV संचालित करते समय अर्कांसस CDL धारक के पहली बार रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के दोषी पाए जाने पर न्यूनतम अयोग्यता क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"एक पहला रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन अर्कांसस में न्यूनतम 60-day की अयोग्यता वहन करता है। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"52":{"q":"3 साल की अवधि के भीतर दूसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन किस न्यूनतम अर्कांसस अयोग्यता का परिणाम देता है?","options":["120 days","60 days","1 year","90 days"],"explanation":"3 साल के भीतर दूसरा ग्रेड-क्रॉसिंग उल्लंघन अर्कांसस में न्यूनतम 120-day की अयोग्यता वहन करता है। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"53":{"q":"3 साल की अवधि के भीतर तीसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन किस न्यूनतम अर्कांसस अयोग्यता का परिणाम देता है?","options":["1 year","120 days","180 days","60 days"],"explanation":"3 साल के भीतर तीसरा ग्रेड-क्रॉसिंग उल्लंघन अर्कांसस में न्यूनतम 1-year की अयोग्यता वहन करता है। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"54":{"q":"कौन सी क्रिया एक रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन है जो किसी अर्कांसस CDL धारक को अयोग्य कर सकती है?","options":["Failing to have enough space to drive completely through the crossing without stopping","Driving 5 mph over the limit near tracks","Sounding the horn before crossing","Stopping more than 15 feet from the nearest rail"],"explanation":"ग्रेड-क्रॉसिंग उल्लंघनों में ट्रेनों के लिए गति धीमी करने और जाँच करने में विफल रहना, आवश्यक होने पर रुकने में विफल रहना, क्रॉसिंग साफ करने के लिए पर्याप्त जगह न होना, क्रॉसिंग ट्रैफ़िक-नियंत्रण उपकरणों की अवहेलना करना, और अपर्याप्त अंडरकैरिज क्लीयरेंस शामिल हैं। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"55":{"q":"किसी चालक या वाहन आउट-ऑफ-सर्विस (OOS) आदेश का उल्लंघन करने के लिए अर्कांसस CDL धारक के पहली बार दोषी पाए जाने पर न्यूनतम अयोग्यता अवधि क्या है?","options":["180 days","60 days","1 year","90 days"],"explanation":"आउट-ऑफ-सर्विस आदेश का उल्लंघन करने के लिए पहली बार दोषी पाए जाने पर अर्कांसस में न्यूनतम 180-day (1 year तक) की अयोग्यता वहन करती है। स्रोत: Ark. Code 27-23-112/27-23-114; Arkansas CDL manual; 49 CFR 383.51।"},"56":{"q":"आउट-ऑफ-सर्विस आदेश का उल्लंघन करने के लिए 10 साल के भीतर दूसरी बार दोषी पाए जाने पर किस न्यूनतम अर्कांसस अयोग्यता का परिणाम होता है?","options":["2 years","180 days","1 year","5 years"],"explanation":"10 साल के भीतर दूसरा OOS-आदेश उल्लंघन अर्कांसस में न्यूनतम 2-year (5 years तक) की अयोग्यता वहन करता है। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"57":{"q":"अयोग्यता के अलावा, अर्कांसस में आउट-ऑफ-सर्विस आदेश का उल्लंघन करने के दोषी चालक पर पहली बार दोषसिद्धि के लिए कम से कम कितनी राशि का दीवानी जुर्माना लगता है?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"अर्कांसस एक चालक पर पहले आउट-ऑफ-सर्विस-आदेश उल्लंघन के लिए कम से कम $2,500 का दीवानी जुर्माना (और दूसरे के लिए कम से कम $5,000) अयोग्यता के अतिरिक्त लगाता है। स्रोत: Ark. Code 27-23-114।"},"58":{"q":"अर्कांसस और संघीय नियमों के अंतर्गत, CMV चलाते समय किसी CDL चालक द्वारा हैंड-हेल्ड मोबाइल फोन के उपयोग या टेक्स्टिंग को अयोग्यता के उद्देश्यों के लिए कैसे माना जाता है?","options":["As a serious traffic violation that, on repeat offenses, can lead to disqualification","As a major offense with a 1-year disqualification","As a lifetime-disqualifying offense","It carries no disqualification consequence, only a citation"],"explanation":"CMV चलाते समय टेक्स्टिंग या हैंड-हेल्ड फोन का उपयोग एक गंभीर यातायात उल्लंघन है; कई दोषसिद्धियाँ 2-उल्लंघन (60 days) / 3-उल्लंघन (120 days) अयोग्यता की ओर गिनी जाती हैं, चालकों के लिए $2,750 तक के जुर्माने के साथ। स्रोत: Arkansas CDL manual; Ark. Code 27-51-1504; FMCSA 49 CFR 383.51/392.80-82।"},"59":{"q":"एक अर्कांसस CDL धारक जो किसी नियंत्रित पदार्थ के निर्माण, वितरण या वितरण से जुड़े किसी अपराध (felony) के लिए CMV का उपयोग करता है, उसे किस अयोग्यता का सामना करना पड़ता है?","options":["Lifetime, with no possibility of reinstatement","1 year","3 years","10 years"],"explanation":"नियंत्रित पदार्थों के निर्माण, वितरण या वितरण के लिए CMV का उपयोग करना एक प्रमुख अपराध है जो बिना किसी पुनर्बहाली के अनिवार्य आजीवन अयोग्यता वहन करता है, जो अन्य आजीवन प्रतिबंधों से भिन्न है जो 10 साल बाद पुनर्बहाली की अनुमति दे सकते हैं। स्रोत: Ark. Code 27-23-112; Arkansas CDL manual; 49 CFR 383.51।"},"60":{"q":"अर्कांसस में, जब किसी बस या प्लेकार्ड लगे खतरनाक-सामग्री वाहन को रेलरोड-हाईवे क्रॉसिंग पर रुकना पड़े, तो उसे निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["15 feet से अधिक निकट नहीं और 50 feet से अधिक दूर नहीं","10 feet से अधिक निकट नहीं और 40 feet से अधिक दूर नहीं","25 feet से अधिक निकट नहीं और 75 feet से अधिक दूर नहीं","5 feet से अधिक निकट नहीं और 15 feet से अधिक दूर नहीं"],"explanation":"अर्कांसस के अनुसार बसों और प्लेकार्ड लगे HazMat वाहनों को निकटतम रेल से 15 feet से अधिक निकट नहीं और 50 feet से अधिक दूर नहीं रुकना चाहिए, जहाँ चालक को पटरियों का सबसे अच्छा दृश्य मिलता है। स्रोत: Arkansas Commercial Driver License Manual, Sections 2.15, 4.3.5, and 9."},"61":{"q":"अर्कांसस के Move Over कानून के तहत, बहु-लेन हाईवे पर किसी चालक को क्या करना चाहिए जब वह फ्लैशिंग लाइट के साथ रुके हुए किसी अधिकृत वाहन के पास पहुँचता है?","options":["अधिकृत वाहन के हटने तक पूरी तरह रुक जाएँ","रुके हुए वाहन से सबसे दूर संभव लेन में चले जाएँ जब तक कि उसे सुरक्षित रूप से पार न कर लें","निर्धारित गति बनाए रखें और पास होते समय हॉर्न बजाएँ","ट्रैफिक प्रवाह बनाए रखने के लिए रुके हुए वाहन के सबसे निकट की लेन में चले जाएँ"],"explanation":"Arkansas Code 27-51-310 के अनुसार बहु-लेन सड़क पर चालकों को रुके हुए अधिकृत वाहन से सबसे दूर संभव लेन या स्थिति में जाना चाहिए और उसे सुरक्षित रूप से पार करने तक वहीं रहना चाहिए। स्रोत: Ark. Code Ann. 27-51-310 (Move Over law)."},"62":{"q":"अर्कांसस के एक गैर-नियंत्रित-पहुँच (non-controlled-access) हाईवे पर, एक-और-डेढ़ टन क्षमता या उससे अधिक के ट्रक के लिए अधिकतम वैध गति क्या है?","options":["55 mph","60 mph","50 mph","65 mph"],"explanation":"अर्कांसस उन हाईवे पर जो नियंत्रित-पहुँच वाले नहीं हैं, एक-और-डेढ़ टन क्षमता या उससे अधिक के ट्रकों के लिए अधिकतम 50 mph निर्धारित करता है, जबकि उन्हीं स्थानों पर अन्य वाहनों के लिए 60 mph है। स्रोत: Ark. Code Ann. 27-51-201."},"63":{"q":"अर्कांसस में, जब कोई स्कूल बस दो-लेन सड़क पर रुकती है और बच्चों को चढ़ाने या उतारने के लिए अपनी बारी-बारी जलने वाली लाल चेतावनी लाइटें दिखाती है, तो किन चालकों को रुकना चाहिए?","options":["केवल बस के पीछे उसी दिशा में चल रहे चालक","केवल बस के ठीक बगल वाली लेन में चल रहे चालक","केवल बस के 100 feet के भीतर मौजूद चालक","किसी भी दिशा से बस के सामने आने या उससे आगे निकलने वाले चालक"],"explanation":"दो-लेन सड़क पर, Arkansas Code 27-51-1004 के अनुसार किसी भी दिशा से बस के सामने आने या उससे आगे निकलने वाले हर चालक को लाल लाइटें जलने के दौरान पूरी तरह रुकना चाहिए। स्रोत: Ark. Code Ann. 27-51-1004."},"64":{"q":"2021 का कौन-सा अर्कांसस कानून बहु-लेन हाईवे पर सबसे बाईं लेन के उपयोग को केवल ओवरटेक करने तक सीमित करता है?","options":["Act 1054 of 2007","Act 1090 of 2021","Act 27 of 2021","Act 310 of 2019"],"explanation":"Act 1090 of 2021 बहु-लेन हाईवे पर सबसे बाईं लेन को ओवरटेक करने के लिए आरक्षित करता है; उन स्थानों को छोड़कर जहाँ लेन अवरुद्ध हों, चालकों को यात्रा के लिए दाईं लेन का उपयोग करना चाहिए। स्रोत: Act 1090 of 2021; ARDOT public notice on the Left Lane Driving Law."},"65":{"q":"यदि किसी वाणिज्यिक वाहन को अर्कांसस हाईवे के किनारे (shoulder) पर रुकना पड़े, तो चालक को आपातकालीन चेतावनी उपकरण (परावर्तक त्रिकोण) कितने समय के भीतर लगाने चाहिए?","options":["5 minutes के भीतर","15 minutes के भीतर","10 minutes के भीतर","30 minutes के भीतर"],"explanation":"जिस चालक को सड़क या किनारे पर रुकना पड़े, उसे 10 minutes के भीतर आपातकालीन चेतावनी उपकरण लगाने चाहिए। स्रोत: Arkansas Commercial Driver License Manual, Section 2.5 (Communicating)."},"66":{"q":"किसी एक-तरफा (one-way) या विभाजित (divided) अर्कांसस हाईवे पर, रुके हुए वाणिज्यिक वाहन को अपने तीन चेतावनी त्रिकोण कहाँ लगाने चाहिए?","options":["10 feet, 100 feet, और हर तरफ 100 feet","आती हुई ट्रैफिक की ओर 25 feet, 100 feet, और 300 feet","आती हुई ट्रैफिक की ओर 50 feet, 150 feet, और 250 feet","आती हुई ट्रैफिक की ओर 10 feet, 100 feet, और 200 feet"],"explanation":"एक-तरफा या विभाजित हाईवे पर त्रिकोण वाहन से आती हुई ट्रैफिक की ओर 10 feet, 100 feet, और 200 feet पर लगाए जाते हैं। स्रोत: Arkansas Commercial Driver License Manual, Section 2.5."},"67":{"q":"वाहनों का कौन-सा समूह अर्कांसस के Move Over कानून (Ark. Code 27-51-310) के तहत आने वाले 'अधिकृत वाहनों' में शामिल नहीं है?","options":["अपनी 4-way फ्लैशर चालू किए कोई भी निजी यात्री कार","टोइंग कार्य में लगे टो ट्रक","Arkansas Department of Transportation के वाहन","फ्लैशिंग लाइट दिखाते हुए उपयोगिता कंपनी (utility) के वाहन"],"explanation":"अर्कांसस का Move Over कानून आपातकालीन प्रतिक्रिया, कानून प्रवर्तन, ARDOT, ARDOT ठेकेदार, उपयोगिता, और फ्लैशिंग/घूमती लाइट दिखाते टोइंग वाहनों को कवर करता है; केवल अपनी हैजर्ड फ्लैशर का उपयोग करने वाली एक सामान्य निजी कार 'अधिकृत वाहन' नहीं है। स्रोत: Ark. Code Ann. 27-51-310."},"68":{"q":"किसी गैर-नियंत्रित-पहुँच वाले अर्कांसस हाईवे पर, यात्री कारों के लिए सामान्य गति सीमा एक-और-डेढ़ टन क्षमता या उससे अधिक के ट्रकों की तुलना में कितनी अधिक है?","options":["5 mph अधिक (55 mph बनाम 50 mph)","15 mph अधिक (65 mph बनाम 50 mph)","10 mph अधिक (60 mph बनाम 50 mph)","कोई अंतर नहीं; दोनों 55 mph हैं"],"explanation":"अर्कांसस गैर-नियंत्रित-पहुँच वाले हाईवे पर अन्य वाहनों के लिए 60 mph की अनुमति देता है लेकिन भारी ट्रकों के लिए केवल 50 mph, यानी 10 mph का अंतर। स्रोत: Ark. Code Ann. 27-51-201."},"69":{"q":"अर्कांसस के स्कूल बस कानून के तहत, किस प्रकार की सड़क पर सामने से आने वाले चालकों को बच्चों को चढ़ाती या उतारती स्कूल बस के लिए रुकना आवश्यक नहीं है?","options":["दो-लेन सड़क","बीच में टर्निंग लेन वाली दो-लेन सड़क","मध्य-विभाजक (median) रहित चार-लेन सड़क","मध्य-विभाजक (median) से अलग की गई चार या अधिक लेन वाली विभाजित हाईवे"],"explanation":"अर्कांसस के अनुसार दोनों दिशाओं की सारी ट्रैफिक को रुकना चाहिए, सिवाय मध्य-विभाजक से अलग की गई चार या अधिक लेन वाली विभाजित हाईवे के, जहाँ केवल बस के पीछे चल रही ट्रैफिक को रुकना होता है। बीच की टर्न लेन मध्य-विभाजक नहीं है। स्रोत: Ark. Code Ann. 27-51-1004; official Arkansas school bus safety law guidance."},"70":{"q":"अर्कांसस का कानून नियंत्रित-पहुँच (controlled-access) वाले हाईवे पर भारी ट्रकों (1.5 टन या उससे अधिक) की अधिकतम गति को ऑटो अधिकतम से कितना कम निर्धारित करने की अपेक्षा करता है?","options":["ऑटोमोबाइल के लिए अधिकतम से 10 mph कम","ऑटोमोबाइल के लिए अधिकतम से 5 mph कम","ऑटोमोबाइल के लिए अधिकतम से 15 mph कम","ऑटोमोबाइल के लिए अधिकतम के बराबर"],"explanation":"Ark. Code 27-51-201 निर्देश देता है कि नियंत्रित-पहुँच वाले हाईवे पर एक-और-डेढ़ टन क्षमता या उससे अधिक के ट्रकों की अधिकतम अनुमत गति ऑटो अधिकतम से 10 mph कम निर्धारित की जाए (उदाहरण के लिए, ट्रकों के लिए 70 mph जहाँ कारें 75 चला सकती हैं)। स्रोत: Ark. Code Ann. 27-51-201."},"71":{"q":"कौन-सा अर्कांसस-विशिष्ट लेन प्रतिबंध कुछ छह-लेन Interstates पर 'Trucks Use Right 2 Lanes' के रूप में लगाया जाता है?","options":["सभी ट्रकों को हर समय केवल बीच की लेन में चलना चाहिए","दो से अधिक एक्सल वाले वाहन निर्दिष्ट छह-लेन Interstates पर सबसे बाईं लेन का उपयोग नहीं कर सकते","ट्रकों को सुबह 7 a.m. और 9 a.m. के बीच Interstates पर पूरी तरह प्रतिबंधित किया जाता है","ट्रकों को बाईं लेन का उपयोग करना चाहिए ताकि दाईं लेन मर्जिंग के लिए खुली रहें"],"explanation":"Act 1054 of 2007 ने Ark. Code 27-65-107(a) में संशोधन कर दो से अधिक एक्सल वाले वाहनों को निर्दिष्ट छह-लेन Interstates पर सबसे बाईं लेन से बाहर रखा, जिन्हें 'Trucks Use Right 2 Lanes' से चिह्नित किया गया है। स्रोत: Act 1054 of 2007; Ark. Code Ann. 27-65-107(a)."},"72":{"q":"यदि अर्कांसस में किसी रुके हुए अधिकृत वाहन के पास पहुँचते समय लेन बदलना असुरक्षित या असंभव हो, तो Move Over कानून क्या अपेक्षा करता है?","options":["अधिकृत वाहन के हटने तक सड़क पर पूरी तरह रुक जाएँ","निर्धारित गति पर चलते रहें क्योंकि लेन बदलना संभव नहीं है","अधिकृत वाहन के पीछे किनारे (shoulder) पर खींच लें और प्रतीक्षा करें","गति कम करें, सावधानी से आगे बढ़ें, और उस क्षेत्र में कम गति बनाए रखें"],"explanation":"जब सुरक्षित रूप से लेन बदलना संभव न हो, तो Ark. Code 27-51-310 चालक से अपेक्षा करता है कि वह गति कम करे, सावधानी से आगे बढ़े, और उस क्षेत्र में जहाँ अधिकृत वाहन रुका है, सड़क की स्थितियों के अनुरूप कम गति बनाए रखे। स्रोत: Ark. Code Ann. 27-51-310."},"73":{"q":"अर्कांसस में किसी ओवरसाइज़ परमिट की आवश्यकता पड़ने से पहले किसी वाहन या लोड की वैध अधिकतम चौड़ाई क्या है?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"State Highway System पर अर्कांसस की वैध अधिकतम चौड़ाई 8 feet 6 inches है; इससे अधिक चौड़ी किसी भी चीज़ के लिए ओवरसाइज़ परमिट आवश्यक है। स्रोत: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"74":{"q":"दोनों दिशाओं की ट्रैफिक ले जाने वाली दो-लेन अर्कांसस सड़क पर, रुके हुए CMV को अपने चेतावनी त्रिकोण कहाँ लगाने चाहिए?","options":["केवल पीछे की ओर 10 feet, 100 feet, और 200 feet","वाहन के 10 feet के भीतर और उसके 100 feet पीछे तथा 100 feet आगे","केवल वाहन के 25 feet पीछे और 25 feet आगे","केवल 100 feet पीछे, आगे कोई नहीं"],"explanation":"दो-लेन, दो-तरफा (अविभाजित) सड़क पर, एक त्रिकोण वाहन के 10 feet के भीतर और एक 100 feet पीछे तथा एक 100 feet आगे लगाएँ। स्रोत: Arkansas Commercial Driver License Manual, Section 2.5."},"75":{"q":"अर्कांसस के State Highway System पर परमिट की आवश्यकता पड़ने से पहले किसी वाहन की वैध अधिकतम ऊँचाई क्या है?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"explanation":"अर्कांसस की वैध अधिकतम ऊँचाई 13 feet 6 inches है; इससे अधिक के लोड के लिए ओवरसाइज़ परमिट आवश्यक है। स्रोत: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"76":{"q":"अर्कांसस किसी ओवरवाइड या ओवरलेंथ परमिट प्राप्त लोड के पिछले कोनों पर किस आकार के लाल झंडे आवश्यक करता है?","options":["12-inch लाल झंडे","24-inch लाल झंडे","6-inch लाल झंडे","18-inch लाल झंडे"],"explanation":"अर्कांसस ओवरवाइड और ओवरलेंथ लोड के निचले पिछले कोनों पर 18-inch लाल झंडे आवश्यक करता है, साथ ही आगे और पीछे OVERSIZE LOAD संकेत भी। स्रोत: ARDOT Permit Rules for the Movement of Oversize and Overweight Vehicles."},"77":{"q":"अर्कांसस में, किसी निर्मित (manufactured) या मोबाइल घर को टो करने वाले वाहन को किस अधिकतम गति पर चलाया जा सकता है?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"अर्कांसस के परमिट नियम किसी निर्मित या मोबाइल घर को टो करने वाले वाहन को 55 mph से अधिक तेज़ चलाने पर रोक लगाते हैं। स्रोत: Code of Arkansas Rules 111-109 / ARDOT Permit Rules (oversize/overweight movement)."},"78":{"q":"बच्चों को चढ़ाती या उतारती रुकी हुई स्कूल बस को अवैध रूप से पार करने के लिए अर्कांसस के दंड में किस सीमा का जुर्माना शामिल है?","options":["बिना जेल के एक निश्चित $100 जुर्माना","$500 से कम नहीं और $5,000 से अधिक नहीं","$250 से कम नहीं और $1,000 से अधिक नहीं","$50 से कम नहीं और $250 से अधिक नहीं"],"explanation":"Ark. Code 27-51-1001 रुकी हुई स्कूल बस को पार करने के लिए जुर्माना $250 से कम नहीं और $1,000 से अधिक नहीं निर्धारित करता है, साथ ही संभावित जेल, लाइसेंस निलंबन, और सामुदायिक सेवा भी। स्रोत: Ark. Code Ann. 27-51-1001."},"79":{"q":"अर्कांसस में रेलरोड-हाईवे क्रॉसिंग पर रुकते समय, एक वाणिज्यिक चालक को पार करने से पहले निम्नलिखित में से क्या भी करना चाहिए?","options":["चार-तरफा आपातकालीन फ्लैशर चालू करें और यदि उपलब्ध हो तो पुलआउट लेन का उपयोग करें","वाहन के पटरियों के पार होने तक लगातार हॉर्न बजाएँ","पटरियों को तेज़ी से पार करने के लिए ऊँचे गियर में बदलें","पटरियों का दृश्य अधिकतम करने के लिए सीधे निकटतम रेल पर रुकें"],"explanation":"जब किसी ग्रेड क्रॉसिंग पर रुकना आवश्यक हो, तो अर्कांसस मैनुअल चालकों को निर्देश देता है कि धीरे-धीरे रुकते समय पीछे की ट्रैफिक जाँचें, यदि उपलब्ध हो तो पुलआउट लेन का उपयोग करें, और चार-तरफा फ्लैशर चालू करें; पार करते समय गियर न बदलें। स्रोत: Arkansas Commercial Driver License Manual, Section 2.15.4."},"80":{"q":"अर्कांसस में Commercial Driver Licenses (CDLs) जारी करने के लिए कौन-सी राज्य एजेंसी जिम्मेदार है?","options":["The Arkansas State Police Highway Safety Division","The Arkansas Department of Transportation (ARDOT)","The Federal Motor Carrier Safety Administration (FMCSA)","The Arkansas Department of Finance and Administration (DFA), Office of Driver Services"],"explanation":"अर्कांसस में CDLs Department of Finance and Administration (DFA), Office of Driver Services द्वारा जारी किए जाते हैं, जो चालक लाइसेंसिंग कानून का प्रशासन और प्रवर्तन करता है। स्रोत: Arkansas DFA Office of Driver Services / CDL pages (dfa.arkansas.gov)."},"81":{"q":"अर्कांसस में, आमतौर पर CDL कौशल (सड़क) परीक्षण का संचालन कौन करता है?","options":["आवेदन अपॉइंटमेंट के दौरान कोई भी स्थानीय राजस्व कार्यालय क्लर्क","निर्दिष्ट परीक्षण स्थानों पर Arkansas State Police, या कोई अनुमोदित तृतीय-पक्ष परीक्षक","Arkansas Department of Transportation के वजन-स्टेशन कर्मचारी","केवल निजी CDL स्कूल जो सीधे लाइसेंस जारी करते हैं"],"explanation":"जबकि DFA लाइसेंस जारी करता है, CDL कौशल परीक्षण निर्दिष्ट Arkansas State Police परीक्षण स्थानों पर या अनुमोदित तृतीय-पक्ष परीक्षकों द्वारा संचालित किए जाते हैं। स्रोत: Arkansas DFA Driver Services / Arkansas State Police CDL testing information."},"82":{"q":"अर्कांसस में CDL कौशल परीक्षण देने से पहले, किसी आवेदक को पहले कौन-सी क्रेडेंशियल प्राप्त करनी होगी?","options":["एक Class D ऑपरेटर लाइसेंस एंडोर्समेंट","एक संघीय अंतरराज्यीय संचालन प्राधिकरण संख्या","एक Commercial Learner's Permit (CLP)","एक अस्थायी 30-दिन का वाणिज्यिक सड़क परमिट"],"explanation":"किसी आवेदक के पास अर्कांसस में CDL कौशल परीक्षण देने से पहले एक Commercial Learner's Permit (CLP) होना आवश्यक है। स्रोत: Arkansas DFA CLP page (dfa.arkansas.gov)."},"83":{"q":"अर्कांसस के नियमों के तहत, CDL कौशल परीक्षण देने की अनुमति मिलने से पहले किसी आवेदक को Commercial Learner's Permit (CLP) कितने समय तक रखना होगा?","options":["CLP के प्रारंभिक जारी होने के कम से कम 14 days बाद","CLP के प्रारंभिक जारी होने के कम से कम 30 days बाद","CLP के प्रारंभिक जारी होने के कम से कम 7 days बाद","CLP के प्रारंभिक जारी होने के कम से कम 60 days बाद"],"explanation":"अर्कांसस, संघीय CDL मानक का पालन करते हुए, CLP के प्रारंभिक जारी होने के पहले 14 days में कौशल परीक्षण देने पर रोक लगाता है। स्रोत: Arkansas DFA CLP page (49 CFR 383.25 standard adopted by Arkansas)."},"84":{"q":"ज्ञान परीक्षण दोबारा देने से पहले अर्कांसस में Commercial Learner's Permit (CLP) अधिकतम कितनी अवधि तक वैध रहता है?","options":["जारी होने से दो वर्ष तक","जारी होने से एक वर्ष तक","जारी होने से 90 days तक","जारी होने से चार वर्ष तक"],"explanation":"CLP एक वर्ष तक वैध रहता है; यदि यह समाप्त हो जाता है, तो धारक को नया परमिट जारी होने से पहले सामान्य और कोई भी एंडोर्समेंट ज्ञान परीक्षण दोबारा देना होगा। स्रोत: Arkansas DFA CLP page (consistent with 49 CFR 383.25)."},"85":{"q":"अर्कांसस में पहली बार Class A CDL चाहने वाले एक नए आवेदक को CLP-से-CDL प्रक्रिया के लिए ज्ञान परीक्षण देने से पहले कौन-सा संघीय रूप से आवश्यक प्रशिक्षण पूरा करना होगा?","options":["एक राज्य-संचालित रक्षात्मक ड्राइविंग प्रमाणपत्र पाठ्यक्रम","किसी FMCSA-पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक National Safety Council प्राथमिक चिकित्सा प्रमाणन","12 महीने तक चलने वाली एक नियोक्ता-प्रायोजित अप्रेंटिसशिप"],"explanation":"February 7, 2022 से, पहली बार CDL आवेदकों को परीक्षण से पहले FMCSA Training Provider Registry में सूचीबद्ध किसी प्रदाता के माध्यम से Entry-Level Driver Training (ELDT) पूरा करना होगा। अर्कांसस रजिस्ट्री के माध्यम से पूर्णता सत्यापित करता है। स्रोत: FMCSA ELDT rule / Arkansas DFA CDL information."},"86":{"q":"ELDT सिद्धांत प्रशिक्षण की पूर्णता किस सिस्टम को रिपोर्ट की जाती है जिसे Arkansas DFA CDL जारी करने से पहले जाँचता है?","options":["केवल Arkansas DFA MyDMV पोर्टल","The National Driver Register (NDR)","केवल Commercial Driver License Information System (CDLIS)","The FMCSA Training Provider Registry (TPR)"],"explanation":"प्रशिक्षण प्रदाता ELDT पूर्णता को FMCSA Training Provider Registry (TPR) में प्रस्तुत करते हैं; राज्य लाइसेंसिंग एजेंसी, जिसमें Arkansas DFA शामिल है, कौशल परीक्षण की अनुमति देने या CDL जारी करने से पहले TPR की जाँच करती है। स्रोत: FMCSA Training Provider Registry (tpr.fmcsa.dot.gov)."},"87":{"q":"निम्नलिखित सभी स्थितियों में अर्कांसस में पहली बार के आवेदक के लिए ELDT आवश्यक है, सिवाय:","options":["पहली बार Class A या Class B CDL प्राप्त करना","किसी मौजूदा Class B CDL को Class A CDL में अपग्रेड करना","किसी मौजूदा Class A CDL का बिना किसी नए एंडोर्समेंट के नवीनीकरण करना","पहली बार खतरनाक सामग्री (H) एंडोर्समेंट प्राप्त करना"],"explanation":"ELDT पहली बार के Class A/B CDLs, B से A में अपग्रेड, और पहली बार के S, P, या H एंडोर्समेंट पर लागू होता है। बिना किसी नए एंडोर्समेंट के किसी मौजूदा CDL का सामान्य नवीनीकरण ELDT को ट्रिगर नहीं करता। स्रोत: FMCSA ELDT rule (49 CFR Part 380) as applied in Arkansas."},"88":{"q":"अर्कांसस में CDL कौशल परीक्षण में कौन-से तीन भाग शामिल होते हैं, उस क्रम में जिसमें वे आमतौर पर किए जाते हैं?","options":["लिखित ज्ञान, दृष्टि जाँच, और सड़क पर ड्राइविंग","एयर-ब्रेक जाँच, hazmat हैंडलिंग, और सड़क पर ड्राइविंग","यात्रा-पूर्व निरीक्षण, मूल वाहन नियंत्रण, और सड़क पर ड्राइविंग","मूल वाहन नियंत्रण, ज्ञान परीक्षण, और यात्रा-पूर्व निरीक्षण"],"explanation":"अर्कांसस CDL कौशल परीक्षण के तीन भाग हैं: यात्रा-पूर्व वाहन निरीक्षण, मूल वाहन नियंत्रण कौशल, और सड़क पर ड्राइविंग परीक्षण। स्रोत: Arkansas DFA / Arkansas State Police CDL skills test information (49 CFR 383.113)."},"89":{"q":"अर्कांसस CDL कौशल परीक्षण के मूल वाहन नियंत्रण भाग के दौरान, परीक्षक मुख्य रूप से आवेदक की किस क्षमता का मूल्यांकन करता है:","options":["किसी सीमित क्षेत्र में वाहन को सटीक रूप से चलाना और पीछे ले जाना","संघीय सेवा-घंटे (hours-of-service) सीमाओं को स्मृति से सुनाना","वाहन की सकल संयोजन भार रेटिंग (gross combination weight rating) की गणना करना","आपातकालीन रोडसाइड फ्लेयर प्लेसमेंट का प्रदर्शन करना"],"explanation":"मूल वाहन नियंत्रण चालक की वाहन को सीधी-रेखा बैकिंग, ऑफसेट बैकिंग, और किसी सीमित क्षेत्र में पार्किंग जैसे युद्धाभ्यासों के माध्यम से नियंत्रित और स्थापित करने की क्षमता का परीक्षण करता है। स्रोत: Arkansas DFA / FMCSA skills test standards (49 CFR 383.113)."},"90":{"q":"अर्कांसस द्वारा अपनाए गए संघीय चिकित्सा प्रमाणन नियम हर CLP और CDL धारक से कितनी संभावित संचालन श्रेणियों में स्व-प्रमाणन (self-certify) करने की अपेक्षा करते हैं?","options":["दो श्रेणियाँ","चार श्रेणियाँ","तीन श्रेणियाँ","छह श्रेणियाँ"],"explanation":"हर CLP/CDL धारक को अंतरराज्यीय बनाम राज्य-आंतरिक संचालन और छूट-प्राप्त (excepted) बनाम गैर-छूट-प्राप्त (non-excepted) स्थिति के आधार पर चार श्रेणियों में से एक में स्व-प्रमाणन करना होगा। स्रोत: Arkansas DFA Medical Certification page (49 CFR 383.71)."},"91":{"q":"किस स्व-प्रमाणन श्रेणी में चालक को संघीय DOT शारीरिक योग्यता मानकों को पूरा करना और चिकित्सा परीक्षक का प्रमाणपत्र रखना आवश्यक है?","options":["Excepted Interstate","Excepted Intrastate","Non-Excepted Interstate","Hobby / Personal Use Only"],"explanation":"जो चालक Non-Excepted Interstate के रूप में स्व-प्रमाणन करता है, उसे संघीय DOT शारीरिक योग्यता मानकों (49 CFR 391) को पूरा करना होगा और एक वैध चिकित्सा परीक्षक प्रमाणपत्र बनाए रखना होगा। स्रोत: Arkansas DFA Medical Certification page (49 CFR 383.71)."},"92":{"q":"जो चालक केवल अर्कांसस के भीतर संचालन करता है और संघीय शारीरिक योग्यता आवश्यकताओं के अधीन नहीं है, वह सबसे सटीक रूप से किस रूप में स्व-प्रमाणन करेगा:","options":["Non-Excepted Interstate","Excepted Intrastate","Excepted Interstate","Non-Excepted Federal"],"explanation":"जो चालक केवल राज्य के भीतर संचालन करता है और जिसे संघीय शारीरिक योग्यता मानकों को पूरा करना आवश्यक नहीं है, वह Excepted Intrastate के रूप में स्व-प्रमाणन करता है। स्रोत: Arkansas DFA Medical Certification page (49 CFR 383.71)."},"93":{"q":"जब अर्कांसस में कोई CDL आवेदक Non-Excepted Interstate के रूप में स्व-प्रमाणन करता है, तो शारीरिक परीक्षण करने वाला DOT चिकित्सा परीक्षक होना चाहिए:","options":["Arkansas State Police चिकित्सा इकाई द्वारा नियोजित","आवेदक के गृह काउंटी में कोई भी लाइसेंस प्राप्त फार्मासिस्ट","स्थानीय राजस्व कार्यालय प्रबंधक द्वारा व्यक्तिगत रूप से अनुमोदित","FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध"],"explanation":"गैर-छूट-प्राप्त चालकों को अपना शारीरिक परीक्षण FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध किसी चिकित्सा परीक्षक से कराना होगा, और वह प्रमाणपत्र Office of Driver Services को प्रस्तुत किया जाता है। स्रोत: Arkansas DFA Medical Certification page (49 CFR 391.41 / National Registry)."},"94":{"q":"Arkansas Office of Driver Services को DOT Medical Examiner's Certificate और Self-Certification Affidavit प्रस्तुत करने का निम्नलिखित में से कौन-सा एक स्वीकृत तरीका है?","options":["इसे सीधे FMCSA National Registry वेबसाइट पर पोस्ट करना","इसे किसी भी ट्रैफिक स्टॉप पर रोडसाइड Arkansas State Police ट्रूपर को सौंपना","इसे किसी भी अर्कांसस राजस्व कार्यालय में व्यक्तिगत रूप से लाना, या इसे Office of Driver Services को ईमेल/फैक्स करना","इसे केवल आवेदक के निजी ट्रकिंग नियोक्ता पोर्टल पर अपलोड करना"],"explanation":"अर्कांसस चिकित्सा प्रमाणपत्र और स्व-प्रमाणन को किसी भी राज्य राजस्व कार्यालय में व्यक्तिगत रूप से, Office of Driver Services को डाक से, या DFA द्वारा प्रकाशित ईमेल/फैक्स माध्यमों से स्वीकार करता है। स्रोत: Arkansas DFA Medical Certification / Register Medical Certificate pages."},"95":{"q":"यदि किसी गैर-छूट-प्राप्त अर्कांसस CDL धारक का DOT चिकित्सा परीक्षक प्रमाणपत्र समाप्त हो जाता है और नया प्रस्तुत नहीं किया जाता, तो उसके वाणिज्यिक विशेषाधिकारों का क्या होता है?","options":["CDL को 'Not Certified' स्थिति में बदल दिया जाता है और वाणिज्यिक ड्राइविंग विशेषाधिकार खो जाते हैं","कुछ वर्षों बाद पूरी CDL अवधि समाप्त होने तक कुछ नहीं बदलता","CDL को स्वचालित रूप से एक वर्ष के लिए CLP में डाउनग्रेड कर दिया जाता है","चालक पर जुर्माना लगाया जाता है लेकिन वह पूर्ण वाणिज्यिक विशेषाधिकार बनाए रखता है"],"explanation":"समाप्ति तक एक वर्तमान चिकित्सा कार्ड प्रदान न करने पर CDL को 'Not Certified' चिकित्सा स्थिति में रख दिया जाता है, जिससे वैध प्रमाणपत्र प्रस्तुत होने तक वाणिज्यिक ड्राइविंग विशेषाधिकार हट जाते हैं। स्रोत: Arkansas DFA Medical Certification page."},"96":{"q":"अर्कांसस में CDL का नवीनीकरण करते समय, एक गैर-छूट-प्राप्त चालक को आमतौर पर निम्नलिखित सभी प्रदान करने होते हैं, सिवाय:","options":["मौजूदा वर्ग के लिए एक नया Entry-Level Driver Training (ELDT) प्रमाणपत्र","उनका वर्तमान चालक लाइसेंस","एक पूर्ण Self-Certification Affidavit","एक वर्तमान Medical Examiner's Certificate"],"explanation":"बिना किसी नए एंडोर्समेंट के उसी वर्ग के किसी मौजूदा CDL का नवीनीकरण करने के लिए ELDT की आवश्यकता नहीं है; चालक को अपना वर्तमान लाइसेंस, एक स्व-प्रमाणन शपथपत्र, और (यदि गैर-छूट-प्राप्त है) एक वर्तमान चिकित्सा प्रमाणपत्र की आवश्यकता होती है। स्रोत: Arkansas DFA Driver Services renewal requirements / FMCSA ELDT rule."},"97":{"q":"राज्य-आंतरिक (intrastate, राज्य के भीतर) वाणिज्यिक ड्राइविंग तक सीमित अर्कांसस CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"अर्कांसस राज्य-आंतरिक संचालन के लिए 18 वर्ष की आयु में CDL की अनुमति देता है; अंतरराज्यीय संचालन के लिए चालक का 21 वर्ष का होना आवश्यक है। स्रोत: Arkansas DFA CDL requirements (49 CFR 383 / 391 age standards)."},"98":{"q":"अर्कांसस में CDL आवेदन शुल्क के संबंध में, कौन-सा कथन सही प्रक्रिया-उन्मुख अपेक्षा को दर्शाता है?","options":["अर्कांसस में CDL आवेदन और परीक्षण हमेशा निःशुल्क होते हैं","शुल्क संघीय कानून द्वारा स्थायी रूप से तय है और कभी नहीं बदलता","केवल hazmat एंडोर्समेंट पर कोई शुल्क लगता है; अन्य सभी CDL सेवाएँ निःशुल्क हैं","शुल्क राज्य द्वारा निर्धारित किए जाते हैं और बदल सकते हैं, इसलिए आवेदकों को आवेदन से पहले DFA से वर्तमान राशि की पुष्टि करनी चाहिए"],"explanation":"अर्कांसस CDL शुल्क (लाइसेंस, एंडोर्समेंट, और परीक्षण) राज्य द्वारा निर्धारित किए जाते हैं और परिवर्तन के अधीन हैं, इसलिए आवेदकों को किसी तय आंकड़े पर निर्भर रहने के बजाय DFA से वर्तमान राशियों की पुष्टि करनी चाहिए। स्रोत: Arkansas DFA Driver Services fee schedule (subject to change)."}},"ar":{"0":{"q":"على الطرق السريعة في أركنساس، ما هو أقصى عرض خارجي إجمالي للمركبة (محملة أو غير محملة) قبل أن يصبح التصريح الخاص مطلوباً؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"يحدد قانون أركنساس Arkansas Code Ann. 27-35-206 الحد الأقصى القانوني لعرض المركبة عند 102 inches (8 feet 6 inches)، محملة أو غير محملة؛ وأي عرض يتجاوز ذلك يتطلب تصريحاً للحجم الزائد من ARDOT/شرطة الطرق السريعة في أركنساس."},"1":{"q":"بموجب قانون أركنساس الحالي، ما هو الحد الأقصى لارتفاع المركبة (بما في ذلك حمولتها) المسموح به على الطرق السريعة للولاية دون تصريح خاص؟","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"رفع قانون أركنساس Arkansas Code Ann. 27-35-207، بصيغته المعدلة بموجب Act 871 of 2021 (الساري اعتباراً من July 28, 2021)، حد الارتفاع القانوني من 13'6\" إلى 14 feet. المركبة التي تتجاوز 14 feet تتطلب تصريحاً خاصاً (للارتفاع الزائد)."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة أو المجموعة المسموح به على الطرق السريعة في أركنساس دون تصريح للوزن الزائد؟","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"تماشياً مع المعيار الفيدرالي وقانون أركنساس Arkansas Code Ann. 27-35-203، فإن الحد الأقصى القانوني للوزن الإجمالي هو 80,000 pounds. ويتطلب تجاوزه تصريحاً للوزن الزائد من قسم التصاريح في ARDOT/شرطة الطرق السريعة في أركنساس."},"3":{"q":"في أركنساس، ما هو الحد الأقصى للحمولة التي يمكن نقلها على محور مفرد دون تصريح؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"يحد قانون أركنساس Arkansas Code Ann. 27-35-203 المحور المفرد بـ 20,000 pounds. ويتطابق هذا مع الحد الفيدرالي للمحور المفرد المطبق على الطرق السريعة في أركنساس."},"4":{"q":"ما هو الحد الأقصى القانوني للحمولة على مجموعة محاور مزدوجة (تاندم) في أركنساس دون تصريح؟","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"explanation":"يحد قانون أركنساس Arkansas Code Ann. 27-35-203 المحور المزدوج (تاندم) بـ 34,000 pounds. (بتصريح، قد يصل المحور المزدوج إلى 46,000 pounds، لكن 34,000 هو الحد الأقصى دون تصريح.)"},"5":{"q":"بموجب قانون أركنساس 27-35-203، يُعامل محوران متتاليان على أنهما 'محور مزدوج (تاندم)' عندما تكون المسافة بين مركزيهما:","options":["More than 40 inches but not more than 96 inches","More than 96 inches but not more than 120 inches","Exactly 48 inches","Less than 40 inches"],"explanation":"يعرّف قانون أركنساس Arkansas Code Ann. 27-35-203 المحور المزدوج (تاندم) بأنه محوران متتاليان أو أكثر تكون المسافة بين مركزيهما أكثر من 40 inches وليست أكثر من 96 inches، بحد مجمّع قدره 34,000 pounds."},"6":{"q":"ما هو الحد الأقصى لطول الشاحنة المفردة (المستقيمة) المُشغّلة على الطرق السريعة في أركنساس دون تصريح؟","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"يحد قانون أركنساس Arkansas Code Ann. 27-35-208 المركبة المفردة (المستقيمة) بطول إجمالي قدره 40 feet، محملة أو غير محملة."},"7":{"q":"على الطرق السريعة في أركنساس، ما هو الحد الأقصى لطول نصف المقطورة المُشغّلة بالاقتران مع جرّار شاحنة، والذي لا يمكن للولاية أن تقيّده دونه؟","options":["48 feet","50 feet","53 feet 6 inches","57 feet"],"explanation":"ينص قانون أركنساس Arkansas Code Ann. 27-35-208 على أن الولاية لا يجوز لها أن تفرض حداً لطول نصف المقطورة/المقطورة أقل من 53 feet 6 inches على وحدة مُشغّلة بالاقتران مع جرّار شاحنة."},"8":{"q":"في مجموعة جرّار شاحنة-نصف مقطورة-مقطورة (التوأم/المزدوجة) على الطرق السريعة في أركنساس، ما هو الحد الأقصى لطول كل وحدة مقطورة؟","options":["24 feet","28 feet","33 feet","40 feet"],"explanation":"يحد قانون أركنساس Arkansas Code Ann. 27-35-208 كل نصف مقطورة أو مقطورة في مجموعة جرّار شاحنة-نصف مقطورة-مقطورة (المزدوجة) بطول إجمالي قدره 28 feet، باستثناء أجهزة الاقتران."},"9":{"q":"ما هي المعادلة التي تستخدمها أركنساس لتحديد أقصى وزن مسموح به على مجموعة من المحاور بالنسبة للمسافة بينها؟","options":["The Federal Bridge Formula (Formula B)","The Arkansas Tare Weight Formula","The Gross Combination Ratio Rule","The Tandem Spacing Multiplier"],"explanation":"تطبّق أركنساس معادلة الجسر الفيدرالية (Bridge Formula B)، W = 500[LN/(N-1) + 12N + 36]، لتحديد أقصى وزن يمكن لمجموعة محاور معينة أن تحمله بناءً على عدد المحاور (N) والمسافة (L) بينها."},"10":{"q":"في معادلة الجسر الفيدرالية كما تُطبَّق في أركنساس، W = 500[LN/(N-1) + 12N + 36]، ماذا يمثّل 'N'؟","options":["The number of axles in the group being considered","The net (tare) weight of the vehicle","The number of tires on the drive axle","The nominal speed limit of the highway"],"explanation":"في معادلة الجسر الفيدرالية التي تستخدمها أركنساس، N هو عدد المحاور في المجموعة قيد النظر، وL هي المسافة بالأقدام بين المحاور الخارجية للمجموعة، وW هو أقصى وزن مسموح به."},"11":{"q":"حمولة أحد سائقي الشاحنات عرضها 9 feet 2 inches. على الطرق السريعة في أركنساس، هذه الحمولة:","options":["Is legal because it is under 10 feet","Requires an oversize permit because it exceeds 102 inches","Is legal only on the Interstate system","Requires only a flag, not a permit"],"explanation":"العرض القانوني في أركنساس هو 102 inches (8'6\") بموجب القانون 27-35-206. وحمولة بعرض 9'2\" (110 inches) تتجاوز العرض القانوني وتتطلب تصريحاً للحجم الزائد من ARDOT/شرطة الطرق السريعة في أركنساس."},"12":{"q":"أي جهة تُصدر تصاريح حركة الحجم الزائد والوزن الزائد لنظام الطرق السريعة في ولاية أركنساس؟","options":["The Arkansas Department of Finance and Administration","The Arkansas Department of Transportation through the Arkansas Highway Police Permit Section","The county sheriff in each county of travel","The Federal Motor Carrier Safety Administration"],"explanation":"بموجب قواعد تصاريح ARDOT لعام 2023، تُصدر تصاريح الحجم الزائد/الوزن الزائد لنظام الطرق السريعة للولاية من قِبَل The Arkansas Department of Transportation من خلال قسم التصاريح في شرطة الطرق السريعة في أركنساس (Arkansas Highway Police Permit Section)."},"13":{"q":"متى يحتاج ناقل آلي إلى تصريح للوزن الزائد في أركنساس؟","options":["Only when the load can be reduced by splitting it","When the vehicle exceeds the legal gross, single-axle, or tandem-axle weight limits","Any time the trip crosses a county line","Only when traveling at night"],"explanation":"وفقاً لقواعد تصاريح ARDOT والقانون 27-35-203/210، يكون تصريح الوزن الزائد مطلوباً كلما تجاوزت المركبة الحدود القانونية (80,000 lbs إجمالي، أو 20,000 lbs للمحور المفرد، أو 34,000 lbs للمحور المزدوج، أو حد معادلة الجسر). وتُصدر هذه التصاريح عموماً للحمولات غير القابلة للتجزئة فقط."},"14":{"q":"تصاريح الوزن الزائد في أركنساس تُصدر عموماً فقط للحمولات التي تكون:","options":["Divisible into smaller legal loads","Nondivisible (cannot reasonably be reduced to legal weight)","Carried at less than 45 mph","Owned by a government agency"],"explanation":"بموجب قواعد تصاريح ARDOT، يُصدر تصريح الوزن الزائد للحمولات غير القابلة للتجزئة، أي تلك التي لا يمكن تقسيمها بشكل معقول للوفاء بحدود الوزن القانونية. أما الحمولات القابلة للتجزئة فيجب تقليلها إلى الوزن القانوني بدلاً من منح تصريح لها."},"15":{"q":"تسمح أركنساس بتصريح سنوي لمجموعة جرّار شاحنة/نصف مقطورة مكونة من خمسة محاور على الأقل تنقل محاصيل زراعية أو بستانية في حالتها الطبيعية حتى أي وزن إجمالي؟","options":["84,000 pounds","90,000 pounds","100,000 pounds","112,000 pounds"],"explanation":"يُجيز قانون أركنساس Arkansas Code Ann. 27-35-210 تصريحاً سنوياً لمجموعة جرّار شاحنة/نصف مقطورة بحد أدنى خمسة محاور تنقل محاصيل زراعية أو بستانية في حالتها الطبيعية حتى وزن إجمالي قدره 100,000 pounds."},"16":{"q":"في حركة مُصرّح بها في أركنساس، يمكن تحميل مجموعة المحاور المزدوجة (تاندم) حتى حد أقصى قدره:","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"explanation":"بموجب قواعد تصاريح ARDOT، يمكن لمجموعة المحاور المزدوجة المُصرّح بها أن تحمل حتى 46,000 pounds (دون أن يتجاوز أي محور مفرد 23,000 pounds)، مقارنة بالحد القانوني دون تصريح البالغ 34,000 pounds في القانون 27-35-203."},"17":{"q":"جرّار-نصف مقطورة بخمسة محاور في أركنساس محمّل بوزن إجمالي 80,000 lbs، و20,000 lbs على محور التوجيه، و34,000 lbs على المحور المزدوج للدفع، و26,000 lbs على المحور المزدوج للمقطورة. أي حالة تتجاوز الحد القانوني؟","options":["The gross weight","The steer (single) axle weight","The drive tandem weight","None of these exceed their legal limit"],"explanation":"وفقاً للقانون 27-35-203، فإن الحدود القانونية هي 80,000 lbs إجمالي، و20,000 lbs للمحور المفرد، و34,000 lbs للمحور المزدوج. كل قيمة هنا عند حدها أو دونه، لذا لا يتجاوز أي محور أو الوزن الإجمالي الحد القانوني (ولا تزال مسافات معادلة الجسر سارية)."},"18":{"q":"أي عبارة بشأن الطول الإجمالي للمجموعة على الطرق السريعة في أركنساس صحيحة بالنسبة لجرّار شاحنة ونصف مقطورة مفردة؟","options":["Arkansas caps the overall tractor-semitrailer combination at exactly 65 feet","Arkansas does not impose a fixed overall length limit on a tractor-and-single-semitrailer combination; the semitrailer itself may be up to 53'6\"","Arkansas caps the overall combination at 60 feet on all roads","Arkansas allows no semitrailer longer than 48 feet"],"explanation":"يحد قانون أركنساس Arkansas Code Ann. 27-35-208 طول نصف المقطورة (لا يجوز تقييد طول يقل عن 53'6\") لكنه لا يضع حداً ثابتاً للطول الإجمالي لمجموعة جرّار شاحنة مع نصف مقطورة مفردة، تماشياً مع قواعد STAA الفيدرالية."},"19":{"q":"تبلغ شاحنة ذات منصة مسطحة (فلات بد) في أركنساس ارتفاعاً قدره 14 feet 4 inches حتى أعلى حمولتها. دون تصريح، فإن هذه المركبة:","options":["Legal, because the limit is 15 feet","Over height and requires a special (over-height) permit","Legal only off the Interstate system","Legal because height is not regulated in Arkansas"],"explanation":"الارتفاع القانوني الحالي في أركنساس هو 14 feet بموجب القانون 27-35-207 (بصيغته المعدلة بموجب Act 871 of 2021). وحمولة يبلغ ارتفاعها 14'4\" تتجاوز 14 feet وتتطلب تصريحاً للارتفاع الزائد من ARDOT/شرطة الطرق السريعة في أركنساس."},"20":{"q":"في أركنساس، أي فئة من رخصة القيادة التجارية CDL مطلوبة لتشغيل مجموعة من المركبات بتصنيف وزن مجموعة إجمالي (GCWR) قدره 26,001 pounds أو أكثر، حيث يكون للوحدة المقطورة تصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 pounds؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تعرّف أركنساس رخصة CDL من الفئة Class A بأنها أي مجموعة من المركبات بتصنيف GCWR قدره 26,001 pounds أو أكثر، شاملةً وحدة مقطورة بتصنيف GVWR يزيد عن 10,000 pounds. المصدر: دليل CDL في أركنساس، القسم 1 (التصنيفات)؛ صفحة CDL لمكتب خدمات السائقين في Arkansas DFA."},"21":{"q":"بموجب قواعد أركنساس، فإن مركبة مفردة بتصنيف GVWR قدره 26,001 pounds أو أكثر (أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز تصنيف GVWR لها 10,000 pounds) تتطلب أي فئة من رخصة CDL؟","options":["Class B","Class A","Class C","Class M"],"explanation":"تعرّف أركنساس رخصة CDL من الفئة Class B بأنها أي مركبة مفردة بتصنيف GVWR قدره 26,001 pounds أو أكثر، أو أي مركبة من هذا القبيل تقطر وحدة لا يتجاوز تصنيف GVWR لها 10,000 pounds. المصدر: دليل CDL في أركنساس، القسم 1 (التصنيفات)؛ صفحة CDL لـ Arkansas DFA."},"22":{"q":"في أركنساس، فإن المركبة التي لا تنطبق عليها تعريفات الفئة Class A أو Class B لكنها مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق) أو تُستخدم لنقل مواد خطرة تتطلب لوحات تحذير، تندرج تحت أي فئة من رخصة CDL؟","options":["Class A","Class C","Class B","Class P"],"explanation":"تعرّف أركنساس رخصة CDL من الفئة Class C بأنها مركبة لا تنطبق عليها الفئة Class A أو B لكنها مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق، أو تنقل مواد خطرة تتطلب لوحات تحذير أو عاملاً/سُمّاً محدداً بموجب 42 CFR Part 73. المصدر: دليل CDL في أركنساس، القسم 1؛ صفحة CDL لـ Arkansas DFA."},"23":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في أركنساس مقصورة على قيادة مركبة آلية تجارية داخل الولاية فقط (التجارة داخل الولاية)؟","options":["16 years old","18 years old","19 years old","21 years old"],"explanation":"تشترط أركنساس أن يكون عمر السائق 18 years old على الأقل لتشغيل مركبة آلية تجارية في التجارة داخل الولاية (داخل أركنساس فقط). المصدر: متطلبات CDL لمكتب خدمات السائقين في Arkansas DFA."},"24":{"q":"ما هو الحد الأدنى للعمر المطلوب للحصول على رخصة CDL في أركنساس صالحة للقيادة عبر حدود الولايات (التجارة بين الولايات)؟","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"تشترط أركنساس (تبعاً للمعايير الفيدرالية) أن يكون عمر السائق 21 years old على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات. ويقتصر السائق الذي يبلغ عمره 18-20 على التشغيل داخل الولاية. المصدر: متطلبات CDL لمكتب خدمات السائقين في Arkansas DFA."},"25":{"q":"أي تصريح مطلوب في أركنساس لتشغيل مركبة صهريج مصممة لنقل سائل أو غاز في خزان بسعة مصنّفة فردية تزيد عن 119 gallons وسعة مصنّفة إجمالية قدرها 1,000 gallons أو أكثر؟","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"تشترط أركنساس تصريح N (مركبة الصهريج) للمركبات المصممة لنقل مواد سائلة أو غازية في خزان أو خزانات بسعة مصنّفة فردية تزيد عن 119 gallons وسعة مصنّفة إجمالية قدرها 1,000 gallons أو أكثر. المصدر: دليل CDL في أركنساس، القسم 1 (التصاريح) والقسم 8."},"26":{"q":"في أركنساس، أي تصريح مطلوب لقيادة مركبة تنقل مادة مصنّفة على أنها خطرة ويُشترط وضع لوحات تحذير لها بموجب 49 CFR Part 172؟","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"explanation":"تشترط أركنساس تصريح H (المواد الخطرة)، بصرف النظر عن فئة المركبة، لأي سائق ينقل مادة مصنّفة على أنها خطرة بموجب 49 U.S.C. 5103 ويُشترط وضع لوحات تحذير لها بموجب 49 CFR Part 172. المصدر: دليل CDL في أركنساس، القسم 1 (التصاريح)."},"27":{"q":"بالإضافة إلى اجتياز اختبار المعرفة التحريري، ما الخطوة الإضافية التي تشترطها أركنساس قبل إصدار تصريح المواد الخطرة (H)؟","options":["A vision exam by an ophthalmologist","A TSA security threat assessment with fingerprints and a background check","A second road skills test in a tank vehicle","A notarized employer sponsorship letter"],"explanation":"للحصول على تصريح HazMat أو تجديده أو نقله، تشترط أركنساس تقييماً أمنياً للتهديد من TSA يشمل أخذ البصمات وفحصاً فيدرالياً للسوابق (السجلات الجنائية وسجلات الهجرة وسجلات FBI). وينبغي على السائقين إتاحة 90 يوماً على الأقل. المصدر: صفحة تصريح المواد الخطرة لـ Arkansas DFA؛ دليل CDL في أركنساس، القسم 1."},"28":{"q":"أي تصريح تشترطه أركنساس على السائق الذي يرغب في قطر مقطورات مزدوجة أو ثلاثية؟","options":["T endorsement","N endorsement","S endorsement","X endorsement"],"explanation":"تشترط أركنساس تصريح T (المزدوجة/الثلاثية) لقطر المقطورات المزدوجة أو الثلاثية؛ ويجب على المتقدم اجتياز اختبار معرفة حول المشكلات المرتبطة بقطر مقطورات متعددة. المصدر: دليل CDL في أركنساس، القسم 1 (التصاريح) والقسم 7."},"29":{"q":"في أركنساس، يجب على السائق الذي يرغب في تشغيل مركبة مصممة لنقل 16 شخصاً أو أكثر، بما في ذلك السائق، الحصول على أي تصريح؟","options":["S endorsement","T endorsement","P endorsement","N endorsement"],"explanation":"تشترط أركنساس تصريح P (الركاب) لسائقي المركبة المصممة لنقل 16 شخصاً أو أكثر بما في ذلك السائق. ويجب على المتقدم اجتياز اختبار معرفة واختبار مهارات في مركبة ركاب. المصدر: دليل CDL في أركنساس، القسم 1 (التصاريح) والقسم 4."},"30":{"q":"أي تصريح يجب أن يحمله السائق في أركنساس لقيادة حافلة مدرسية، بالإضافة إلى تصريح الركاب (P)؟","options":["H endorsement","T endorsement","S endorsement","X endorsement"],"explanation":"تشترط أركنساس تصريح S (الحافلة المدرسية) لقيادة حافلة مدرسية؛ ويجب على السائق اجتياز اختبار معرفة خاص بالحافلة المدرسية واختبار مهارات في حافلة مدرسية، ويسري التصريح على أي فئة (A أو B أو C). المصدر: دليل CDL في أركنساس، القسم 1 (التصاريح) والقسم 10."},"31":{"q":"في أركنساس، يجب على سائق مركبة صهريج الذي يتعين عليه أيضاً نقل مواد خطرة تتطلب لوحات تحذير الحصول على أي تصريح مجمّع واحد؟","options":["T endorsement","X endorsement","P endorsement","S endorsement"],"explanation":"تُصدر أركنساس تصريح X كتصريح مجمّع للمواد الخطرة ومركبة الصهريج؛ ويجب على السائق اجتياز اختباري المعرفة لكل من مركبات الصهريج والمواد الخطرة. المصدر: دليل CDL في أركنساس، القسم 1 (التصاريح)."},"32":{"q":"وفقاً لدليل CDL في أركنساس، أي مجموعة من التصاريح هي الوحيدة التي يمكن إضافتها إلى تصريح المتعلم التجاري (CLP)؟","options":["H, N, and T","P, H, and X","P, S, and N","T, S, and H"],"explanation":"ينص دليل CDL في أركنساس على أن التصاريح الوحيدة التي يمكن إضافتها إلى CLP هي الركاب (P) والحافلة المدرسية (S) ومركبة الصهريج (N). ولا يمكن إصدار تصريح المواد الخطرة (H) على CLP. المصدر: دليل CDL في أركنساس، القسم 1 (التصاريح/CLP)."},"33":{"q":"في أركنساس، عندما يُصدر CLP بتصريح مركبة الصهريج (N)، ما القيد الذي يجب أن يحمله؟","options":["No interstate operation (K)","No air brake equipped CMV (L)","No manual transmission (E)","No cargo in a CMV tank vehicle (X)"],"explanation":"تشترط أركنساس أن يحمل CLP الصادر بتصريح N أيضاً القيد X (ممنوع نقل البضائع في مركبة صهريج CMV)؛ ويجوز لحامله تشغيل خزان فارغ فقط تم تنظيفه من أي بقايا. المصدر: دليل CDL في أركنساس، القسم 1 (القيود)."},"34":{"q":"بموجب قواعد CLP في أركنساس والقواعد الفيدرالية، كم يجب أن ينتظر حامل CLP بعد الإصدار الأولي قبل أن يصبح مؤهلاً لخوض اختبار مهارات CDL؟","options":["7 days","10 days","14 days","30 days"],"explanation":"تطبّق أركنساس القاعدة الفيدرالية التي تقضي بأن حامل CLP غير مؤهل لخوض اختبار مهارات CDL خلال أول 14 days بعد الإصدار الأولي لـ CLP. المصدر: صفحة تصريح المتعلم التجاري (CLP) لـ Arkansas DFA؛ 49 CFR 383.25."},"35":{"q":"كم المدة التي يكون فيها تصريح المتعلم التجاري (CLP) في أركنساس صالحاً قبل أن يتعين على الحامل إعادة خوض اختباري المعرفة العام والخاص بالتصاريح؟","options":["Up to 60 days","Up to 180 days","Up to 1 year","Up to 2 years"],"explanation":"يكون CLP في أركنساس صالحاً لمدة تصل إلى 1 year؛ وبعد انتهاء الصلاحية يجب على الحامل إعادة خوض اختباري المعرفة العام والخاص بالتصاريح. المصدر: صفحة تصريح المتعلم التجاري (CLP) لـ Arkansas DFA."},"36":{"q":"أي جهة حكومية تُصدر رخصة القيادة التجارية (CDL) في أركنساس؟","options":["Arkansas State Police","Arkansas Department of Finance and Administration, Office of Driver Services","Arkansas Department of Transportation (ARDOT)","Federal Motor Carrier Safety Administration"],"explanation":"في أركنساس، تُصدر رخصة CDL من قِبَل Department of Finance and Administration (DFA)، Office of Driver Services. وتتولى ARDOT الطرق/التصاريح وتُعد FMCSA الجهة التنظيمية الفيدرالية، لكن جهة إصدار الرخص هي DFA Driver Services. المصدر: صفحة CDL لـ Arkansas DFA Driver Services."},"37":{"q":"عند التقدم للحصول على رخصة CDL أو CLP في أركنساس، أي مجموعة من الإثباتات يشترط مكتب خدمات السائقين على المتقدم تقديمها؟","options":["Only a Social Security card and a utility bill","Only a U.S. passport","Proof of identity/date of birth, Social Security number, Arkansas residency, and lawful presence","A high school diploma and proof of employment"],"explanation":"تشترط Arkansas DFA على المتقدمين تقديم إثبات الهوية وتاريخ الميلاد، وإثبات رقم الضمان الاجتماعي، وإثبات الإقامة في أركنساس (العنوان الحالي)، وإثبات التواجد القانوني/الوجود القانوني في الولايات المتحدة. المصدر: متطلبات الوثائق لدى Arkansas DFA Driver Services ('Do You Have What You Need?')."},"38":{"q":"بموجب قواعد التدريب الفيدرالي لسائقي المبتدئين (ELDT) المطبقة في أركنساس (السارية اعتباراً من Feb. 7, 2022)، أين يجب على المتقدم لأول مرة إكمال التدريب المطلوب قبل الاختبار؟","options":["Any community college in Arkansas","An Arkansas DFA revenue office","A provider listed on the FMCSA Training Provider Registry (TPR)","An employer's in-house orientation only"],"explanation":"تشترط ELDT على المتقدمين لأول مرة للفئة Class A/B والمتقدمين لتصريح P أو S أو H إكمال التدريب لدى مزوّد مدرج في FMCSA Training Provider Registry قبل الاختبار الذي تجريه الولاية؛ وبالنسبة لـ H يكون التدريب نظرياً فقط قبل اختبار المعرفة، بينما تتطلب Class A/B وP وS تدريباً نظرياً بالإضافة إلى تدريب عملي خلف المقود قبل اختبار المهارات. المصدر: قاعدة ELDT لـ FMCSA (49 CFR Part 380)، السارية اعتباراً من Feb. 7, 2022؛ FMCSA Training Provider Registry."},"39":{"q":"عند التقدم للحصول على رخصة CDL في أركنساس، يجب على السائق أن يصرّح ذاتياً بانتمائه إلى إحدى فئات الشهادة الطبية الأربع. أي مما يلي يُعد إحدى تلك الفئات الأربع؟","options":["Recreational interstate","Hazmat-exempt interstate","Provisional intrastate","Non-excepted interstate"],"explanation":"يجب على السائقين في أركنساس التصريح الذاتي بالانتماء إلى إحدى أربع فئات: Non-excepted Interstate أو Excepted Interstate أو Non-excepted Intrastate أو Excepted Intrastate. ويجب على سائقي Non-excepted interstate الاحتفاظ بشهادة فاحص طبي فيدرالي. المصدر: دليل CDL في أركنساس، القسم 1.2 (التصريح الذاتي)؛ 49 CFR 383.71."},"40":{"q":"في أركنساس، يُعتبر الشخص قائداً لمركبة آلية تجارية (CMV) تحت تأثير الكحول وعرضةً لإسقاط الأهلية إذا كان تركيز الكحول في دمه (BAC) عند أي مستوى أو أعلى منه؟","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"تتبنى أركنساس المعيار الفيدرالي لمركبات CMV: تشغيل مركبة CMV بتركيز BAC قدره 0.04% أو أكثر يُعد قيادة تحت التأثير ومخالفة كبرى تستوجب إسقاط الأهلية، وهو نصف حد 0.08% للسائقين غير التجاريين. المصدر: مخالفات CDL/CMV لـ Arkansas DFA؛ Ark. Code 27-23-112؛ 49 CFR 383.51."},"41":{"q":"بموجب قانون أركنساس، ما هو الحد الأدنى لفترة إسقاط الأهلية لأول مخالفة كبرى لحامل رخصة CDL (مثل القيادة تحت التأثير في مركبة CMV) عند عدم نقل مواد خطرة تتطلب لوحات تحذير؟","options":["1 year","60 days","3 years","6 months"],"explanation":"تؤدي أول مخالفة كبرى (القيادة تحت التأثير، أو BAC قدره 0.04 أو أكثر، أو رفض الاختبار، أو مغادرة موقع الحادث، إلخ) إلى إسقاط أهلية CDL لمدة 1 year في أركنساس. المصدر: مخالفات CDL/CMV لـ Arkansas DFA؛ Ark. Code 27-23-112؛ 49 CFR 383.51."},"42":{"q":"في أركنساس، إذا ارتكب سائق أول مخالفة كبرى أثناء تشغيل مركبة CMV تنقل مواد خطرة تتطلب لوحات تحذير، فإن فترة إسقاط الأهلية تزداد إلى:","options":["3 years","1 year","5 years","Lifetime"],"explanation":"تزيد أركنساس فترة إسقاط الأهلية لأول مخالفة كبرى من 1 year إلى 3 years عندما تقع المخالفة أثناء نقل مواد خطرة تتطلب لوحات تحذير. المصدر: مخالفات CDL/CMV لـ Arkansas DFA؛ Ark. Code 27-23-112؛ 49 CFR 383.51."},"43":{"q":"ما هي فترة إسقاط الأهلية في أركنساس لثاني مخالفة كبرى يرتكبها حامل رخصة CDL في حادثة منفصلة؟","options":["Lifetime","10 years","3 years","5 years"],"explanation":"تؤدي ثاني مخالفة كبرى إلى إسقاط أهلية CDL مدى الحياة (دائم) في أركنساس. المصدر: مخالفات CDL/CMV لـ Arkansas DFA؛ Ark. Code 27-23-112؛ 49 CFR 383.51."},"44":{"q":"رفض الخضوع لاختبار كحول/BAC مطلوب أثناء تشغيل مركبة CMV في أركنساس يؤدي إلى أي إسقاط للأهلية في أول حدوث له؟","options":["1 year","90 days","30 days","No disqualification, only a fine"],"explanation":"يُعامَل رفض الاختبار كمخالفة كبرى، ويحمل نفس إسقاط الأهلية لمدة 1 year كالقيادة تحت التأثير (3 years في حال نقل مواد خطرة تتطلب لوحات تحذير). ويندرج الرفض ضمن قاعدة الموافقة الضمنية في أركنساس لمشغّلي CMV. المصدر: Ark. Code 27-23-112؛ مخالفات CDL/CMV لـ Arkansas DFA؛ 49 CFR 383.51."},"45":{"q":"بموجب نص الموافقة الضمنية في أركنساس للسائقين التجاريين، فإن الشخص الذي يشغّل مركبة CMV في الولاية يُعتبر قد أعطى موافقته على:","options":["Testing of blood, breath, or urine for alcohol or controlled substances","Random vehicle searches without cause","Waiving the right to a hearing on any disqualification","Annual mandatory drug rehabilitation"],"explanation":"تنص قاعدة الموافقة الضمنية في أركنساس على أن أي شخص يقود مركبة CMV يُعتبر قد وافق على اختبار الكحول/المواد الخاضعة للرقابة المطلوب لإنفاذ قواعد القيادة تحت التأثير وقاعدة 0.04%. المصدر: Ark. Code 27-23-112/27-23-113؛ مخالفات CDL/CMV لـ Arkansas DFA."},"46":{"q":"حامل رخصة CDL في أركنساس الذي يتبين وجود أي كمية مقاسة أو مكتشفة من الكحول لديه (دون 0.04%) أثناء تشغيل مركبة CMV يجب أن:","options":["Placed out of service for 24 hours","Disqualified for 1 year","Fined $2,500 and disqualified for 60 days","Arrested for DUI immediately"],"explanation":"يحظر قانون أركنساس 27-23-113 تشغيل مركبة CMV مع وجود أي كحول مقاس أو مكتشف؛ ويُوضَع السائق المخالف خارج الخدمة لمدة 24 hours. ولا يسري إسقاط الأهلية الكامل للقيادة تحت التأثير إلا عند 0.04% أو أعلى. المصدر: Ark. Code 27-23-113."},"47":{"q":"في أركنساس، ثاني مخالفة مرورية خطيرة تُرتكب في حادثة منفصلة خلال فترة 3 years تؤدي إلى إسقاط الأهلية لأي مدة؟","options":["60 days","30 days","120 days","1 year"],"explanation":"مخالفتان مروريتان خطيرتان في حادثتين منفصلتين خلال 3 years تؤديان إلى إسقاط الأهلية لمدة 60 days في أركنساس. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"48":{"q":"ثالث مخالفة مرورية خطيرة (أو لاحقة) في حوادث منفصلة خلال فترة 3 years تؤدي إلى أي إسقاط للأهلية في أركنساس؟","options":["120 days","60 days","1 year","90 days"],"explanation":"ثلاث مخالفات مرورية خطيرة أو أكثر في حوادث منفصلة خلال 3 years تؤدي إلى إسقاط الأهلية لمدة 120 days في أركنساس. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"49":{"q":"أي مما يلي يُصنَّف كمخالفة مرورية خطيرة لحامل رخصة CDL في أركنساس (وليست مخالفة كبرى)؟","options":["Excessive speeding, 15 mph or more over the limit","Driving a CMV with a 0.04% BAC","Leaving the scene of an accident in a CMV","Using a CMV to commit a felony"],"explanation":"السرعة المفرطة (15 mph أو أكثر فوق الحد)، والقيادة المتهورة، وتغيير المسارات غير السليم/المتقلب، والاقتراب الشديد من المركبة الأمامية، والمراسلة النصية/استخدام الهاتف المحمول باليد كلها مخالفات مرورية خطيرة. أما الخيارات الأخرى المذكورة فهي مخالفات كبرى. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"50":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3 years المطلوبة قبل أن تُفعَّل أي فترة إسقاط للأهلية في أركنساس؟","options":["2","1","3","4"],"explanation":"المخالفة الخطيرة الواحدة لا تُسقط الأهلية؛ فأول إسقاط للأهلية (60 days) يُفعَّل بثاني مخالفة خطيرة خلال 3 years، وثالثة تُفعِّل 120 days. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"51":{"q":"ما هو الحد الأدنى لإسقاط الأهلية لأول إدانة لحامل رخصة CDL في أركنساس بمخالفة معبر سكة حديد مع طريق سريع أثناء تشغيل مركبة CMV؟","options":["60 days","30 days","120 days","1 year"],"explanation":"تحمل أول مخالفة لمعبر سكة حديد مع طريق سريع حداً أدنى لإسقاط الأهلية قدره 60 days في أركنساس. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"52":{"q":"ثاني مخالفة لمعبر سكة حديد مع طريق سريع خلال فترة 3 years تؤدي إلى أي حد أدنى لإسقاط الأهلية في أركنساس؟","options":["120 days","60 days","1 year","90 days"],"explanation":"تحمل ثاني مخالفة لمعبر سكة حديد خلال 3 years حداً أدنى لإسقاط الأهلية قدره 120 days في أركنساس. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"53":{"q":"ثالث مخالفة لمعبر سكة حديد مع طريق سريع خلال فترة 3 years تؤدي إلى أي حد أدنى لإسقاط الأهلية في أركنساس؟","options":["1 year","120 days","180 days","60 days"],"explanation":"تحمل ثالث مخالفة لمعبر سكة حديد خلال 3 years حداً أدنى لإسقاط الأهلية قدره 1 year في أركنساس. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"54":{"q":"أي إجراء يُعد مخالفة لمعبر سكة حديد مع طريق سريع يمكن أن تُسقط أهلية حامل رخصة CDL في أركنساس؟","options":["Failing to have enough space to drive completely through the crossing without stopping","Driving 5 mph over the limit near tracks","Sounding the horn before crossing","Stopping more than 15 feet from the nearest rail"],"explanation":"تشمل مخالفات معابر السكة الحديد عدم الإبطاء والتحقق من القطارات، وعدم التوقف عند الاقتضاء، وعدم توفر مساحة لإخلاء المعبر، وعدم الامتثال لأجهزة التحكم المروري عند المعبر، وعدم كفاية خلوص الهيكل السفلي. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"55":{"q":"ما هو الحد الأدنى لفترة إسقاط الأهلية لأول إدانة لحامل رخصة CDL في أركنساس بمخالفة أمر إخراج سائق أو مركبة من الخدمة (OOS)؟","options":["180 days","60 days","1 year","90 days"],"explanation":"تحمل أول إدانة بمخالفة أمر الإخراج من الخدمة حداً أدنى لإسقاط الأهلية قدره 180 days (حتى 1 year) في أركنساس. المصدر: Ark. Code 27-23-112/27-23-114؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"56":{"q":"ثاني إدانة خلال 10 years بمخالفة أمر الإخراج من الخدمة تؤدي إلى أي حد أدنى لإسقاط الأهلية في أركنساس؟","options":["2 years","180 days","1 year","5 years"],"explanation":"تحمل ثاني مخالفة لأمر OOS خلال 10 years حداً أدنى لإسقاط الأهلية قدره 2 years (حتى 5 years) في أركنساس. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"57":{"q":"بالإضافة إلى إسقاط الأهلية، فإن السائق المُدان بمخالفة أمر الإخراج من الخدمة في أركنساس يخضع لغرامة مدنية لا تقل عن أي مبلغ لأول إدانة؟","options":["$2,500","$1,000","$5,000","$500"],"explanation":"تفرض أركنساس غرامة مدنية لا تقل عن $2,500 على السائق لأول مخالفة لأمر الإخراج من الخدمة (ولا تقل عن $5,000 للثانية)، بالإضافة إلى إسقاط الأهلية. المصدر: Ark. Code 27-23-114."},"58":{"q":"بموجب قواعد أركنساس والقواعد الفيدرالية، كيف يُعامَل استخدام سائق CDL لهاتف محمول باليد أو المراسلة النصية أثناء قيادة مركبة CMV لأغراض إسقاط الأهلية؟","options":["As a serious traffic violation that, on repeat offenses, can lead to disqualification","As a major offense with a 1-year disqualification","As a lifetime-disqualifying offense","It carries no disqualification consequence, only a citation"],"explanation":"المراسلة النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة CMV هي مخالفة مرورية خطيرة؛ وتُحسب الإدانات المتعددة ضمن إسقاط الأهلية عند المخالفتين (60 days)/الثلاث مخالفات (120 days)، مع غرامات تصل إلى $2,750 للسائقين. المصدر: دليل CDL في أركنساس؛ Ark. Code 27-51-1504؛ FMCSA 49 CFR 383.51/392.80-82."},"59":{"q":"حامل رخصة CDL في أركنساس الذي يستخدم مركبة CMV في ارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة يواجه أي إسقاط للأهلية؟","options":["Lifetime, with no possibility of reinstatement","1 year","3 years","10 years"],"explanation":"استخدام مركبة CMV لتصنيع أو توزيع أو صرف مواد خاضعة للرقابة هو مخالفة كبرى تحمل إسقاطاً إلزامياً للأهلية مدى الحياة دون إمكانية إعادة الترخيص، وهو يختلف عن حالات الحظر مدى الحياة الأخرى التي قد تسمح بإعادة الترخيص بعد 10 years. المصدر: Ark. Code 27-23-112؛ دليل CDL في أركنساس؛ 49 CFR 383.51."},"60":{"q":"في ولاية أركنساس، عندما يتعين على حافلة أو مركبة تحمل لافتات مواد خطرة التوقف عند ملتقى السكة الحديدية مع الطريق، على أي مسافة من أقرب سكة يجب أن تتوقف؟","options":["ليس أقرب من 15 قدمًا وليس أبعد من 50 قدمًا","ليس أقرب من 10 أقدام وليس أبعد من 40 قدمًا","ليس أقرب من 25 قدمًا وليس أبعد من 75 قدمًا","ليس أقرب من 5 أقدام وليس أبعد من 15 قدمًا"],"explanation":"تشترط أركنساس على الحافلات ومركبات المواد الخطرة (HazMat) التي تحمل لافتات أن تتوقف ليس أقرب من 15 قدمًا وليس أبعد من 50 قدمًا من أقرب سكة، حيث يتمتع السائق بأفضل رؤية للقضبان. المصدر: دليل رخصة القيادة التجارية لولاية أركنساس، الأقسام 2.15 و4.3.5 و9."},"61":{"q":"بموجب قانون \"الابتعاد\" (Move Over) في أركنساس، ماذا يجب على السائق على طريق متعدد المسارات فعله عند الاقتراب من مركبة مرخصة متوقفة وأضواؤها وامضة؟","options":["التوقف توقفًا تامًا حتى تتحرك المركبة المرخصة","الانتقال إلى أبعد مسار ممكن عن المركبة المتوقفة حتى تجاوزها بأمان","الحفاظ على السرعة المحددة وإطلاق البوق أثناء المرور","الانتقال إلى المسار الأقرب إلى المركبة المتوقفة للحفاظ على انسياب حركة المرور"],"explanation":"يشترط قانون أركنساس 27-51-310 على السائقين على طريق متعدد المسارات الانتقال إلى أبعد مسار أو موضع ممكن عن المركبة المرخصة المتوقفة والبقاء هناك حتى تجاوزها بأمان. المصدر: Ark. Code Ann. 27-51-310 (قانون الابتعاد Move Over)."},"62":{"q":"على طريق سريع في أركنساس غير مقيد الوصول، ما هي السرعة القصوى القانونية لشاحنة بسعة طن ونصف فأكثر؟","options":["55 mph","60 mph","50 mph","65 mph"],"explanation":"تحدد أركنساس حدًا أقصى قدره 50 mph للشاحنات بسعة طن ونصف فأكثر على الطرق السريعة غير المقيدة الوصول، مقارنةً بـ 60 mph للمركبات الأخرى في تلك المواقع نفسها. المصدر: Ark. Code Ann. 27-51-201."},"63":{"q":"في أركنساس، عندما تتوقف حافلة مدرسية على طريق بمسارين وتُشغّل أضواءها الحمراء التحذيرية المتناوبة لتحميل أو إنزال الركاب، أي السائقين يجب أن يتوقفوا؟","options":["فقط السائقون المسافرون خلف الحافلة في الاتجاه نفسه","فقط السائقون في المسار المجاور مباشرةً للحافلة","فقط السائقون على بُعد 100 قدم من الحافلة","السائقون الذين يقابلون الحافلة أو يتجاوزونها من أي اتجاه"],"explanation":"على طريق بمسارين، يشترط قانون أركنساس 27-51-1004 على كل سائق يقابل الحافلة أو يتجاوزها من أي اتجاه أن يتوقف توقفًا تامًا أثناء وميض الأضواء الحمراء. المصدر: Ark. Code Ann. 27-51-1004."},"64":{"q":"ما هو قانون أركنساس لعام 2021 الذي يقصر استخدام المسار الأقصى إلى اليسار على طريق متعدد المسارات على التجاوز فقط؟","options":["القانون رقم 1054 لعام 2007 (Act 1054 of 2007)","القانون رقم 1090 لعام 2021 (Act 1090 of 2021)","القانون رقم 27 لعام 2021 (Act 27 of 2021)","القانون رقم 310 لعام 2019 (Act 310 of 2019)"],"explanation":"يخصص القانون رقم 1090 لعام 2021 (Act 1090 of 2021) المسار الأقصى إلى اليسار للتجاوز على الطرق متعددة المسارات؛ وباستثناء الحالات التي تكون فيها المسارات مسدودة، يجب على السائقين استخدام المسارات اليمنى للسير. المصدر: Act 1090 of 2021؛ إشعار ARDOT العام بشأن قانون القيادة في المسار الأيسر."},"65":{"q":"إذا تعيّن على مركبة تجارية التوقف على كتف طريق سريع في أركنساس، خلال أي مدة يجب على السائق وضع أجهزة التحذير من الطوارئ (المثلثات العاكسة)؟","options":["خلال 5 دقائق","خلال 15 دقيقة","خلال 10 دقائق","خلال 30 دقيقة"],"explanation":"يجب على السائق الذي يضطر إلى التوقف على طريق أو كتف أن يضع أجهزة التحذير من الطوارئ خلال 10 دقائق. المصدر: دليل رخصة القيادة التجارية لولاية أركنساس، القسم 2.5 (التواصل)."},"66":{"q":"على طريق سريع باتجاه واحد أو مقسوم في أركنساس، أين يجب على مركبة تجارية متوقفة وضع مثلثاتها التحذيرية الثلاثة؟","options":["10 أقدام و100 قدم و100 قدم على كل جانب","25 قدمًا و100 قدم و300 قدم باتجاه حركة المرور القادمة","50 قدمًا و150 قدمًا و250 قدمًا باتجاه حركة المرور القادمة","10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة"],"explanation":"على طريق باتجاه واحد أو مقسوم، توضع المثلثات على بُعد 10 أقدام و100 قدم و200 قدم من المركبة باتجاه حركة المرور القادمة. المصدر: دليل رخصة القيادة التجارية لولاية أركنساس، القسم 2.5."},"67":{"q":"أي مجموعة من المركبات ليست من \"المركبات المرخصة\" المشمولة بقانون \"الابتعاد\" (Move Over) في أركنساس (Ark. Code 27-51-310)؟","options":["أي سيارة ركاب خاصة وأضواؤها الرباعية الوامضة مُشغّلة","شاحنات القطر العاملة في عملية قطر","مركبات إدارة النقل في ولاية أركنساس","مركبات شركات المرافق التي تعرض أضواءً وامضة"],"explanation":"يشمل قانون أركنساس للابتعاد (Move Over) مركبات الاستجابة للطوارئ وإنفاذ القانون وARDOT ومقاولي ARDOT والمرافق والقطر التي تعرض أضواءً وامضة/دوّارة؛ أما السيارة الخاصة العادية التي تستخدم أضواءها الوامضة (الخطر) فقط فليست \"مركبة مرخصة\". المصدر: Ark. Code Ann. 27-51-310."},"68":{"q":"على طريق سريع في أركنساس غير مقيد الوصول، بكم يزيد حد السرعة العام لسيارات الركاب عنه للشاحنات بسعة طن ونصف فأكثر؟","options":["أعلى بـ 5 mph (55 mph مقابل 50 mph)","أعلى بـ 15 mph (65 mph مقابل 50 mph)","أعلى بـ 10 mph (60 mph مقابل 50 mph)","لا فرق؛ كلاهما 55 mph"],"explanation":"تسمح أركنساس بسرعة 60 mph للمركبات الأخرى لكن 50 mph فقط للشاحنات الثقيلة على الطرق السريعة غير المقيدة الوصول، أي بفارق 10 mph. المصدر: Ark. Code Ann. 27-51-201."},"69":{"q":"بموجب قانون الحافلات المدرسية في أركنساس، على أي نوع من الطرق لا يُطلب من السائقين القادمين في الاتجاه المعاكس التوقف لحافلة مدرسية تُحمّل أو تُنزل الأطفال؟","options":["طريق بمسارين","طريق بمسارين مع مسار انعطاف وسطي","طريق بأربعة مسارات بدون جزيرة وسطية","طريق سريع مقسوم بأربعة مسارات أو أكثر مع فاصل بجزيرة وسطية"],"explanation":"تشترط أركنساس على جميع حركة المرور في كلا الاتجاهين التوقف باستثناء الطريق السريع المقسوم بأربعة مسارات أو أكثر مع فاصل بجزيرة وسطية، حيث يجب أن تتوقف فقط حركة المرور التي تتبع الحافلة. ومسار الانعطاف الوسطي ليس جزيرة وسطية. المصدر: Ark. Code Ann. 27-51-1004؛ الإرشادات الرسمية لقانون سلامة الحافلات المدرسية في أركنساس."},"70":{"q":"بمقدار كم يشترط قانون أركنساس أن تكون السرعة القصوى للشاحنات الثقيلة (1.5 طن فأكثر) محددة دون الحد الأقصى للسيارات على الطرق السريعة المقيدة الوصول؟","options":["أقل بـ 10 mph من الحد الأقصى للسيارات","أقل بـ 5 mph من الحد الأقصى للسيارات","أقل بـ 15 mph من الحد الأقصى للسيارات","نفس الحد الأقصى للسيارات"],"explanation":"يوجّه قانون أركنساس 27-51-201 بأن تُحدد السرعة القصوى المسموح بها للشاحنات بسعة طن ونصف فأكثر على الطرق السريعة المقيدة الوصول عند 10 mph دون الحد الأقصى للسيارات (مثلًا 70 mph للشاحنات حيث يجوز للسيارات السير بسرعة 75). المصدر: Ark. Code Ann. 27-51-201."},"71":{"q":"ما هو القيد المميز للمسار في أركنساس المعروض على بعض الطرق السريعة بين الولايات ذات الستة مسارات على أنه \"الشاحنات تستخدم المسارين الأيمنين\"؟","options":["يجب على جميع الشاحنات السير في المسار الأوسط فقط في كل الأوقات","لا يجوز للمركبات ذات أكثر من محورين استخدام المسار الأقصى إلى اليسار على الطرق السريعة بين الولايات ذات الستة مسارات المخصصة","تُمنع الشاحنات من الطرق السريعة بين الولايات تمامًا بين الساعة 7 صباحًا والساعة 9 صباحًا","يجب على الشاحنات استخدام المسار الأيسر لإبقاء المسارات اليمنى مفتوحة للاندماج"],"explanation":"عدّل القانون رقم 1054 لعام 2007 (Act 1054 of 2007) قانون أركنساس 27-65-107(a) لإبقاء المركبات ذات أكثر من محورين خارج المسار الأقصى إلى اليسار على الطرق السريعة بين الولايات ذات الستة مسارات المخصصة، المُشار إليها بعلامة \"الشاحنات تستخدم المسارين الأيمنين\". المصدر: Act 1054 of 2007؛ Ark. Code Ann. 27-65-107(a)."},"72":{"q":"إذا كان تغيير المسارات غير آمن أو مستحيلًا أثناء الاقتراب من مركبة مرخصة متوقفة في أركنساس، فماذا يشترط قانون \"الابتعاد\" (Move Over)؟","options":["التوقف توقفًا تامًا على الطريق حتى تغادر المركبة المرخصة","الاستمرار بالسرعة المحددة بما أن تغيير المسار غير ممكن","الانتقال إلى الكتف خلف المركبة المرخصة والانتظار","تخفيض السرعة والمتابعة بحذر والحفاظ على سرعة مخفضة خلال المنطقة"],"explanation":"عندما يتعذر تغيير المسار بأمان، يشترط قانون أركنساس 27-51-310 على السائق تخفيض السرعة والمتابعة بحذر والحفاظ على سرعة مخفضة مناسبة لظروف الطريق خلال المنطقة التي تتوقف فيها المركبة المرخصة. المصدر: Ark. Code Ann. 27-51-310."},"73":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة أو الحمولة في أركنساس قبل أن يُطلب تصريح حمولة كبيرة الحجم؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"الحد الأقصى القانوني للعرض في أركنساس على شبكة الطرق السريعة للولاية هو 8 أقدام و6 بوصات؛ وأي شيء أعرض يتطلب تصريح حمولة كبيرة الحجم. المصدر: قواعد تصاريح ARDOT لنقل المركبات كبيرة الحجم والزائدة الوزن."},"74":{"q":"على طريق في أركنساس بمسارين يحمل حركة المرور في الاتجاهين، أين يجب على مركبة تجارية متوقفة وضع مثلثاتها التحذيرية؟","options":["10 أقدام و100 قدم و200 قدم باتجاه الخلف فقط","ضمن 10 أقدام من المركبة و100 قدم خلفها و100 قدم أمامها","25 قدمًا خلف المركبة و25 قدمًا أمامها فقط","100 قدم خلفها فقط، دون وضع أي مثلث أمامها"],"explanation":"على طريق بمسارين ثنائي الاتجاه (غير مقسوم)، ضع مثلثًا واحدًا ضمن 10 أقدام من المركبة وواحدًا على بُعد 100 قدم خلفها وواحدًا على بُعد 100 قدم أمامها. المصدر: دليل رخصة القيادة التجارية لولاية أركنساس، القسم 2.5."},"75":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة على شبكة الطرق السريعة لولاية أركنساس قبل أن يُطلب تصريح؟","options":["13 قدمًا و0 بوصة","14 قدمًا و0 بوصة","13 قدمًا و6 بوصات","12 قدمًا و6 بوصات"],"explanation":"الحد الأقصى القانوني للارتفاع في أركنساس هو 13 قدمًا و6 بوصات؛ والحمولات التي تتجاوزه تتطلب تصريح حمولة كبيرة الحجم. المصدر: قواعد تصاريح ARDOT لنقل المركبات كبيرة الحجم والزائدة الوزن."},"76":{"q":"ما حجم الأعلام الحمراء التي تشترطها أركنساس على الزوايا الخلفية لحمولة مُرخّصة زائدة العرض أو زائدة الطول؟","options":["أعلام حمراء بحجم 12 بوصة","أعلام حمراء بحجم 24 بوصة","أعلام حمراء بحجم 6 بوصات","أعلام حمراء بحجم 18 بوصة"],"explanation":"تشترط أركنساس أعلامًا حمراء بحجم 18 بوصة على الزوايا الخلفية السفلية للحمولات زائدة العرض وزائدة الطول، إلى جانب لافتات OVERSIZE LOAD في المقدمة والمؤخرة. المصدر: قواعد تصاريح ARDOT لنقل المركبات كبيرة الحجم والزائدة الوزن."},"77":{"q":"في أركنساس، ما هي السرعة القصوى التي يمكن أن تُقاد بها مركبة تقطر منزلًا مُصنّعًا أو متنقلًا؟","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"تمنع قواعد تصاريح أركنساس قيادة مركبة تقطر منزلًا مُصنّعًا أو متنقلًا بسرعة أكبر من 55 mph. المصدر: Code of Arkansas Rules 111-109 / قواعد تصاريح ARDOT (نقل المركبات كبيرة الحجم/الزائدة الوزن)."},"78":{"q":"تشمل عقوبات أركنساس على التجاوز غير القانوني لحافلة مدرسية متوقفة أثناء تحميل أو إنزال الأطفال غرامة ضمن أي نطاق؟","options":["غرامة ثابتة قدرها $100 دون سجن","لا تقل عن $500 ولا تزيد عن $5,000","لا تقل عن $250 ولا تزيد عن $1,000","لا تقل عن $50 ولا تزيد عن $250"],"explanation":"يحدد قانون أركنساس 27-51-1001 الغرامة على تجاوز حافلة مدرسية متوقفة بما لا يقل عن $250 ولا يزيد عن $1,000، مع احتمال السجن وتعليق الرخصة والخدمة المجتمعية. المصدر: Ark. Code Ann. 27-51-1001."},"79":{"q":"عند التوقف عند ملتقى السكة الحديدية مع الطريق في أركنساس، ماذا ينبغي أن يفعل السائق التجاري أيضًا قبل العبور؟","options":["تشغيل الأضواء الرباعية الوامضة للطوارئ واستخدام مسار جانبي إن توفر","إطلاق البوق باستمرار حتى تعبر المركبة القضبان","التحويل إلى ترس أعلى لعبور القضبان بسرعة أكبر","التوقف مباشرةً على أقرب سكة لزيادة الرؤية للقضبان"],"explanation":"عندما يكون التوقف مطلوبًا عند ملتقى مستوٍ، يوجّه دليل أركنساس السائقين إلى مراقبة حركة المرور خلفهم أثناء التوقف تدريجيًا، واستخدام مسار جانبي إن توفر، وتشغيل الأضواء الرباعية الوامضة؛ ولا تُحوّل التروس أثناء العبور. المصدر: دليل رخصة القيادة التجارية لولاية أركنساس، القسم 2.15.4."},"80":{"q":"أي جهة حكومية في الولاية مسؤولة عن إصدار رخص القيادة التجارية (CDLs) في أركنساس؟","options":["قسم سلامة الطرق السريعة بشرطة ولاية أركنساس","إدارة النقل في ولاية أركنساس (ARDOT)","الإدارة الفيدرالية لسلامة ناقلي البضائع بالمركبات (FMCSA)","إدارة المالية والإدارة في أركنساس (DFA)، مكتب خدمات السائقين"],"explanation":"تُصدر رخص القيادة التجارية (CDLs) في أركنساس من قِبل إدارة المالية والإدارة (DFA)، مكتب خدمات السائقين، التي تتولى إدارة قانون ترخيص السائقين وإنفاذه. المصدر: صفحات مكتب خدمات السائقين / CDL التابعة لـ DFA في أركنساس (dfa.arkansas.gov)."},"81":{"q":"في أركنساس، من الذي يتولى عادةً إجراء اختبار المهارات (القيادة على الطريق) لرخصة القيادة التجارية (CDL)؟","options":["أي موظف في مكتب الإيرادات المحلي أثناء موعد التقديم","شرطة ولاية أركنساس في مواقع اختبار محددة، أو جهة اختبار خارجية معتمدة","موظفو محطات الوزن التابعون لإدارة النقل في أركنساس","مدارس CDL الخاصة فقط التي تُصدر الرخصة مباشرةً"],"explanation":"بينما تُصدر DFA الرخصة، تُجرى اختبارات المهارات لرخصة CDL في مواقع اختبار محددة تابعة لشرطة ولاية أركنساس أو من قِبل جهات اختبار خارجية معتمدة. المصدر: خدمات السائقين بـ DFA في أركنساس / معلومات اختبار CDL لشرطة ولاية أركنساس."},"82":{"q":"قبل أن يتمكن المتقدم من إجراء اختبار المهارات لرخصة CDL في أركنساس، يجب أولًا الحصول على أي وثيقة؟","options":["تظهير رخصة مشغّل من الفئة D","رقم صلاحية تشغيل فيدرالي بين الولايات","تصريح المتعلّم التجاري (CLP)","تصريح طريق تجاري مؤقت لمدة 30 يومًا"],"explanation":"يجب على المتقدم أولًا أن يحمل تصريح المتعلّم التجاري (CLP) قبل إجراء اختبار المهارات لرخصة CDL في أركنساس. المصدر: صفحة CLP التابعة لـ DFA في أركنساس (dfa.arkansas.gov)."},"83":{"q":"بموجب قواعد أركنساس، كم يجب أن يحمل المتقدم تصريح المتعلّم التجاري (CLP) قبل أن يُسمح له بإجراء اختبار المهارات لرخصة CDL؟","options":["ما لا يقل عن 14 يومًا بعد الإصدار الأولي للـ CLP","ما لا يقل عن 30 يومًا بعد الإصدار الأولي للـ CLP","ما لا يقل عن 7 أيام بعد الإصدار الأولي للـ CLP","ما لا يقل عن 60 يومًا بعد الإصدار الأولي للـ CLP"],"explanation":"تمنع أركنساس، اتباعًا للمعيار الفيدرالي لرخصة CDL، إجراء اختبار المهارات في أول 14 يومًا بعد الإصدار الأولي للـ CLP. المصدر: صفحة CLP التابعة لـ DFA في أركنساس (معيار 49 CFR 383.25 المُعتمد من أركنساس)."},"84":{"q":"ما هي المدة القصوى التي يظل خلالها تصريح المتعلّم التجاري (CLP) ساريًا في أركنساس قبل وجوب إعادة اختبارات المعرفة؟","options":["حتى سنتين من الإصدار","حتى سنة واحدة من الإصدار","حتى 90 يومًا من الإصدار","حتى أربع سنوات من الإصدار"],"explanation":"يكون تصريح CLP ساريًا لمدة تصل إلى سنة واحدة؛ وإذا انتهت صلاحيته، يجب على حامله إعادة اختبار المعرفة العام وأي اختبار معرفة للتظهير قبل إصدار تصريح جديد. المصدر: صفحة CLP التابعة لـ DFA في أركنساس (بما يتوافق مع 49 CFR 383.25)."},"85":{"q":"يجب على المتقدم الجديد الذي يسعى للحصول على رخصة CDL من الفئة A للمرة الأولى في أركنساس إكمال أي تدريب مطلوب فيدراليًا قبل إجراء اختبار المعرفة لعملية التحول من CLP إلى CDL؟","options":["دورة شهادة قيادة دفاعية تديرها الولاية","تدريب السائقين المبتدئين (ELDT) من مزوّد مسجّل لدى FMCSA","شهادة إسعافات أولية من مجلس السلامة الوطني","تدريب مهني برعاية صاحب العمل يستمر 12 شهرًا"],"explanation":"منذ 7 فبراير 2022، يجب على المتقدمين لأول مرة للحصول على رخصة CDL إكمال تدريب السائقين المبتدئين (ELDT) عبر مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل الاختبار. وتتحقق أركنساس من الإكمال عبر السجل. المصدر: قاعدة ELDT الخاصة بـ FMCSA / معلومات CDL التابعة لـ DFA في أركنساس."},"86":{"q":"يُبلَّغ عن إكمال التدريب النظري لـ ELDT إلى أي نظام تتحقق منه DFA في أركنساس قبل إصدار رخصة CDL؟","options":["بوابة MyDMV التابعة لـ DFA في أركنساس فقط","السجل الوطني للسائقين (NDR)","نظام معلومات رخصة القيادة التجارية (CDLIS) فقط","سجل مزوّدي التدريب التابع لـ FMCSA (TPR)"],"explanation":"يقدّم مزوّدو التدريب إكمال ELDT إلى سجل مزوّدي التدريب التابع لـ FMCSA (TPR)؛ وتتحقق جهة ترخيص السائقين في الولاية، بما في ذلك DFA في أركنساس، من TPR قبل السماح باختبار المهارات أو إصدار رخصة CDL. المصدر: سجل مزوّدي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov)."},"87":{"q":"يُشترط تدريب ELDT في أركنساس لمتقدم لأول مرة في جميع الحالات التالية باستثناء:","options":["الحصول على رخصة CDL من الفئة A أو الفئة B للمرة الأولى","ترقية رخصة CDL قائمة من الفئة B إلى الفئة A","تجديد رخصة CDL قائمة من الفئة A دون تظهيرات جديدة","الحصول على تظهير المواد الخطرة (H) للمرة الأولى"],"explanation":"ينطبق ELDT على رخص CDL من الفئة A/B لأول مرة، والترقيات من B إلى A، وتظهيرات S أو P أو H لأول مرة. أما التجديد البسيط لرخصة CDL قائمة دون تظهير جديد فلا يستدعي ELDT. المصدر: قاعدة ELDT الخاصة بـ FMCSA (49 CFR Part 380) كما تُطبَّق في أركنساس."},"88":{"q":"يتكوّن اختبار المهارات لرخصة CDL في أركنساس من أي ثلاثة أجزاء، بالترتيب الذي تُؤدى به عمومًا؟","options":["اختبار المعرفة الكتابي، وفحص النظر، والقيادة على الطريق","فحص الفرامل الهوائية، ومناولة المواد الخطرة، والقيادة على الطريق","الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","التحكم الأساسي بالمركبة، واختبار المعرفة، والفحص قبل الرحلة"],"explanation":"يتكوّن اختبار المهارات لرخصة CDL في أركنساس من ثلاثة أجزاء: الفحص قبل الرحلة للمركبة، ومهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: معلومات اختبار مهارات CDL التابعة لـ DFA في أركنساس / شرطة ولاية أركنساس (49 CFR 383.113)."},"89":{"q":"خلال جزء التحكم الأساسي بالمركبة من اختبار مهارات CDL في أركنساس، يقيّم الفاحص بشكل أساسي قدرة المتقدم على:","options":["المناورة والرجوع بالمركبة بدقة في مساحة محدودة","تلاوة حدود ساعات الخدمة الفيدرالية من الذاكرة","حساب التصنيف الإجمالي للوزن المركّب للمركبة","إظهار وضع شعلات الطوارئ على جانب الطريق"],"explanation":"يختبر التحكم الأساسي بالمركبة قدرة السائق على التحكم بالمركبة وتمويضعها عبر مناورات مثل الرجوع في خط مستقيم، والرجوع المُزاح، والركن في مساحة محدودة. المصدر: معايير اختبار المهارات التابعة لـ DFA في أركنساس / FMCSA (49 CFR 383.113)."},"90":{"q":"تشترط قواعد الشهادة الطبية الفيدرالية التي اعتمدتها أركنساس على كل حامل لتصريح CLP ورخصة CDL أن يقرّ ذاتيًا بانتمائه إلى كم فئة تشغيل ممكنة؟","options":["فئتان","أربع فئات","ثلاث فئات","ست فئات"],"explanation":"يجب على كل حامل لتصريح CLP / رخصة CDL أن يقرّ ذاتيًا بانتمائه إلى إحدى أربع فئات بناءً على التشغيل بين الولايات مقابل التشغيل داخل الولاية والحالة المستثناة مقابل غير المستثناة. المصدر: صفحة الشهادة الطبية التابعة لـ DFA في أركنساس (49 CFR 383.71)."},"91":{"q":"أي فئة من فئات الإقرار الذاتي تتطلب أن يستوفي السائق معايير التأهيل البدني الفيدرالية لـ DOT وأن يحمل شهادة فاحص طبي؟","options":["مستثنى بين الولايات","مستثنى داخل الولاية","غير مستثنى بين الولايات","هواية / استخدام شخصي فقط"],"explanation":"يجب على السائق الذي يقرّ ذاتيًا بأنه غير مستثنى بين الولايات أن يستوفي معايير التأهيل البدني الفيدرالية لـ DOT (49 CFR 391) وأن يحتفظ بشهادة فاحص طبي سارية. المصدر: صفحة الشهادة الطبية التابعة لـ DFA في أركنساس (49 CFR 383.71)."},"92":{"q":"السائق الذي يعمل فقط داخل أركنساس وليس خاضعًا لمتطلبات التأهيل البدني الفيدرالية سيقرّ ذاتيًا على الأرجح وبأكثر دقة بأنه:","options":["غير مستثنى بين الولايات","مستثنى داخل الولاية","مستثنى بين الولايات","غير مستثنى فيدراليًا"],"explanation":"السائق الذي يعمل فقط داخل الولاية وليس مُطالبًا باستيفاء معايير التأهيل البدني الفيدرالية يقرّ ذاتيًا بأنه مستثنى داخل الولاية. المصدر: صفحة الشهادة الطبية التابعة لـ DFA في أركنساس (49 CFR 383.71)."},"93":{"q":"عندما يقرّ متقدم لرخصة CDL في أركنساس ذاتيًا بأنه غير مستثنى بين الولايات، يجب أن يكون الفاحص الطبي لـ DOT الذي يجري الفحص البدني:","options":["موظفًا لدى الوحدة الطبية لشرطة ولاية أركنساس","أي صيدلي مرخّص في مقاطعة المتقدم","معتمدًا بشكل فردي من قِبل مدير مكتب الإيرادات المحلي","مدرجًا في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA"],"explanation":"يجب على السائقين غير المستثنين الحصول على فحصهم البدني من فاحص طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA، وتُقدَّم تلك الشهادة إلى مكتب خدمات السائقين. المصدر: صفحة الشهادة الطبية التابعة لـ DFA في أركنساس (49 CFR 391.41 / السجل الوطني)."},"94":{"q":"أي مما يلي يُعد طريقة مقبولة لتقديم شهادة الفاحص الطبي لـ DOT وإفادة الإقرار الذاتي إلى مكتب خدمات السائقين في أركنساس؟","options":["نشرها مباشرةً على موقع السجل الوطني التابع لـ FMCSA","تسليمها لشرطي من شرطة ولاية أركنساس على جانب الطريق عند أي توقف مروري","إحضارها شخصيًا إلى أي مكتب إيرادات في أركنساس، أو إرسالها بالبريد الإلكتروني/الفاكس إلى مكتب خدمات السائقين","رفعها فقط إلى بوابة صاحب العمل الخاص بشركة النقل التابع لها المتقدم"],"explanation":"تقبل أركنساس الشهادة الطبية والإقرار الذاتي شخصيًا في أي مكتب إيرادات بالولاية، أو بالبريد إلى مكتب خدمات السائقين، أو عبر قنوات البريد الإلكتروني/الفاكس التي تنشرها DFA. المصدر: صفحات الشهادة الطبية / تسجيل الشهادة الطبية التابعة لـ DFA في أركنساس."},"95":{"q":"ماذا يحدث لامتيازات القيادة التجارية لحامل رخصة CDL غير مستثنى في أركنساس إذا انتهت صلاحية شهادة الفاحص الطبي لـ DOT ولم تُقدَّم شهادة جديدة؟","options":["تُغيَّر حالة رخصة CDL إلى \"غير معتمد\" وتُفقد امتيازات القيادة التجارية","لا يتغير شيء حتى تنتهي صلاحية مدة رخصة CDL الكاملة بعد سنوات","تُخفَّض رخصة CDL تلقائيًا إلى تصريح CLP لمدة سنة واحدة","تُفرض غرامة على السائق لكنه يحتفظ بكامل امتيازات القيادة التجارية"],"explanation":"يؤدي عدم تقديم بطاقة طبية سارية بحلول تاريخ انتهائها إلى وضع رخصة CDL في حالة طبية \"غير معتمد\"، مما يزيل امتيازات القيادة التجارية حتى تُقدَّم شهادة سارية. المصدر: صفحة الشهادة الطبية التابعة لـ DFA في أركنساس."},"96":{"q":"عند تجديد رخصة CDL في أركنساس، يجب على السائق غير المستثنى عادةً تقديم جميع ما يلي باستثناء:","options":["شهادة تدريب سائقين مبتدئين (ELDT) جديدة للفئة القائمة","رخصة قيادته الحالية","إفادة إقرار ذاتي مكتملة","شهادة فاحص طبي سارية"],"explanation":"تجديد رخصة CDL قائمة من الفئة نفسها دون تظهير جديد لا يتطلب ELDT؛ لكن السائق يحتاج إلى رخصته الحالية، وإفادة إقرار ذاتي، و(إن كان غير مستثنى) شهادة طبية سارية. المصدر: متطلبات التجديد بخدمات السائقين بـ DFA في أركنساس / قاعدة ELDT الخاصة بـ FMCSA."},"97":{"q":"ما هو الحد الأدنى لسن الحصول على رخصة CDL في أركنساس مقصورة على القيادة التجارية داخل الولاية؟","options":["18 عامًا","21 عامًا","19 عامًا","16 عامًا"],"explanation":"تسمح أركنساس برخصة CDL للتشغيل داخل الولاية في سن 18؛ أما التشغيل بين الولايات فيتطلب أن يكون عمر السائق 21. المصدر: متطلبات CDL التابعة لـ DFA في أركنساس (معايير العمر 49 CFR 383 / 391)."},"98":{"q":"فيما يتعلق برسوم التقديم لرخصة CDL في أركنساس، أي عبارة تعكس التوقّع الصحيح من منظور العملية؟","options":["التقديم والاختبار لرخصة CDL مجانيان دائمًا في أركنساس","الرسم محدد بشكل دائم بموجب القانون الفيدرالي ولا يتغير أبدًا","تظهير المواد الخطرة وحده يحمل رسمًا؛ وجميع خدمات CDL الأخرى مجانية","تحدد الولاية الرسوم ويمكن أن تتغير، لذا ينبغي على المتقدمين تأكيد المبلغ الحالي مع DFA قبل التقديم"],"explanation":"تحدد الولاية رسوم CDL في أركنساس (الرخصة والتظهير والاختبار) وهي عرضة للتغيير، لذا ينبغي على المتقدمين التحقق من المبالغ الحالية مع DFA بدلًا من الاعتماد على رقم ثابت. المصدر: جدول رسوم خدمات السائقين بـ DFA في أركنساس (عرضة للتغيير)."}}};
